INSERT INTO `blogs` (`id`, `user_id`, `name`, `image_path`, `short_description`, `description`, `keyword`, `pageview`, `slug`, `created_at`, `updated_at`) VALUES
(3, 1, 'স্বনামধন্য বিশ্ববিদ্যালয়ের Home Tutor  যেখানে খুঁজে পাবেন', '1717187335-KNO3zY4awTPE8MTMTcdrOFmJKgRIWFrt.jpg', 'স্বনামধন্য বিশ্ববিদ্যালয়ের Home Tutor যেখানে খুঁজে পাবেন short details', '<p style=\"text-align:justify\"><span style=\"font-size:14px\">শিক্ষা যে কোনো জাতির জন্য অগ্রগতি ও উন্নয়নের ভিত্তি, এবং সমৃদ্ধ সাংস্কৃতিক ঐতিহ্যের দেশ বাংলাদেশও এর ব্যতিক্রম নয়। বছরের পর বছর ধরে, দেশে&nbsp;শিক্ষার মান&nbsp; উন্নত করার জন্য পদক্ষেপ নেওয়া হয়েছে, কিন্তু চ্যালেঞ্জগুলি এখনও রয়ে গেছে, বিশেষ করে মানসম্পন্ন টিউটরিং (home tutor bd)&nbsp;এবং শিক্ষাগত সহায়তার ক্ষেত্রে। এই চ্যালেঞ্জগুলির মধ্যেও টিউটর সেবা tutor sheba&nbsp;,<a href=\"https://www.redrosebd.com/Tutor\">Redrose academy,</a> সহ বেশ কিছু টিউশন মিডিয়া অনলাইন ওয়েব পেজ&nbsp;আশার আলোর মতো আবির্ভূত হয়েছে, এবং বিপ্লব ঘটিয়ে সারা বাংলাদেশে অগণিত শিক্ষার্থীদের জন্য শিক্ষার&nbsp;&nbsp;মান বৃদ্ধি &nbsp;করেছে। </span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:14px\">শিক্ষক ও শিক্ষার্থীদের ক্ষমতায়ন 2015 সালে প্রতিষ্ঠিত টিউটর সেবা হল একটি বাংলাদেশী অনলাইন টিউটরিং প্ল্যাটফর্ম যার লক্ষ্য হল বিভিন্ন শিক্ষাগত ব্যাকগ্রাউন্ড থেকে ছাত্র এবং টিউটরদের সংযুক্ত করা। প্ল্যাটফর্মটি একটি ব্যবহার-বান্ধব ওয়েবসাইট এবং মোবাইল অ্যাপ্লিকেশনের মাধ্যমে কাজ করে, এটিকে প্রথাগত শিক্ষার ক্ষেত্রগুলোতে সীমিত প্রবেশসহ গ্রামীণ অঞ্চলের ব্যবহারকারীদের কাছে প্রবেশযোগ্য করে তোলে। প্রযুক্তির ব্যবহার দ্বারা টিউটর সেবা একটি দক্ষ ইকোসিস্টেম তৈরি করেছে যা টিউটর এবং শিক্ষার্থীদের একইভাবে ক্ষমতায়ন করে। অনলাইন টিউটরিং এর সুবিধা, টিউটর সেবার একটি উল্লেখযোগ্য সুবিধা হল ভৌগলিক বাধা অতিক্রম করার ক্ষমতা। টিউটর সেবার অনলাইন প্ল্যাটফর্মের মাধ্যমে বাংলাদেশের যেকোন প্রান্তের প্রতিভাবান টিউটররা সারা দেশে শিক্ষার্থীদের পড়াতে পারে এবং সবার জন্য শিক্ষার সুযোগ প্রসারিত করে। অধিকন্তু, প্ল্যাটফর্মটি শিক্ষার্থীদেরকে তাদের সুবিধামত টিউটরিং গ্রহণ করতে দেয়। এটি পাঠ্যক্রম বহির্ভূত অন্যান্য কর্মকাণ্ডে নিয়োজিত শিক্ষার্থীদের জন্য উপকারী এবং এটি পেশাজীবী শিক্ষার্থীদেরকে তাদের পেশাগত দায়িত্ব বজায় রেখে নতুন জ্ঞান অর্জন করতে বা অন্বেষণ করতে সক্ষম করে। গুণমানের নিশ্চয়তা এবং বিভিন্ন বিষয়ের কভারেজ টিউটর সেবার গৃহশিক্ষক নির্বাচনের জন্য কঠোর মানদণ্ড রয়েছে যা শুধুমাত্র যোগ্য ও যাদের শিক্ষাদানের প্রতি অনুরাগ রয়েছে তাদেরকেই নির্বাচন করে।এর জন্য,টিউটরদেরকে একটি সূক্ষ্ম নির্বাচন প্রক্রিয়ার মধ্য দিয়ে যেতে হয়, যার মধ্যে তাদের বিষয়ের দক্ষতা, শিক্ষাদানের পদ্ধতি এবং যোগাযোগ দক্ষতার মূল্যায়ন অন্তর্ভুক্ত থাকে এবং এই প্রক্রিয়া নিশ্চিত করে যে শিক্ষার্থীরা মানসম্পন্ন নির্দেশনা এবং ব্যক্তিকেন্দ্রিক মনোযোগ পাবে। তদুপরি, টিউটর সেবা প্রাথমিক, মাধ্যমিক এবং উচ্চ মাধ্যমিক শিক্ষার পাশাপাশি বিভিন্ন বিশ্ববিদ্যালয় শাখার এবং একাডেমিক স্তরের বিভিন্ন বিষয় আচ্ছাদন করে।যার ফলে, শিক্ষার্থীদের কাছে চ্যালেঞ্জিং মনে হয় এমন বিষয়গুলিতে নির্দেশনা পেতে সক্ষম করার পাশাপাশি একটি সুষ্ঠু শিক্ষার অভিজ্ঞতা তৈরি করে। আর্থ-সামাজিক উন্নয়নে সহায়তা করা টিউটর সেবার প্রভাব শিক্ষাদানের বাইরেও প্রসারিত। এটি বাংলাদেশের আর্থ-সামাজিক উন্নয়নে সহায়ক ভূমিকা পালন করে। যেমন,দক্ষ ব্যক্তিদের তাদের জ্ঞান ভাগ করে নেওয়ার এবং জীবিকা অর্জনের জন্য একটি প্ল্যাটফর্ম প্রদান করে এবং টিউটর শেবা বেকারত্বের হার কমাতে এবং আর্থিক স্বাধীনতা বৃদ্ধিতে অবদান রাখে।</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:14px\">উক্ত প্লাটফর্মগুলো&nbsp;নারী শিক্ষকদের সক্রিয়ভাবে অংশগ্রহণের জন্য উৎসাহিত করার মাধ্যমে লিঙ্গ সমতা বৃদ্ধিতে সহায়তা করে। যেহেতু অনেক মহিলা শিক্ষার্থী মহিলা টিউটরদের সাথে পড়াশোনা করতে বেশি স্বাচ্ছন্দ্য বোধ করে, তাই&nbsp; tutor sheba এবং red rose academy মহিলা টিউটররা মেয়েদের এবং মহিলাদের আত্মবিশ্বাসের সাথে শিক্ষা গ্রহণের জন্য গুরুত্বপূর্ণ ভূমিকা পালন করে।&nbsp;</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:14px\">এটি মোকাবেলা করার জন্য,&nbsp; কমিউনিটি লার্নিং সেন্টার স্থাপনের জন্য স্থানীয় সংস্থাগুলির সাথে অংশীদারিত্ব করেছে, প্রত্যন্ত অঞ্চলের শিক্ষার্থীদের অনলাইন টিউটরিং এবং শিক্ষাগত ক্ষেত্রগুলোতে প্রবেশ প্রদান করে। উপসংহার গৃহশিক্ষক সেবা বাংলাদেশের শিক্ষাক্ষেত্রে আশার আলো হিসেবে আবির্ভূত হয়েছে। প্রযুক্তির ব্যবহার এবং দক্ষ শিক্ষকদের ক্ষমতায়নের মাধ্যমে,&nbsp;প্লাটফর্মগুলো সফলভাবে সারা দেশে মানসম্পন্ন শিক্ষার প্রবেশাধিকারকে&nbsp;নিশ্চিত করার চেষ্টা করে যাচ্ছে । শিক্ষাগত ব্যবধান কমানো এবং আর্থ-সামাজিক উন্নয়নে সহায়তা করার অঙ্গীকারের মাধ্যমে টিউটর সেবা বাংলাদেশের মানুষের উন্নতি, জীবন <strong>পরিবর্তন ও একটি উজ্জ্বল ভবিষ্যত নিশ্চিতের লক্ষ্যে কাজ করে চলেছে।</strong></span></p>', 'স্বনামধন্য বিশ্ববিদ্যালয়ের Home Tutor যেখানে খুঁজে পাবেন keyword', 0, 'slug-3-wmeryjhszs-1-2omsksmoxo-3-gpmyg14vht-1-ZGstddmEkQ', '2023-07-22 17:57:44', '2024-06-01 06:28:55'),
(4, 1, 'ফাজিল (অনার্স) ভর্তি ২০২৪ - বিজ্ঞপ্তি প্রকাশিত।', '1717187352-Ah2DK3qBJdMUYVESeWeCAytFcn8hzCmr.png', NULL, '<p style=\"text-align:center\"><strong><span style=\"font-size:16px\">☆ ইসলামি আরবি বিশ্ববিদ্যালয় রেজিস্ট্রারের কার্যালয়</span></strong></p>\r\n\r\n<p style=\"text-align:center\"><strong><span style=\"font-size:16px\">ফাজিল (অনার্স) ভর্তি ২০২৪&nbsp;</span></strong></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">বাড়ি নং-১২৪/২২ ব্লক-এ, সড়ক নং-০৩, ওয়েস্ট ধানমন্ডি, বছিলা, মোহাম্মদপুর, ঢাকা-১২৩১</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">তারিখ : ২ মাঘ ১৪৩০০লাব্ল ১৬ জানুয়ারি</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">স্বারক নং- ইআবি/একা-৪১/ফা,ভর্তি/২০১৮/০০০৪৯৪</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২০২৩-২০২৪ শিক্ষাবর্ষে ফাজিল স্নাতক (পাস) ১ম বর্ষে ভর্তি বিজ্ঞপ্তি</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ইসলামি আরবি বিশ্ববিদ্যালয়ের অধীনে পরিচালিত ফাজিল স্নাতক (পাস) শ্রেণিতে পাঠদানকারী মাদরাসাসমূহে ২০২৩-২০২৪ শিক্ষাবর্ষে আগ্রহী প্রার্থীরা ফাজিল স্নাতক (পাস) ১ম বর্ষে ১৭.০১.২০২৪ খ্রি. তারিখ হতে ১৮.০৩.২০২৪ খ্রি. তারিখ পর্যন্ত এবং বিলম্ব ফি&#39; সহ ১৯.০৩.২০২৪ খ্রি. তারিখ হতে ২১.০৪.২০২৪ খ্রি. তারিখ পর্যন্ত সংশ্লিষ্ট মাদরাসাসমূহে ভর্তি হতে পারবে। ভর্তির কার্যক্রম সমাপ্তির সাথে সাথে পাঠদান শুরু হবে।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">১। ভর্তি ও রেজিস্ট্রেশন ফি&#39; সহ অন্যান্য ফি&#39; জমাদানের নিয়মাবলী:</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">(ক) বিলম্ব ফি&#39; ছাড়া ভর্তিকৃত ছাত্র-ছাত্রীদের আদায়কৃত ফি&#39; ১৯.০৩.২০২৪ তারিখ থেকে ২৪.০৩.২০২৪ তারিখের মধ্যে Payslip ডাউনলোড পূর্বক অগ্রনী ব্যাংকের যে কোন শাখায় জমা প্রদান করতে হবে।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">(খ) বিলম্ব ফি&#39; সহ ভর্তিকৃত ছাত্র-ছাত্রীদের আদায়কৃত ফি&#39; ২২.৪.২০২৪ খ্রি. তারিখ থেকে ২৩.০৪.২০২৪ খ্রি.তারিখের মধ্যে Payslip ডাউনলোড পূর্বক অগ্রনী ব্যাংকের যে কোন শাখায় জমা প্রদান করতে হবে।&nbsp;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২। ভর্তি কার্যক্রম সুষ্ঠুভাবে সম্পন্নের নিমিত্তে প্রতিটি মাদরাসায় নিম্নরূপ একটি করে কমিটি গঠন করা হলো:</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">১ অধ্যক্ষ</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">আহবায়ক</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২ একজন শিক্ষক প্রতিনিধি</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">সদস্য</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">(গভর্নিং বডি/এডহক কমিটির সদস্য, তবে সরকারি মাদরাসার ক্ষেত্রে সংশ্লিষ্ট মাদরাসার অধ্যক্ষ কর্তৃক মনোনীত একজন শিক্ষক)</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৩ ফাজিল পর্যায়ের একজন শিক্ষক (প্রভাষক/সহকারী অধ্যাপক) অধ্যক্ষ কর্তৃক মনোনীত</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">সদস্য</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৩। ফাজিল (স্নাতক) পাস শ্রেণীতে ভর্তির যোগ্যতাঃ</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২০২২/২০২৩ সনে আলিম/সমমান পরীক্ষায় উত্তীর্ণ ছাত্র-ছাত্রীগণ ফাজিল স্নাতক (পাস) ১ম বর্ষে ভর্তির যোগ্য বলে বিবেচিত হবেন (২০২২ সালে উত্তীর্ণ ছাত্র/ছাত্রীদের শিক্ষাবিরতি ফি&#39; দিতে হবে)। প্রাথমিক পাঠদানের অনুমতিবিহীন / অনুমতির মেয়াদ উত্তীর্ণ অথবা অধিভূক্তি বাতিলকৃত মাদরাসাসমূহে ছাত্র-ছাত্রী ভর্তি করা যাবে না।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৪ । শিক্ষার্থীদের অনলাইন রেজিস্ট্রেশন এবং মাদরাসাসমূহের eSIF তালিকা প্রেরণের সময়সূচীঃ</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২০২৩-২০২৪ ইং শিক্ষাবর্ষে ফাজিল স্নাতক (পাস) শ্রেণীতে ১ম বর্ষে ভর্তিকৃত ছাত্র-ছাত্রীদের অনলাইন রেজিস্ট্রেশন ২২.০৪.২০২৪ খ্রি. থেকে ২১.০৫.২০২৪ খ্রি. তারিখের মধ্যে সম্পন্ন করে ২২.০৫.২০২৪ খ্রি. থেকে<br />\r\n২৯.০৫.২০২৪ খ্রি. তারিখের মধ্যে Final submit দিতে হবে (অনলাইন রেজিস্ট্রেশন চলাকালীন সময় Final submit অপশন দেয়া থাকবে না)। অনলাইন রেজিস্ট্রেশন সম্পন্ন করে পরবর্তী ৭ (সাত) দিনের মধ্যে সংশ্লিষ্ট মাদরাসার অধ্যক্ষ/অধ্যক্ষ কর্তৃক মনোনীত প্রতিনিধিকে অফিস অনলাইন Payslip এর মূল কপি ও ২ কপি esif লিস্টসহ আনুষাঙ্গিক কাগজপত্র সরাসরি/ডাকযোগে/কুরিয়ার সার্ভিসের মাধ্যমে বিশ্ববিদ্যালয়ের বছিলাস্থ অস্থায়ী কার্যালয়ের একাডেমিক শাখায়</span></p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৫। বিশ্ববিদ্যালয়ের ওয়েবসাইট হতে ডাউনলোড করে নির্ধারিত আবেদন ফরম পূরণপূর্বক ছাত্র-ছাত্রী ভর্তি করতে হবে। ছাত্র-ছাত্রী অথবা অভিভাবকের সম্মতি ব্যতীত কোন ছাত্র-ছাত্রী ভর্তি করা যাবে না। ভর্তি ফরমে প্রত্যেক ছাত্র-ছাত্রীর নিকট থেকে এ মর্মে একটি অঙ্গীকারনামা দিতে হবে যে, &quot;আমি ভালভাবে বুঝে শুনেই এ মাদরাসায় ভর্তি হতে ইচ্ছুক। ভর্তি হওয়ার পর কোন অবস্থাতেই এ মাদরাসা পরিবর্তন করে অন্য কোন মাদরাসায় ভর্তির জন্য আবেদন করবো না।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৬। ফাজিল স্নাতক (পাস) শ্রেণির রেজিস্ট্রেশন ফি&#39; সহ অন্যান্য ফি&#39; এর হার:</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">বিলম্ব ফি ছাড়া রেজিঃ ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">রোভার স্কাউটস ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">আবেদন ফরম</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ক্রীড়া ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ভর্তি ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">শিক্ষা বিরতি ফি</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">শ্রেণী</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">বি.এন.সি.সি. ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ফি&#39; ৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">১৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২৫/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ফাজিল স্নাতক (পাস)</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">বিলম্ব ফি&#39; সহ</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">শিক্ষা বিরতি</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">রোভার স্কাউটস ফি&#39; বি.এন.সি.সি. ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ভর্তি ফি&#39; রেজিঃ ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ক্রীড়া ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">শ্রেণী</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">আবেদন ফরম</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ফি ১৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ফি</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">২৫/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">800/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৩৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ফাজিল স্নাতক</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">৫০/-</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ভর্তি ফি&#39;, বিলম্ব ভর্তি ফি&#39;, ক্রীড়া ফি&#39; ও শিক্ষা বিরতি ফি&#39; বাবদ আদায়কৃত অর্থের ৫০% অর্থসহ অন্যান্য ফি&#39;</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">(ক) বিলম্ব ফি&#39; ও শিক্ষা বিরতি ফি&#39; ছাড়া প্রতি ছাত্র/ছাত্রী ৪৭৫/- টাকা, (খ) বিলম্ব ফি&#39; ছাড়া ও শিক্ষা বিরতি ফি&#39; সহ প্রতি ছাত্র/ছাত্রী ৫৫০/- টাকা,</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">(গ) বিলম্ব ফি&#39; সহ ও শিক্ষা বিরতি ফি&#39; ছাড়া প্রতি ছাত্র/ছাত্রী ৬৫০/- টাকা, (ঘ) বিলম্ব ফি&#39; ও শিক্ষা বিরতি ফি&#39; সহ প্রতি ছাত্র/ছাত্রী ৭২৫/- হারে নিম্নলিখিত নিয়মাবলী অনুসরণ করে &quot;অগ্রণী</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">ব্যাংক লিঃ&quot; এর যে কোন শাখায় জমা দেয়া যাবে। Payslip রশিদের অপর পৃষ্ঠায় মাদরাসা অধ্যক্ষের সীল ও</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">স্বাক্ষরসহ রশিদটি eSIF তালিকা এর সাথে সংযুক্ত করতে হবে।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">( ঙ) ফি-জমা দেয়ার নিয়মাবলীঃ</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">প্রথম ধাপ j<a href=\"https://iau.edu.bd/\">au.edu.bd</a>/Payment তে প্রবেশ করুন।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">দ্বিতীয় ধাপ। EIN ও Password দিয়ে Login করুন।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">তৃতীয় ধাপ। Admission &amp; Registration Fee তে ক্লিক করে প্রয়োজনীয় তথ্য পূরণপূর্বক Save এ ক্লিক করুন।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">-- Payslip Download করে ব্যাংকে টাকা জমা দিন।</span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:14px\">চতুর্থ ধাপ (Payslip Download করতে কোন সমস্যা হলে জনাব মোঃ রুমি কিসলু, সেকশন অফিসার (০১৭১৮-৯৫৫৫৯৬ এই নম্বরে যোগাযোগ করুন)।</span></p>', NULL, 39, 'slug-4-x1yxccjeoq-1-hPQPOFyF5Q', '2024-02-14 10:48:56', '2024-06-01 06:29:12'),
(7, 1, 'সম্পূর্ণ ফ্রিতে পিএইচডি করুন সিঙ্গাপুরে, সাথে থাকছে মাসে  ২ লাখ টাকা উপবৃত্তি', '1717187430-0xAN4XItrn7idCWTeQaUYFiZcX5P55mC.jpg', NULL, '<p>উচ্চশিক্ষায় আন্তর্জাতিক শিক্ষার্থীদের বিনামূল্যে পিএইচডি প্রোগ্রামে অধ্যায়নের সুযোগ দিচ্ছে বিশ্বের অন্যতম উন্নত একটি দেশ সিঙ্গাপুর। &rdquo;সিঙ্গাপুর ইন্টারন্যাশনাল গ্র্যাজুয়েট অ্যাওয়ার্ড (সিঙ্গা) &rdquo;আওতায় নির্বাচিত শিক্ষার্থীদের সিঙ্গাপুরের সরকার এই স্কলারশিপ প্রদান করবে। বাংলাদেশসহ অন্য যে কোনো দেশের শিক্ষার্থীরা জানুয়ারী ২০২৫ ইনটেকের জন্য আবেদন করতে পারবেন। আবেদনের শেষ সময় আগামী ১ জুন ২০২৪।</p>\r\n\r\n<p>সিঙ্গা অ্যাওয়ার্ডের আওতায় আছে এজেন্সি ফর সায়েন্স, টেকনোলজি অ্যান্ড রিসার্চ (এস্টার), নানয়াং টেকনোলজিক্যাল ইউনিভার্সিটি (এনটিইউ), ন্যাশনাল ইউনিভার্সিটি অব সিঙ্গাপুর (এনএসইউ) এবং সিঙ্গাপুর ইউনিভার্সিটি অব টেকনোলজি অ্যান্ড ডিজাইন। এসব বিশ্ববিদ্যালয়ে বিজ্ঞান ও প্রকৌশল বিষয় নিয়ে পিএইচডি করতে পারবেন শিক্ষার্থীরা। পিএইচডি কোর্সের মেয়াদ সর্বোচ্চ চার বছর।</p>\r\n\r\n<p><strong>সুযোগ-সুবিধাসমূহঃ</strong><br />\r\n* শিক্ষার্থীদের সম্পূর্ণ টিউশন ফি মওকুফ করা হবে।<br />\r\n* প্রতিমাসে শিক্ষার্থীদের প্রায় ২,৭০০ সিঙ্গাপুর ডলার (বাংলাদেশী টাকায় প্রায় ২ লাখ ২০ হাজার টাকা) উপবৃত্তি প্রদান করবে। &nbsp;<br />\r\n* আবাসন ভাতা হিসেবে এককালীন &nbsp;১,০০০ সিঙ্গাপুর ডলার (বাংলাদেশী টাকায় প্রায় ৮১ হাজার টাকা) প্রদান করবে।&nbsp;<br />\r\n* &nbsp;মেডিক্যাল ইনস্যুরেন্স এর সুবিধাসহ অন্যান্য সুবিধা প্রদান করা হবে।<br />\r\n* বিমানে আসা-যাওয়ার খরচ বাবদ ১,৫০০ সিঙ্গাপুর ডলার &nbsp;(বাংলাদেশী টাকায় প্রায় ১ লাখ ২২ হাজার টাকা) প্রদান করা হবে।</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>আবেদনের যোগ্যতাসমূহঃ</strong><br />\r\n* প্রথমবারের মতো ভর্তি হতে হবে।<br />\r\n* ইংরেজি ভাষায় দক্ষ হতে হবে।&nbsp;<br />\r\n* স্নাতক ও স্নাতকোত্তর ডিগ্রীধারী হতে হবে<br />\r\n* একাডেমিক ফলাফল ভালো হতে হবে।&nbsp;<br />\r\n* একাডেমিক রেফারি থেকে ভাল রিপোর্ট।</p>\r\n\r\n<p><strong>প্রয়োজনীয় নথিপত্রঃ</strong><br />\r\n* আবেদনকারীর পাসপোর্ট।<br />\r\n* আবেদনকারীর ছবি।<br />\r\n* একাডেমিক ট্রান্সক্রিপ্ট।<br />\r\n* সিভি।<br />\r\n* স্টেটমেন্ট অব পারপাস।<br />\r\n* রেফারেন্স লেটার দুইটি।<br />\r\n* আইএলটিএস/মিডিয়াম অব ইন্সট্রাকশন সনদ (যদি থাকে)।</p>\r\n\r\n<p><strong>আবেদনের প্রক্রিয়াঃ-&nbsp;</strong><br />\r\nঅনলাইনে আবেদন করতে এবং বিস্তারিত জানতে&nbsp;<a href=\"https://www.a-star.edu.sg/Scholarships/For-Graduate-Studies/Singapore-International-Graduate-Award-SINGA\" rel=\"noopener\" target=\"_blank\"><strong>ক্লিক করুন</strong></a>&nbsp;</p>', NULL, 18, 'slug-7-7thymway1l-8-T1Zwl5tLcT', '2024-02-17 09:26:49', '2024-06-01 06:30:30'),
(9, 1, 'মিলবে ৫১ লাখ টাকা,বিশ্বব্যাংক দেবে রবার্ট এস ম্যাকনামারা ফেলোশিপ', '1717187673-Rc4z8gLzpvuCYHPOzWEuBRdPkU2sQmM0.jpg', NULL, '<p><span style=\"font-size:14px\">বিদেশি শিক্ষার্থীদের গবেষণার জন্য &nbsp;বিশ্বব্যাংকের &lsquo;রবার্ট এস ম্যাকনামারা ফেলোশিপ প্রোগ্রাম&rsquo; নামের একটি ফেলোশিপ আছে। এর আওতায় নির্বাচিত শিক্ষার্থীরা পান ফেলোশিপ। আট মাসের জন্য দেওয়া হবে এ ফেলোশিপ। বাংলাদেশসহ বিশ্বব্যাংকের যেকোনো সদস্যদেশের স্নাতকোত্তর শেষ করা শিক্ষার্থীরা এ ফেলোশিপের জন্য আবেদন করতে পারবেন। এ ফেলোশিপের মেয়াদ এ বছরের সেপ্টেম্বর থেকে ২০২৫ সালের মে পর্যন্ত।</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>আবেদনের যোগ্যতা&mdash;</strong></span></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">ইংরেজিতে দক্ষতা থাকতে হবে;</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">স্নাতকোত্তর শেষ করা শিক্ষার্থী হতে হবে;</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">আবেদনকারীর বয়স ৩৫ বছরের কম হতে হবে (২০২৪ সালের জুনে এ বয়স);</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">ফেলোশিপে অংশগ্রহণের জন্য প্রার্থীদের অবশ্যই ওয়াশিংটন ডিসিতে স্থানান্তর করতে ইচ্ছুক হতে হবে।</span></p>\r\n	</li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:14px\"><strong>প্রয়োজনীয় নথি&mdash;</strong></span></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">আবেদনকারীকে আবেদনের সঙ্গে একটি সিভি দিতে হবে;</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">দুটি রেফারেন্স লেটার;</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">পারসোনাল স্টেটমেন্ট।</span></p>\r\n	</li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:14px\"><strong>সুযোগ-সুবিধাগুলো&mdash;</strong></span></p>\r\n\r\n<p><span style=\"font-size:14px\">ভিসা পেতে বিশ্বব্যাংকের মানবসম্পদ বিভাগ সহায়তা করবে;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">ফেলোশিপে ৮ মাসে ৪৬ হাজার ৫০০ মার্কিন ডলার দেওয়া হবে। (২০ ফেব্রুয়ারি ১ মার্কিন ডলার সমান ১০৯ টাকা ৮৭ পয়সা ধরে বাংলাদেশি মুদ্রায় ৫১ লাখ ৯ হাজার ১২৭ টাকা);</span></p>\r\n\r\n<p><span style=\"font-size:14px\">নির্বাচিত শিক্ষার্থীরা গবেষকদের তত্ত্বাবধানে বিশ্বব্যাংকে কাজ করার সুযোগ পাবেন।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">আবেদন করতে এবং বিস্তারিত জানতে এখানে <a href=\"https://www.worldbank.org/en/programs/scholarships/brief/robert-s-mcnamara-fellowships-program#1\" rel=\"nofollow\" target=\"_blank\">ক্লিক</a> করুন</span></p>', NULL, 3, 'slug-9-xcpddbvqbu-1-JPt0fiakpI', '2024-02-22 12:11:33', '2024-06-01 06:34:33'),
(10, 1, '২ ক্যাটাগরিতে ৭৫ ফেলোশিপ,ইউনেসকোর ফেলোশিপে চীনের বিশ্ববিদ্যালয়ে পড়াশোনা', '1717187800-J7RYTwB6V90jliPepzyHXJBWnjIASRwW.jpg', NULL, '<p><span style=\"font-size:14px\">চীন সরকার ও ইউনেসকো প্রতিবছর এ ফেলোশিপ প্রদান করে থাকে। ২০২৪-২৫ শিক্ষাবর্ষে ৭৫টি (পঁচাত্তর) ফেলোশিপ প্রদান করা হবে। ইউনেসকো&ndash;চায়না দ্য গ্রেট ওয়াল কো-স্পনসর্ড ফেলোশিপ &lsquo;জেনারেল স্কলার প্রোগ্রাম&rsquo; ও &lsquo;সিনিয়র স্কলার প্রোগ্রাম&rsquo; দুই ক্যাটাগরিতে আবেদন করা যাবে।২০২৪-২৫ শিক্ষাবর্ষে বিশ্বের অন্য দেশের সঙ্গে বাংলাদেশিরাও আবেদন করতে পারবেন। শিক্ষা, সংস্কৃতি, যোগাযোগ, বিজ্ঞান ও প্রযুক্তি ক্ষেত্রে এবং বিশ্বের জনগোষ্ঠীর মধ্যে ভ্রাতৃত্ববোধ জাগ্রত করার লক্ষ্যই এ ফেলোশিপ দেওয়া হয়।</span></p>\r\n\r\n<h2>আবেদন শেষ কবে</h2>\r\n\r\n<p><span style=\"font-size:14px\">ফেলোশিপে আবেদনপত্র (ইংরেজি ভাষায় লিখিত) ও আনুষঙ্গিক প্রয়োজনীয় কাগজপত্রসহ (দুই সেট হার্ডকপি ও সফটকপি) আবশ্যিকভাবে ২৭ ফেব্রুয়ারির মধ্যে বাংলাদেশ ইউনেসকো জাতীয় কমিশনে (শহীদ ক্যাপ্টেন মনসুর আলী সরণি, ১/ক, সেগুনবাগিচা, ঢাকা-১০০০) পাঠাতে হবে।</span></p>\r\n\r\n<h2>কারা এই ফেলোশিপে আবেদন করতে পারবেন</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">জেনারেল স্কলার প্রোগ্রামের জন্য আবেদনকারীর হাইস্কুল ডিপ্লোমা থাকতে হবে। এই ক্যাটাগরির আবেদনে বয়স সর্বোচ্চ ৪৫ বছর হতে পারে আবেদনকারীর।</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">সিনিয়র স্কলার প্রোগ্রামের জন্য আবেদনকারীর মাস্টার্স ডিগ্রি থাকতে হবে। আবেদনকারীকে সহযোগী অধ্যাপক হতে হবে। আবেদনকারীর বয়স ৫০ বছরের ওপরে হওয়া যাবে না।</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:14px\">জেনারেল স্কলার প্রোগ্রাম ও সিনিয়র স্কলার প্রোগ্রামে আবেদনের জন্য ইংরেজিতে দক্ষতা থাকতে হবে।</span></p>\r\n	</li>\r\n</ul>\r\n\r\n<h2>আবেদন কীভাবে</h2>\r\n\r\n<p><span style=\"font-size:14px\">আবেদনকারীদের অনলাইনে আবেদন করতে হবে। আবেদনের হার্ডকপি প্রিন্ট করে প্রিন্ট কপিসহ অন্যান্য প্রয়োজনীয় কাগজপত্র বাংলাদেশ ইউনেসকো কমিশনে জমা দিতে হবে। আবেদন&ndash;সম্পর্কিত বিস্তারিত তথ্য <a href=\"https://www.unesco.org/en/fellowships/greatwall\" rel=\"nofollow\" target=\"_blank\"> ওয়েবসাইটে</a> পাওয়া যাবে। চীন সরকারের নির্বাচিত বিশ্ববিদ্যালয়ের তালিকা <a href=\"https://www.campuschina.org/\" rel=\"nofollow\" target=\"_blank\">এই ওয়েবসাইটে</a> মিলবে বিস্তারিত তথ্য।</span></p>', NULL, 8, 'slug-10-kqgcxv8llh-1-4Cz9viffxB', '2024-02-23 12:14:50', '2024-06-01 06:36:40'),
(12, 1, 'রাশিয়ার বৃত্তি বাড়াতে বাংলাদেশ ও রাশিয়া চুক্তি', '1717187834-xYrf6QMmUdnazj0b5KwlpWM6FKHD9hZI.webp', NULL, '<p><span style=\"font-size:14px\">বাংলাদেশ ও রাশিয়া দুই দেশের ডিগ্রির পারস্পরিক গ্রহণযোগ্যতা নিশ্চিত করার জন্য চুক্তি করতে সম্মত হয়েছে ।শিক্ষামন্ত্রী মহিবুল হাসান চৌধুরী ও রাশিয়ান&nbsp; ডেপুটি হেড পাভেল শেফসভের মধ্যে এক দ্বিপক্ষীয় সভায় এ বিষয়ে সিদ্ধান্ত হয়। আজ বৃহস্পতিবার সচিবালয়ে শিক্ষামন্ত্রীর দপ্তরে এই সভা অনুষ্ঠিত হয়। </span></p>\r\n\r\n<p><span style=\"font-size:14px\">প্রতিনিধি দলে আরও ছিলেন রাশিয়ান দূতাবাসের কাউন্সিলর পাভেল দুবইচেনকফ, রাশিয়ার সিনারজি বিশ্ববিদ্যালয়ের ভাইস প্রেসিডেন্ট খাশিভ আলী খান ব্যসলানোবিচ, রাশিয়ান ফ্রেন্ডশিপ সোসাইটি উইথ বাংলাদেশের প্রেসিডেন্ট সাত্তার মিয়া প্রমুখ।</span></p>', NULL, 4, 'slug-12-5dovx0tljo-6-yeLzfFtyVd', '2024-02-24 22:41:40', '2024-06-01 06:37:14'),
(13, 1, 'স্নাতকদের মাস্টার্সে আগ্রহ কমছে । দেশ হারাচ্ছে বুদ্ধিবৃত্তিক মূলধন', '1717187872-PFuc66SR0gynTbTqYPnIhmlrpu3kXoym.jpg', NULL, '<p><span style=\"font-size:14px\">বিশ্ববিদ্যালয় মঞ্জুরি কমিশনের (ইউজিসি) সর্বশেষ প্রতিবেদন অনুযায়ী, বর্তমানে দেশে সরকারি-বেসরকারি মিলিয়ে মোট ১৬৩টি বিশ্ববিদ্যালয় রয়েছে। এর মধ্যে শিক্ষা কার্যক্রম চলমান রয়েছে ১৫৭টিতে। এসব বিশ্ববিদ্যালয় থেকে ২০২১ সালে ৪ লাখ ৬৫ হাজার ৮৮৩ জন শিক্ষার্থী স্নাতক সম্পন্ন করেছেন। তাদের মধ্যে থেকে মাত্র ৩ লাখ ৫৩ হাজার ২৫৪জন শিক্ষার্থী স্নাতকোত্তর (মাস্টার্স) প্রোগ্রামে ভর্তি হন। অর্থাৎ ১ লাখ ১১ হাজার ৮২৯ জন শিক্ষার্থী এই প্রোগ্রামে নথিভুক্ত হয়নি, যার ফলে ২৪ দশমিক ৪ শতাংশ বা এক চতুর্থাংশ শিক্ষার্থী দেশে উচ্চতর ডিগ্রির বাইরেই থেকে যাচ্ছে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">শিক্ষা সংশ্লিষ্টরা বলছেন, দেশে মানসম্মত শিক্ষার অভাব ও চাকরির সুযোগ সীমিত হওয়ায় বিদেশে পাড়ি দিচ্ছেন অনেক শিক্ষার্থী। এছাড়া সব সরকারি এবং অনেক বেসরকারি চাকরির জন্য স্নাতকোত্তর ডিগ্রির প্রয়োজন না থাকার কারণেও অনেক শিক্ষার্থী স্নাতক শেষ করেই চাকরির দিকে ঝুঁকছেন বলে মত সংশ্লিষ্টদের।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">তবে শিক্ষাবিদদের মতে, সকল শিক্ষার্থীর জন্য স্নাতকোত্তর ডিগ্রি অপরিহার্য নয়। শিক্ষার্থীদের চাকরির ক্ষেত্রের ওপর নির্ভর করে তারা উচ্চতর ডিগ্রি বেছে নিতে পারে। তাই অনেকে চাকরি শুরু করার পরেও ক্যারিয়ারে অগ্রগতি ও পদোন্নতির জন্য উচ্চ ডিগ্রি অর্জন করে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">এদিকে ইউনেস্কোর এক প্রতিবেদনে দেখা গেছে, ২০২৩ সালে বাংলাদেশ থেকে ৫২ হাজার ৭৯৯ জন শিক্ষার্থী উচ্চশিক্ষার জন্য বিশ্বের ৫৫টি দেশে পাড়ি জমিয়েছেন। ২০২১ সালে এই সংখ্যা ছিল ৪৯ হাজার ১৫১ জন এবং ২০২০ সালে ছিল ৪৪ হাজার ৩৩৮ জন। অর্থাৎ প্রতি বছর বাংলাদেশ থেকে উচ্চশিক্ষার জন্য বিদেশে যাওয়া শিক্ষার্থীর সংখ্যা উল্লেখযোগ্য হারে বাড়ছে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">দেশে বিশ্ববিদ্যালয়ের সংখ্যা বাড়লেও মানসম্মত শিক্ষা নিশ্চিত না হওয়াকে এর কারণ হিসেবে দেখছেন সংশ্লিষ্টরা। তারা বলছেন, ইউরোপ, আমেরিকার দেশগুলো উচ্চশিক্ষায় শিক্ষার্থীদের জন্য ভালো ও আধুনিক সুযোগ-সুবিধা নিশ্চিত করছে। ফলে বিদেশে ডিগ্রি নিতে এবং স্থায়ীভাবে বসবাস করতে আগ্রহী হচ্ছেন তারা। আর এ কারণে দেশ হারাচ্ছে বুদ্ধিবৃত্তিক মূলধন।</span></p>', NULL, 5, 'slug-13-zdnqg2ouy4-1-38X8IpEBno', '2024-02-24 23:26:23', '2024-06-01 06:37:52'),
(14, 1, 'পিএইচডির জন্য বৃত্তি দিচ্ছে সরকার,সিজিপিএ ৩.৫ হলে আবেদন । প্রতি মাসে ৩৫ -৪৫হাজার  টাকা।', '1717187918-omcav8ccbAwRAsNkTvd42395jDlhp9ir.webp', NULL, '<p><span style=\"font-size:14px\">প্রধানমন্ত্রীর গবেষণা ও উচ্চশিক্ষা সহায়তা তহবিল থেকে ২০২৪ সালের পিএইচডি বৃত্তি প্রদান করা হবে। দেশের বিভিন্ন বিশ্ববিদ্যালয় ও গবেষণাপ্রতিষ্ঠান থেকে নীতিমালায় উল্লিখিত বিষয়গুলোয় পিএইচডি ডিগ্রি অর্জনের লক্ষ্যে বাংলাদেশের নাগরিকদের কাছ থেকে নির্ধারিত ফরমে দরখাস্ত আহ্বান করেছে। আবেদন করা যাবে আগামী ৩১ মার্চ পর্যন্ত।&nbsp;বিদেশে উচ্চশিক্ষার স্বপ্নকে বাস্তবায়ন করতে অন্যতম মাধ্যম হলো বৃত্তি বা স্কলারশিপ। স্কলারশিপে টিউশন ফি, আবাসন ভাতা, যাতায়াত ভাতা, বিমানটিকিট ইত্যাদি অন্তর্ভুক্ত থাকে। তেমনই একটি সুযোগ দিচ্ছে বাংলাদেশ সরকার।&nbsp;</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2>যে সকল বিষয়গুলোর উপর ভিত্তি প্রদান করা হবে।&mdash;</h2>\r\n\r\n<p><span style=\"font-size:14px\">*প্রকৌশল ও কম্পিউটারবিজ্ঞান;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*তথ্য ও যোগাযোগপ্রযুক্তি;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*খাদ্য, কৃষি ও সমুদ্রবিজ্ঞান;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*অর্থনীতি/সামাজিক বিজ্ঞান;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*জীববিজ্ঞান;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*ফার্মেসি, চিকিৎসাবিজ্ঞান ও কমিউনিটি মেডিসিন;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*ভৌত বিজ্ঞান;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*কলা/মানবিক;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*বাণিজ্য;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*আইন;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*জলবায়ু ও পরিবেশবিজ্ঞান এবং</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*মহাকাশবিজ্ঞান।</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2>যোগ্যতা ও শর্তাবলি&mdash;</h2>\r\n\r\n<p><span style=\"font-size:14px\">*আবেদনকারীর বয়স অনূর্ধ্ব ৪৫ বছর হতে হবে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*আবেদনকারীর শিক্ষার সব স্তরে প্রথম বিভাগ/শ্রেণি/ন্যূনতম সিজিপিএ ৩.৫ (৪ এর মধ্য) থাকতে হবে;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">* ২০২৪ সাল থেকে শুরু হয়েছে এমন কোর্সে ভর্তি হয়েছেন বা ভর্তির নিশ্চয়তা পেয়েছেন এমন পিএইচডি কোর্সের গবেষকেরাই কেবল বৃত্তির জন্য আবেদন করতে পারবেন;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">*বিশেষ ক্ষেত্রে গবেষণার মেয়াদ সর্বোচ্চ ০৪ বছর পর্যন্ত বৃদ্ধি করা হলেও বৃত্তির মেয়াদ ০৩ বছরেই সীমাবদ্ধ থাকবে। তত্ত্বাবধায়ককে গবেষণাকার্য সমাপ্তির পর এককালীন সম্মানী প্রদান করা হবে। একাধিক তত্ত্বাবধায়কের ক্ষেত্রে এককালীন সম্মানী ভাতা ৬০: ৪০ হারে ভাগ করে প্রদান করা হবে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">* প্রধানমন্ত্রীর কার্যালয় এবং মাধ্যমিক ও উচ্চশিক্ষা বিভাগের <a href=\"https://pmo.gov.bd/site/notices/bd2ae443-18dd-4ecc-880b-f8200d6f40c5/%E0%A6%AA%E0%A7%8D%E0%A6%B0%E0%A6%A7%E0%A6%BE%E0%A6%A8%E0%A6%AE%E0%A6%A8%E0%A7%8D%E0%A6%A4%E0%A7%8D%E0%A6%B0%E0%A7%80%E0%A6%B0-%E0%A6%97%E0%A6%AC%E0%A7%87%E0%A6%B7%E0%A6%A3%E0%A6%BE-%E0%A6%93-%E0%A6%89%E0%A6%9A%E0%A7%8D%E0%A6%9A-%E0%A6%B6%E0%A6%BF%E0%A6%95%E0%A7%8D%E0%A6%B7%E0%A6%BE-%E0%A6%B8%E0%A6%B9%E0%A6%BE%E0%A7%9F%E0%A6%A4%E0%A6%BE-%E0%A6%A4%E0%A6%B9%E0%A6%AC%E0%A6%BF%E0%A6%B2-%E0%A6%A8%E0%A7%80%E0%A6%A4%E0%A6%BF%E0%A6%AE%E0%A6%BE%E0%A6%B2%E0%A6%BE%E0%A6%B0-%E0%A6%86%E0%A6%93%E0%A6%A4%E0%A6%BE%E0%A7%9F-%E0%A6%AA%E0%A6%BF%E0%A6%8F%E0%A6%87%E0%A6%9A%E0%A6%A1%E0%A6%BF-%E0%A6%AC%E0%A7%83%E0%A6%A4%E0%A7%8D%E0%A6%A4%E0%A6%BF-%E0%A7%A8%E0%A7%A6%E0%A7%A8%E0%A7%AA\" target=\"_blank\">ওয়েবসাইট</a> থেকে নীতিমালা এবং আবেদনপত্রের ফরম ডাউনলোড করা যাবে।</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2>বৃত্তির টাকা&mdash;</h2>\r\n\r\n<p><span style=\"font-size:14px\">*প্রথম বছরে প্রতি মাসে ৩৫ হাজার&nbsp; টাকা;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">* ২য় বছরে প্রতি মাসে ৪০ হাজার&nbsp; টাকা;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">* তৃতীয় বছরে প্রতি মাসে ৪৫ হাজার&nbsp; টাকা।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">তবে শর্ত থাকে যে ৩য় বছরের বৃত্তির হার ৫০ শতাংশ অর্থ থিসিস জমার পর প্রদান করা হবে।</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2>আবেদন শেষ কবে&mdash;</h2>\r\n\r\n<p><span style=\"font-size:14px\">&nbsp;রেজিস্ট্রিকৃত ডাকযোগে ৩১/৩/২০২৪ তারিখের মধ্যে পাঠাতে হবে। খামের ওপর অবশ্যই &lsquo;প্রধানমন্ত্রীর গবেষণা ও উচ্চশিক্ষা সহায়তা তহবিল পিএইচডি বৃত্তি আবেদন&rsquo; লিখতে হবে। আবেদনকারীকে সম্প্রতি তোলা ২ কপি পাসপোর্ট সাইজের ছবি, শিক্ষাগত যোগ্যতার প্রমাণপত্র ও মার্কশিটগুলোর সত্যায়িত কপিসহ&nbsp;আবেদনপত্রের সাথে জমা দিতে হবে&nbsp;।</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2>প্রদানের ঠিকানা</h2>\r\n\r\n<p><span style=\"font-size:14px\">ডেপুটি রেজিস্ট্রার (প্রশাসন&ndash;৩), কক্ষ নং&ndash;২০৬, প্রশাসনিক ভবন, ঢাকা বিশ্ববিদ্যালয়, ঢাকা।</span></p>\r\n\r\n<p>**<a href=\"https://pmo.gov.bd/site/notices/bd2ae443-18dd-4ecc-880b-f8200d6f40c5/%E0%A6%AA%E0%A7%8D%E0%A6%B0%E0%A6%A7%E0%A6%BE%E0%A6%A8%E0%A6%AE%E0%A6%A8%E0%A7%8D%E0%A6%A4%E0%A7%8D%E0%A6%B0%E0%A7%80%E0%A6%B0-%E0%A6%97%E0%A6%AC%E0%A7%87%E0%A6%B7%E0%A6%A3%E0%A6%BE-%E0%A6%93-%E0%A6%89%E0%A6%9A%E0%A7%8D%E0%A6%9A-%E0%A6%B6%E0%A6%BF%E0%A6%95%E0%A7%8D%E0%A6%B7%E0%A6%BE-%E0%A6%B8%E0%A6%B9%E0%A6%BE%E0%A7%9F%E0%A6%A4%E0%A6%BE-%E0%A6%A4%E0%A6%B9%E0%A6%AC%E0%A6%BF%E0%A6%B2-%E0%A6%A8%E0%A7%80%E0%A6%A4%E0%A6%BF%E0%A6%AE%E0%A6%BE%E0%A6%B2%E0%A6%BE%E0%A6%B0-%E0%A6%86%E0%A6%93%E0%A6%A4%E0%A6%BE%E0%A7%9F-%E0%A6%AA%E0%A6%BF%E0%A6%8F%E0%A6%87%E0%A6%9A%E0%A6%A1%E0%A6%BF-%E0%A6%AC%E0%A7%83%E0%A6%A4%E0%A7%8D%E0%A6%A4%E0%A6%BF-%E0%A7%A8%E0%A7%A6%E0%A7%A8%E0%A7%AA\" target=\"_blank\">বিস্তারিত জানতে ক্লিক করুন এখানে</a>।</p>\r\n\r\n<p>&nbsp;</p>', NULL, 13, 'slug-14-l82lafifqy-1-jDITyZ9zkx', '2024-02-25 21:47:01', '2024-06-01 06:38:38'),
(15, 1, 'আইইএলটিস ছাড়াই ৭০০টির বেশি বৃত্তি দিচ্ছে সুইডেন, এখনি আবেদন করুন', '1717187956-lxKCwnIWU57cjPHMNMqipKVIir4utnvY.webp', NULL, '<p>সুইডেন সরকার বিদেশি শিক্ষার্থীদের ফুল-ফ্রি স্কলারশিপে পড়াশোনা করার সুযোগ দিচ্ছে। বাংলাদেশসহ বিশ্বের কয়েকটি দেশের নাগরিক সুইডিশ ইনস্টিটিউট (এসআই স্কলারশিপ) স্কলারশিপ ফর গ্লোবাল প্রফেশনাল নামের এ বৃত্তির জন্য আবেদন করতে পারবেন।</p>\r\n\r\n<p>সুইডেন সরকারের এই এসআই বৃত্তি ২০২৪-২৫ শিক্ষাবর্ষের জন্য আবেদন চলছে। এসআই গ্লোবাল প্রফেশনাল স্কলারশিপ সম্পূর্ণ অর্থায়িত বৃত্তি, যা টিউশন ফি, জীবনযাত্রা, ভ্রমণের খরচ ও স্বাস্থ্যবিমা সুবিধা দেয়।</p>\r\n\r\n<p>বিদেশি শিক্ষার্থীদের জন্য সুইডিশ ইনস্টিটিউট (এসআই) ৭০০টির বেশি মাস্টার্স প্রোগ্রামের জন্য বৃত্তি দেবে। সম্পূর্ণ অর্থায়িত এ বৃত্তিতে মাস্টার্স প্রোগ্রামের সময় এক বা দুই বছর হতে পারে। এ স্কলারশিপে আবেদনের জন্য আইইএলটিএসের প্রয়োজন নেই। কেউ বৃত্তি পেলে ২০২৪ সালের অটাম সেমিস্টারে পড়াশোনা শুরু হবে।</p>\r\n\r\n<h2>এসআই বৃত্তির বিশদ বিবরণ&mdash;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>আয়োজক দেশ: সুইডেন</p>\r\n	</li>\r\n	<li>\r\n	<p>বৃত্তির নাম: সুইডিশ ইনস্টিটিউট (এসআই) গ্লোবাল প্রফেশনাল স্কলারশিপ</p>\r\n	</li>\r\n	<li>\r\n	<p>আর্থিক সুবিধা: সম্পূর্ণ অর্থায়ন</p>\r\n	</li>\r\n	<li>\r\n	<p>এসআই স্কলারশিপে আবেদনের শেষ দিন: ২৮ ফেব্রুয়ারি ২০২৪</p>\r\n	</li>\r\n	<li>\r\n	<p>স্কলারশিপের ফলাফল প্রকাশ: ২৫ এপ্রিল ২০২৪।</p>\r\n	</li>\r\n</ul>\r\n\r\n<h2>আর্থিক সুবিধা&mdash;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>সুইডিশ ইনস্টিটিউট গ্লোবাল স্কলারশিপ সুইডেনে পড়াশোনার জন্য সম্পূর্ণ অর্থায়িত বৃত্তি। এ বৃত্তিতে যেসব সুবিধা পাবেন শিক্ষার্থীরা।</p>\r\n	</li>\r\n	<li>\r\n	<p>সম্পূর্ণ টিউশন ফি ফ্রি।</p>\r\n	</li>\r\n	<li>\r\n	<p>জীবনযাত্রার খরচের জন্য মাসে ১২ হাজার সুইডিস ক্রোনার পাবেন শিক্ষার্থীরা (১ ক্রোনা সমান ১০.০৮ টাকা ধরলে বাংলাদেশি মুদ্রা টাকায় দাঁড়ায় ১ লাখ ২০ হাজার ৯৫০ টাকা)।</p>\r\n	</li>\r\n	<li>\r\n	<p>অসুস্থতা ও দুর্ঘটনার বিমা।</p>\r\n	</li>\r\n	<li>\r\n	<p>ভ্রমণের জন্য ১৫ হাজার সুইডিশ ক্রোনা অনুদান।</p>\r\n	</li>\r\n	<li>\r\n	<p>ফিউচার গ্লোবাল প্রফেশনালদের এসআই নেটওয়ার্কের সদস্যপদ।</p>\r\n	</li>\r\n</ul>\r\n\r\n<h2>কোন কোন বিষয়ে মিলবে বৃত্তি&mdash;</h2>\r\n\r\n<p>সুইডেনের এসআই বৃত্তিতে ১০০০টির মধ্যে ৭০০টির বেশি ইংরেজি ভাষার মাস্টার্স প্রোগ্রামের জন্য। মানবিক; কৃষিবিজ্ঞান; মেডিসিন ও জনস্বাস্থ্য; প্রাকৃতিক বিজ্ঞান; সামাজিক বিজ্ঞান ও প্রযুক্তিসহ বিভিন্ন বিষয়ে এসআই গ্লোবাল স্কলারশিপ প্রদান করে সুইডেন সরকার।</p>\r\n\r\n<h2>বৃত্তির যোগ্যতার মানদণ্ড&mdash;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>এ বৃত্তির আবেদনের জন্য বিদেশি শিক্ষার্থীদের অবশ্যই কিছু কিছু শর্ত বা নিয়ম মানতে হবে।</p>\r\n	</li>\r\n	<li>\r\n	<p>আপনাকে অবশ্যই একটি সুইডিশ বিশ্ববিদ্যালয়ে ভর্তি নিশ্চিত করতে হবে এবং জানুয়ারি ২০২৪&ndash;এর মধ্যে একটি অফার লেটার পেতে হবে।</p>\r\n	</li>\r\n	<li>\r\n	<p>আপনাকে অবশ্যই একটি যোগ্য মাস্টার্স ডিগ্রি প্রোগ্রামের জন্য আবেদন করতে হবে।</p>\r\n	</li>\r\n	<li>\r\n	<p>আপনাকে অবশ্যই একটি যোগ্য দেশের নাগরিক হতে হবে।</p>\r\n	</li>\r\n	<li>\r\n	<p>আবেদনকারীকে অবশ্যই তিন হাজার ঘণ্টার কাজের অভিজ্ঞতা থাকতে হবে।</p>\r\n	</li>\r\n</ul>\r\n\r\n<h2>প্রয়োজনীয় নথি</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>জীবনবৃত্তান্ত দিতে হবে, তবে এ ক্ষেত্রে জীবনবৃন্তাত্ত তিন পৃষ্ঠার বেশি হওয়া উচিত নয়।</p>\r\n	</li>\r\n	<li>\r\n	<p>দুটি রেফারেন্স লেটার থাকতে হবে।</p>\r\n	</li>\r\n	<li>\r\n	<p>কাজের অভিজ্ঞতার প্রমাণপত্র।</p>\r\n	</li>\r\n	<li>\r\n	<p>বৈধ পাসপোর্ট।</p>\r\n	</li>\r\n	<li>\r\n	<p>মোটিভেশন লেটার দিতে হবে।</p>\r\n	</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>', NULL, 10, 'slug-15-lwvuzstouj-1-NRZdyQ1loO', '2024-02-27 21:47:19', '2024-06-01 06:39:16'),
(16, 1, 'রাশিয়ায় স্নাতকোত্তর  করুন  সম্পূর্ণ বিনামূল্যে , সাথে ৪৬,০০০ টাকা বৃত্তি  থাকছে  প্রতিমাসে', '1717188058-DZXnCPgUeBkgSlYIYF4qEdTeam49WQpR.jpg', NULL, '<p>ফুল ফ্রি স্কলারশিপের আওতায় আন্তর্জাতিক শিক্ষার্থীদের দুই বছর মেয়াদি স্নাতকোত্তর প্রোগ্রামে অধ্যায়নের সুযোগ দিচ্ছে রাশিয়ার স্কলকভো ইনস্টিটিউট অব সায়েন্স অ্যান্ড টেকনোলজি (স্কলটেক)। বাংলাদেশসহ অন্যান্য দেশের শিক্ষার্থীরা আবেদন করতে পারবে। আবেদনের শেষ সময় স্নাতকোত্তর ১৫ জুলাই ২০২৪।&nbsp;</p>\r\n\r\n<p>স্কলটেক রাশিয়ার মস্কোতে অবস্থিত একটি বেসরকারি বিশ্ববিদ্যালয়। ২০১১ সালে ম্যাসাচুসেটস ইনস্টিটিউট অব টেকনোলজির (এমআইটি) সঙ্গে পার্টনারশিপে এই বিশ্ববিদ্যালয় প্রতিষ্ঠিত হয়। খুব অল্প সময়ের মধ্যেই স্কলটেক ওয়ার্ল্ড র্যাআঙ্কিংয়ে জায়গা করে নিয়েছে। স্কলটেক মূলত শিক্ষার্থীদের উচ্চশিক্ষার জন্য বিভিন্ন ডিগ্রি দিয়ে থাকে। এ বিশ্ববিদ্যালয়ে কোনো আন্ডারগ্র্যাজুয়েট প্রোগ্রাম নেই। এই স্কলারশিপ গ্রহণের মাধ্যমে শিক্ষার্থীরা প্রসিদ্ধ বিজ্ঞানী ও গবেষকদের তত্ত্বাবধানে শিক্ষাগ্রহণের সুযোগ পাবেন।&nbsp;</p>\r\n\r\n<p><strong>সুযোগ-সুবিধা</strong><br />\r\n* টিউশন ফি প্রদান করবে।<br />\r\n* আবেদন ফি নেই।<br />\r\n* প্রতি মাসে ৪০ হাজার রাশিয়ান রুবল দেওয়া হবে। বাংলাদেশী টাকায় (৪৬ হাজার ৩২৫ টাকা )<br />\r\n* মেডিকেল ইনস্যুরেন্স প্রদান করবে।<br />\r\n* রয়েছে এমআইটিসহ বিশ্বের অন্যান্য নামীদামি বিশ্ববিদ্যালয়ে কনফারেন্সের সুযোগ ।</p>\r\n\r\n<p><strong>যেসব বিষয়ে অধ্যয়ন করা যাবে</strong><br />\r\n* ডেটা সায়েন্স<br />\r\n* লাইফ সায়েন্স<br />\r\n* ম্যাটেরিয়াল সায়েন্স<br />\r\n* গণিত ও তাত্ত্বিক পদার্থবিজ্ঞান<br />\r\n* পেট্রোলিয়াম ইঞ্জিনিয়ারিং<br />\r\n* কম্পিউটেশনাল সায়েন্স অ্যান্ড ইঞ্জিনিয়ারিং<br />\r\n* স্পেস অ্যান্ড ইঞ্জিনিয়ারিং সিস্টেম<br />\r\n* এনার্জি সিস্টেম<br />\r\n* ইন্টারনেট অ্যান্ড ওয়্যারলেস টেকনোলজি<br />\r\n* ফটোনিকস অ্যান্ড কোয়ান্টাম ম্যাটেরিয়ালস<br />\r\n* অ্যাডভান্সড অ্যান্ড ডিজিটাল ইঞ্জিনিয়ারিং টেকনোলজি</p>\r\n\r\n<p><strong>যোগ্যতাসমূহঃ-&nbsp;</strong><br />\r\n* সংশ্লিষ্ট &nbsp;বিষয়ে স্নাতক ডিগ্রি থাকতে হবে।<br />\r\n* একাডেমিক ফলাফল ভালো হতে হবে।<br />\r\n* আবেদনকারী যদি মানবিক, সোশ্যাল সায়েন্স কিংবা ব্যবসায়ের কোনো বিষয়ে স্নাতক শেষ করে থাকেন, তবে &nbsp;সে বিষয়ে তাঁদের কাজের অভিজ্ঞতা কিংবা ট্রেনিং থাকতে হবে।<br />\r\n* আইইএলটিএস স্কোর ৬ অথবা টোফেল স্কোর ৮০ থাকতে হবে।&nbsp;<br />\r\n* আবেদনকারী যদি ইংরেজি মাধ্যমে স্নাতক ডিগ্রি নিয়ে থাকেন, তাহলে আইইএলটিএস কিংবা টোফেলের প্রয়োজন নেই।<br />\r\n* যাদের ইংরেজি ভাষায় দক্ষতার প্রমাণ নেই, স্কলটেকের নির্বাচনী সপ্তাহে &lsquo;টোফেল আইটিপি&rsquo; পরীক্ষা দিতে হতে পারে।</p>\r\n\r\n<p><strong>প্রয়োজনীয় নথিপত্র</strong><br />\r\n* সিভি।&nbsp;<br />\r\n* ১টি মোটিভেশনাল লেটার।&nbsp;<br />\r\n* ২টি রেকমেন্ডেশন লেটার।&nbsp;<br />\r\n* ইংরেজি ভাষা দক্ষতার সার্টিফিকেট।&nbsp;<br />\r\n* প্রাসঙ্গিক বিষয়ে ট্রেনিং সার্টিফিকেট।&nbsp;<br />\r\n* রাশিয়ায় যাওয়ার সব প্রয়োজনীয় কাগজপত্র।&nbsp;</p>\r\n\r\n<p><strong>আবেদনের প্রক্রিয়াঃ-&nbsp;</strong><br />\r\nঅনলাইনে আবেদন করা যাবে। অ্যাপ্লিকেশন জমা দেওয়ার পর আবেদনকারী প্রথম ধাপে উত্তীর্ণ হলে একটি অনলাইন পরীক্ষা দিতে হবে।&nbsp;</p>\r\n\r\n<p>আবেদন করতে এবং&nbsp;<a href=\"https://www.skoltech.ru/en/apply/msc-programs/\" rel=\"noopener\" target=\"_blank\"><strong>বিস্তারিত জানতে ক্লিক করুন</strong></a>&nbsp;</p>', NULL, 13, 'slug-16-tkza6hmknz-1-x9GiMtXQbK', '2024-02-29 04:54:18', '2024-06-01 06:40:58'),
(19, 1, 'স্নাতকোত্তর ও পি এইচ ডি তে স্কলারশিপ দিচ্ছে এশিয়ার এমআইটিও খ্যাত দক্ষিণ কোরিয়ার  কাইস্ট ইউনিভার্সিটি', '1717188096-sN2wkqbCq8R4bYzkNQvpCLyGDmeyHfsb.jpg', NULL, '<p><span style=\"font-size:14px\">সেমিস্টার-২০২৪ এ ২ বছর মেয়াদি স্নাতকোত্তর ও ৩ বছর মেয়াদি পিএইচডি প্রোগ্রামে ফুল-ফ্রি স্কলারশিপ দিচ্ছে দক্ষিণ কোরিয়ার অ্যাডভান্সড ইনস্টিটিউট অব সায়েন্স অ্যান্ড টেকনোলজি (কাইস্ট) । আবেদনের শেষ সময় ২৫শে মার্চ, ২০২৪,&nbsp;বাংলাদেশসহ অন্যান্য দেশের শিক্ষার্থীরাও আবেদন করতে পারবেন।&nbsp;&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">বিজ্ঞান ও প্রযুক্তির অত্যাধুনিক গবেষণার জন্য বিখ্যাত এই &nbsp;প্রতিষ্ঠানকে এশিয়ার এমআইটিও বলা হয়ে থাকে।&nbsp;বিশ্ববিদ্যালয়টি দক্ষিণ কোরিয়ার দেজন শহরে অবস্থিত।&nbsp;প্রসিদ্ধ বিজ্ঞানী ও গবেষকদের তত্ত্বাবধানে শেখার সুযোগ রয়েছে কাইস্টে।&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>আবেদনের যোগ্যতা</strong><br />\r\n* যেকোনো দেশের শিক্ষার্থী আবেদন করতে পারবেন।<br />\r\n* স্নাতকোত্তরে আবেদন করার জন্য শিক্ষার্থীর স্নাতক ডিগ্রি থাকতে হবে।<br />\r\n* পিএইচডিতে আবেদনের জন্য স্নাতকোত্তরে বা সমমানের ডিগ্রি থাকতে হবে।<br />\r\n* একাডেমিক ফলাফল ভালো হতে হবে।<br />\r\n* কোরিয়ান নাগরিকত্ব থাকলে আবেদন করা যাবে না।<br />\r\n* ইংরেজি ভাষা দক্ষতার সার্টিফিকেট থাকতে হবে। যেমন: আইএলটিএস ৬.৫, টোফেল ৮৩, টোইআইসি ৭২০ ও টিইপিএস ৩২৬</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>সুযোগ-সুবিধা</strong><br />\r\n* টিউশন ফি মওকুফ।<br />\r\n* স্কলারশিপ প্রাপ্ত শিক্ষার্থীদের মাসিক ভাতা প্রদান করবে।&nbsp;<br />\r\n* মেডিকেল ইনস্যুরেন্স।<br />\r\n* রিসার্চ অ্যাসাইনমেন্টের জন্য বাড়তি আর্থিক সহায়তা।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">উল্লেখ্য, আবেদনের সব কাগজপত্র ইংরেজি কিংবা কোরিয়ান ভাষায় জমা দিতে হবে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>প্রয়োজনীয় কাগজপত্র&nbsp;</strong><br />\r\n* সিভি।<br />\r\n* জাতীয় পরিচয়পত্র।<br />\r\n* পাসপোর্টের কপি।<br />\r\n* অ্যাপ্লিকেশন ফরম।<br />\r\n* মা-বাবার জাতীয় পরিচয়পত্রের কপি।<br />\r\n* মা-বাবার সঙ্গে পারিবারিক সম্পর্কের লিখিত কাগজপত্র।<br />\r\n* ট্রান্সক্রিপ্ট ও সার্টিফিকেট।<br />\r\n* ইংরেজি ভাষা দক্ষতার সার্টিফিকেট।<br />\r\n* দুটো রেকমেন্ডেশন লেটার।<br />\r\n* রিসার্চ প্রপোজাল।<br />\r\n* ফিন্যান্সিয়াল স্টেটমেন্ট।<br />\r\n* স্টেটমেন্ট অব পারপাস।<br />\r\n* কাজের অভিজ্ঞতা (যদি থাকে)।<br />\r\n* নিয়োগকারীর লিখিত প্রমাণ।<br />\r\n* এক্সট্রা কারিকুলার অ্যাকটিভিটিজ সার্টিফিকেট।</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>আবেদনের প্রক্রিয়া</strong><br />\r\nকাইস্টের অফিশিয়াল ওয়েবসাইট থেকে অনলাইনে আবেদন ফরম পূরণ করতে হবে।<br />\r\nঅ্যাপ্লিকেশন ফি জমা দিতে হবে। ফরমটি পূরণ করা হলে তা প্রিন্ট করে অন্য সব ডকুমেন্টের হার্ডকপি বিশ্ববিদ্যালয়ের নির্দিষ্ট ঠিকানায় জমা দিতে হবে।&nbsp;</span></p>', NULL, 3, 'slug-19-svefjx4wvm-1-z2aMiWNNrl', '2024-03-14 01:08:16', '2024-06-18 00:15:57'),
(21, 1, 'পৃথিবীর যেকোনো বিশ্ববিদ্যালয়ে পিএইচডি করুন আমেরিকার লিকে ফাউন্ডেশনের ভিত্তি ( scholarship) নিয়ে', '1717188173-pUbXCI08CQUD2TAkaJgPnxx6rJeb935I.png', NULL, '<p><span style=\"font-size:14px\">প্রতিবছর &nbsp;রিসার্চ গ্র্যান্টস প্রোগ্রামের অধীনে বিদেশি শিক্ষার্থীদের উচ্চশিক্ষার জন্য বৃত্তি ( scholarship) দিয়ে থাকি যুক্তরাষ্ট্রের ক্যালিফোর্নিয়া অঙ্গরাজ্যের সান ফ্রান্সিসকোতে দ্য লিকে ফাউন্ডেশন।এ বৃত্তির আওতায় শিক্ষার্থীরা বিশ্বের যেকোনো উচ্চশিক্ষা প্রতিষ্ঠানে বা গবেষণাপ্রতিষ্ঠানে পিএইচডি কিংবা পোস্ট ডক্টরাল ডিগ্রি অর্জনের সুযোগ পান।বাংলাদেশসহ বিশ্বের যেকোনো দেশের শিক্ষার্থীরা এ বৃত্তির আওতায় পিএইচডি ও পোস্ট ডক্টরালের জন্য আবেদন করতে পারবেন। আগ্রহীদের আবেদন করতে হবে অনলাইনে।</span></p>\r\n\r\n<h2>বৃত্তির পরিমাণ&mdash;৩ থেকে ১৫ হাজার মার্কিন ডলার।</h2>\r\n\r\n<p><span style=\"font-size:14px\">এ প্রোগ্রামে পড়াশোনার সব খরচ বহন করে দ্য লিকে ফাউন্ডেশন। পিএইচডি শিক্ষার্থীদের ৩ থেকে ১৫ হাজার মার্কিন ডলার। এ প্রোগ্রামের অর্থায়ন সর্বোচ্চ ২০ হাজার মার্কিন ডলার পর্যন্ত। এ ছাড়া সিনিয়র বা জ্যেষ্ঠ বিজ্ঞানী ও পোস্ট ডক্টরাল গবেষকদের অনুদান দেওয়া হয় সর্বোচ্চ ৩০ হাজার মার্কিন ডলার।</span></p>\r\n\r\n<h2>আবেদনের সময়সীমা</h2>\r\n\r\n<p><span style=\"font-size:14px\">লিকে ফাউন্ডেশন রিসার্চ গ্র্যান্টস প্রোগ্রামের আবেদন শেষ হবে চলতি বছরের ১৫ জুলাই।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">বৃত্তি&ndash;সম্পর্কিত বিস্তারিত তথ্য জানতে এখানে <a href=\"https://leakeyfoundation.org/grants/research-grants/\" rel=\"nofollow\" target=\"_blank\">ক্লিক করুন</a>।</span></p>\r\n\r\n<h2>পড়াশোনা কোথায়</h2>\r\n\r\n<p><span style=\"font-size:14px\">দ্য লিকে ফাউন্ডেশনের এই বৃত্তির আওতায় শিক্ষার্থীরা বিশ্বের যেকোনো বিশ্ববিদ্যালয় বা গবেষণা প্রতিষ্ঠানে পিএইচডি কিংবা পোস্ট ডক্টরাল ডিগ্রি অর্জনের সুযোগ পাবেন</span></p>', NULL, 4, 'slug-21-2gcwtemgyg-3-rj1JnUdIlr', '2024-03-16 22:11:18', '2024-06-01 06:42:53');
INSERT INTO `blogs` (`id`, `user_id`, `name`, `image_path`, `short_description`, `description`, `keyword`, `pageview`, `slug`, `created_at`, `updated_at`) VALUES
(22, 1, 'জাপানের ওআইএসটি ইনস্টিটিউট দিচ্ছে বিনামূল্যে ইন্টার্নশিপের সুযোগ প্রতিদিন থাকছে ২৪০০ ইয়েন', '1717188199-GGpQnYwLBIUFYxWbk8mhNl43uVsPNxtd.webp', NULL, '<p><span style=\"font-size:14px\">স্নাতক ও স্নাতকোত্তর শিক্ষার্থীদের &nbsp;দুই থেকে ছয় মাস মেয়াদী ইন্টার্নশিপ এর সুযোগ দিচ্ছে জাপানের ওকিনাওয়া ইনস্টিটিউট অফ সায়েন্স অ্যান্ড টেকনোলজি (ওআইএস টি) । বাংলাদেশসহ অন্যান্য দেশের শিক্ষার্থীরাও ১৫ এপ্রিলের মধ্যে আবেদন করতে পারবেন।</span></p>\r\n\r\n<p>(ওকিনাওয়া ইনস্টিটিউট অব সায়েন্স অ্যান্ড টেকনোলজি)</p>\r\n\r\n<p><img alt=\"OIST Okinawa Institute of Science and Technology\" src=\"data:image/jpeg;base64,\" style=\"float:left\" /><strong>যোগ্যতা:</strong></p>\r\n\r\n<p><span style=\"font-size:14px\">*ইংরেজিতে ভালো দক্ষতা থাকতে হবে।<br />\r\n*যেকোনো দেশের শিক্ষার্থীরা আবেদন করতে পারবেন;<br />\r\n*স্নাতক ও স্নাতকোত্তর পর্যায়ের শিক্ষার্থীরা আবেদন করতে পারবেন;<br />\r\n*ভালো ফল থাকতে হবে;</span></p>\r\n\r\n<p><strong>বিমান টিকেট সহ অন্যান্য সুযোগ-সুবিধা সমূহ:</strong></p>\r\n\r\n<p><span style=\"font-size:14px\">* শিক্ষার্থীরা প্রতি কর্মদিবসে ২ হাজার ৪০০ জাপানি ইয়েন পাবেন।&nbsp;&nbsp;বাংলাদেশি মুদ্রা ধরলে ১ হাজার ৮৪০ টাকা হয় (৩ জানুয়ারি&nbsp;হিসাবে);<br />\r\n*জাপানের বিমান টিকিট;<br />\r\n*ফ্রি ভিসা সাপোর্ট;<br />\r\n*আবাসন ও ইনস্যুরেন্স।</span></p>\r\n\r\n<p><strong>প্রয়োজনীয় নথিপত্র:</strong></p>\r\n\r\n<p><span style=\"font-size:14px\">* পাসপোর্ট ও জাতীয় পরিচয় পত্রের কপি<br />\r\n* রিকমেন্ডেশন লেটার<br />\r\n* ৪০০ শব্দের স্টেটমেন্ট অফ পারপাস<br />\r\n* শিক্ষাগত যোগ্যতার মার্কশীট ইংরেজিতে</span></p>\r\n\r\n<p><span style=\"font-size:14px\">গবেষণার বিষয়বস্তু শিক্ষাগত যোগ্যতা ও মেধার ভিত্তিতে ওআইএসটি বছরের দুই বার ইন্টার্নশিপ দেয় ২০২৪ সালের ১ই অক্টোবর শুরু হবে ইন্টার্নশিপ চলবে ২০২৫ সালের ৩১ শে মার্চ পর্যন্ত</span>।</p>\r\n\r\n<p><strong>আবেদনের প্রক্রিয়া:</strong><br />\r\nআগ্রহীরা&nbsp;&nbsp;<a href=\"https://admissions.oist.jp/apply-research-internship\" rel=\"nofollow\" target=\"_blank\">এই লিংক থেকে</a> ইন্টার্নশিপের বিস্তারিত তথ্য জেনে নিতে পারবেন।</p>', NULL, 12, 'slug-22-fnb3fbqtgb-1-C3bhLOXmJ6', '2024-03-18 00:40:28', '2024-06-01 06:43:19'),
(24, 1, 'জার্মানির যে বিশ্ববিদ্যালয়গুলোতে পড়াশোনা করতে আইইএলটিএস লাগবেনা ।', '1717188296-gCpohR94R57HoZrGHgiLxFnUbWtOGJcN.jpg', NULL, '<p>জার্মানি যে সাতটি বিশ্ববিদ্যালয় আইইএলটিএস ছাড়াই শিক্ষার্থীরা বিনামূল্যে পড়াশোনা করার সুযোগ পাবেন</p>\r\n\r\n<p>*এসলিনজেন ইউনিভার্সিটি অব অ্যাপ্লায়েড সায়েন্স<br />\r\n*ব্রাউনচেইইউগ ইউনিভার্সিটি অব টেকনোলজি;<br />\r\n*ইউনিভার্সিটি অব কোবলেঞ্জ অ্যান্ড ল্যান্ডউ;<br />\r\n*ইউনিভার্সিটি অব কাইসারস্লটার্ন;<br />\r\n*ইউনিভার্সিটি অব সিয়েজেন;<br />\r\n*ফ্রি ইউনিভার্সিটি অব বার্লিন;<br />\r\n*ইউনিভার্সিটি অব গিজেন;।</p>\r\n\r\n<p>জার্মানির এ বিশ্ববিদ্যালয়গুলোতে আইইএলটিএস ছাড়া ভর্তি হওয়া যাবে। পড়াশোনা শেষে অডি, বিএমডব্লিউ, ভক্সওয়াগন ও মার্সিডিজের মতো কোম্পানিতে চাকরি পাওয়ার সম্ভাবনা তৈরি হয়।তবে আইইএলটিএসের বিকল্প একটি পরীক্ষা নেবে&nbsp;এ ক্ষেত্রে অনেক সময় আন্ডারগ্র্যাজুয়েট শেষে বৃত্তি পাওয়ার সুযোগ বেশি।আবার কিছু ক্ষেত্রে ভর্তির পর মিলতে পারে বৃত্তিও।২০২৪ সালে ভর্তির জন্য এ সুযোগ পাবেন বিদেশি শিক্ষার্থীরা।</p>\r\n\r\n<h2>আইইএলটিএসের বিকল্প পরীক্ষা</h2>\r\n\r\n<p><strong>*</strong>&nbsp;শিক্ষার্থীর যদি পিটিই (PTE), টোয়েফল (TOEFL), ডুয়োলিঙ্গো (Duolinguo) বা সিএই (CAE) পরীক্ষার সনদ থাকে; তবে আইইএলটিএস পরীক্ষা দিতে হবে না।</p>\r\n\r\n<p><strong>*</strong>ইংরেজি ভাষায় দক্ষতা প্রমাণের জন্য আগের শিক্ষাপ্রতিষ্ঠানের কোর্সে সম্পূর্ণ রূপে ইংরেজি ভাষায় পড়ানো হয়েছিল, এমন একটি সনদ জার্মানির বিশ্ববিদ্যালয়ে জমা দিতে হবে। অর্থাৎ MOI (মিডিয়াম অফ ইন্সট্রাকশন)</p>\r\n\r\n<p>**<a href=\"https://daadscholarship.com/universities-in-germany-without-ielts-requirement-for-admissions-in-2024/\" rel=\"nofollow\" target=\"_blank\">বিস্তারিত দেখতে ক্লিক করুন&nbsp;</a></p>', NULL, 18, 'slug-24-riiicnibjk-1-6koKbxxZVY', '2024-03-19 07:54:54', '2024-06-01 06:44:56'),
(25, 1, 'ssc scholarship result 2024 /এসএসসি বৃত্তি ফলাফল 2024', '1717188382-w0vAFJp3XY9dVCPBFfNuD75Ww6yhyRjY.jpg', NULL, '<p><span style=\"font-size:14px\">এসএসসি বৃত্তি ফলাফল ২০২৪ অথবা SSC scholarship &nbsp;2024 এর ফলাফল সবার আগে জানতে Red Rose Academy এর ওয়েবসাইটে scholarship পেইজে চোখ রাখুন &nbsp;ফলাফল প্রকাশিত হওয়ার দিন আমরা আবার আপডেট নিউজে জানিয়ে দেবো</span></p>\r\n\r\n<p><span style=\"font-size:14px\">তাছাড়াও Red Rose Academy এর ওয়েবসাইটে Dutch Bangla scholarship &nbsp;এইচএসসি স্কলারশিপ ইউনিভার্সিটি স্কলারশিপ দেশ &nbsp;কিংবা বিদেশের যে কোন প্রকার স্কলারশিপ সম্পর্কে জানতে পারবেন।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">এর পাশাপাশি সরকারি কিংবা বেসরকারি যে ওয়েবসাইট গুলোতে আপনি ভিত্তি অথবা স্কলারশিপ এর নিউজ জানতে পারবেন</span></p>\r\n\r\n<p><span style=\"font-size:14px\">https://dinajpureducationboard.gov.bd/site/view/commondoc/Scholarship%20Result/</span></p>\r\n\r\n<p><span style=\"font-size:14px\">https://sylhetboard.gov.bd/public/attachment/2022/12/Final%20Scholarship%20SSC-2022.pdf</span></p>\r\n\r\n<p><span style=\"font-size:14px\">https://www.redrosebd.com/scholarship</span></p>', NULL, 12, 'slug-25-fyfwknhg3t-1-zKDyVmtsQf', '2024-03-22 01:02:18', '2024-06-01 06:46:22'),
(26, 1, 'জয়েন্ট জাপান ওয়ার্ল্ড ব্যাংক  দিচ্ছে অক্সফোর্ডসহ ১৯ বিশ্ববিদ্যালয়ে পড়াশোনার scholarship', '1717188444-LSMGuxs15m6JkqjoPVAbCPRihSENQoqm.png', NULL, '<p><span style=\"font-size:14px\">জয়েন্ট জাপান ওয়ার্ল্ড ব্যাংক গ্র্যাজুয়েট স্কলারশিপের আওতায় অক্সফোর্ড বিশ্ববিদ্যালয়, &nbsp;হার্ভার্ড বিশ্ববিদ্যালয়, ইউনিভার্সিটি অব টোকিও, ইউনিভার্সিটি অব লিডস, &nbsp;স্ট্যানফোর্ড বিশ্ববিদ্যালয়সহ বিশ্বের ১৯টি বিশ্ববিদ্যালয়ে পড়ার সুযোগ মিলবে। বিশ্বব্যাংকের তালিকাভুক্ত উন্নয়নশীল দেশগুলোর শিক্ষার্থীরা আবেদন করার সুযোগ পাবেন এ বৃত্তির জন্য।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">অ্যাপ্লিকেশন উইন্ডো-১ এ ২০২৪ সালের ১৫ জানুয়ারি থেকে ২৯ ফেব্রুয়ারি পর্যন্ত আবেদন করতে পেরেছেন আগ্রহী প্রার্থীরা। এ ধাপের নির্বাচিত প্রার্থীদের তালিকা প্রকাশ করা হবে ২০২৪ সালের মার্চে। প্রতিবছর শিক্ষার্থীরা দুটি সময়ে এ বৃত্তির জন্য আবেদনের সুযোগ পাবেন।এদিকে অ্যাপ্লিকেশন উইন্ডো-২&ndash;এ আবেদন শুরু হবে ২৫ মার্চ থেকে। এ ধাপে আবেদন চলবে আগামী ২৪ মে পর্যন্ত। নির্বাচিত প্রার্থীদের তালিকা প্রকাশ করা হবে ২০২৪ সালের জুনে।</span></p>\r\n\r\n<p><span style=\"font-size:16px\">বৃত্তির সুযোগ-সুবিধাগুলো&mdash; &nbsp; </span>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</p>\r\n\r\n<p><span style=\"font-size:14px\">মাসিক উপবৃত্তি দেওয়া হবে। যার মাধ্যমে আবাসন, খাবার ও বই কেনার ব্যয় বহন করা যাবে। &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">সম্পূর্ণ টিউশন ফি।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">বিমানে আসা-যাওয়ার টিকেট ।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">চিকিৎসা বিমা ।</span></p>\r\n\r\n<p><span style=\"font-size:16px\">আবেদনের প্রক্রিয়া</span></p>\r\n\r\n<p><span style=\"font-size:14px\">আগ্রহী প্রার্থীরা অনলাইনে আবেদন করতে পারবেন। আবেদন করতে এবং বিস্তারিত জানতে ঢুঁ মারতে পারবেন আগ্রহী প্রার্থীরা।&nbsp;বিশ্ববিদ্যালয়গুলোর তালিকা ও বিষয় দেখতে আগ্রহী প্রার্থীরা <a href=\"https://www.worldbank.org/en/programs/scholarships/jj-wbgsp\">ক্লিক </a>করতে পারেন।</span></p>\r\n\r\n<p><span style=\"font-size:16px\">যোগ্যতাগুলো&mdash;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">বিশ্বব্যাংকের সদস্যভুক্ত উন্নয়নশীল দেশের নাগরিক হতে হবে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">কোনো উন্নত দেশের দ্বৈত নাগরিকত্ব থাকা যাবে না।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">সুস্বাস্থ্যের অধিকারী হতে হবে।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">আবেদনের তারিখের কমপক্ষে তিন বছর আগে স্নাতকসম্পন্ন করতে হবে;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">উন্নয়ন&ndash;সম্পর্কিত কাজের সঙ্গে যুক্ত থাকতে হবে।</span></p>\r\n\r\n<p>&nbsp;</p>', NULL, 4, 'slug-26-gpzlzcu0bq-1-tLhDgHOejQ', '2024-03-25 22:26:38', '2024-06-01 06:47:24'),
(27, 1, 'আমেরিকা যাওয়ার সুযোগ সেই সাথে দেওয়া হবে ৫ লাখ টাকা / scholarship in USA', '1717188483-Spd1ZxmMUTb8vDf9JALhc3ZEwkNxi1jP.jpg', NULL, '<p><span style=\"font-size:14px\">১৯৫৪ সালে প্রতিষ্ঠিত হয়া&nbsp;এশিয়া ফাউন্ডেশন&nbsp;এশিয়া-প্যাসিফিক অঞ্চলে শান্তি প্রতিষ্ঠা ও সংঘাত নিরসনে শিক্ষাসফরের জন্য ফেলোশিপ দিচ্ছে।আবেদনের শেষ সময় ১২ মে, ২০২৪। নির্বাচিত ফেলোদের শিক্ষাসফরের পাশাপাশি অংশ নিতে হবে ভার্চুয়াল সেমিনারে। বাংলাদেশসহ নির্ধারিত আরও ২০টি দেশের নাগরিকরা আবেদন করতে পারবেন।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">নির্বাচিতরা আমেরিকার সান ফ্রান্সিককো বে এরিয়া, নিউইয়র্ক সিটি ও ওয়াশিংটন ডিসিতে অক্টোবরের ১৩ থেকে ২৬ তারিখ পর্যন্ত মোট ১২ দিন সশরীর উপস্থিত থাকবেন।সর্বমোট তিনজনকে এই ফেলোশিপ প্রদান করা হবে। এই শিক্ষাসফরের মাধ্যমে এশিয়া-প্যাসিফিক অঞ্চলে শান্তি প্রতিষ্ঠার কাজে অবদান রাখা অন্যান্য দেশের ফেলোদের সঙ্গে যোগাযোগ স্থাপন এবং এই বৈশ্বিক কমিউনিটির উন্নয়নে কাজ করার সুযোগ পাবেন ফেলোরা। এশিয়া ফাউন্ডেশনের &lsquo;বিভেদ ও দ্বন্দ্ব&rsquo; এবং &lsquo;নেতৃত্ব ও বিনিময়&rsquo;</span></p>\r\n\r\n<p><span style=\"font-size:14px\">এটি একটি অলাভজনক সংস্থা, যা এশিয়া &nbsp;অঞ্চলে বসবাসকারী জনগণের জীবনমানের উন্নয়ন ও সম্ভাবনাকে প্রসারিত করতে কাজ করে থাকে।এশিয়ার ২০টির বেশি দেশে ১৭টি স্থায়ী অফিস রয়েছে তাদের, যার মধ্যে একটি বাংলাদেশও রয়েছে। প্রশাসন, জলবায়ু, লিঙ্গসমতা, শিক্ষা ও নেতৃত্ব নিয়ে কাজ করে থাকে সংস্থাটি।&nbsp;</span></p>\r\n\r\n<p><strong><span style=\"font-size:14px\">সুযোগ-সুবিধাসমূহ&nbsp;</span></strong></p>\r\n\r\n<p><span style=\"font-size:14px\">*j- জে-১ ভিসার জন্য সহায়তা।* যুক্তরাষ্ট্রে যাওয়া, ফিরতি ও অভ্যন্তরীণ বিমান ভাড়া।<br />\r\n* শিক্ষা কার্যক্রম ফি।<br />\r\n* থাকা খাওয়ার ব্যবস্তা<br />\r\n* স্বাস্থ্যবিমা। &nbsp;<br />\r\n* শিক্ষানবিশি স্কুলে যাতায়াত ও পেশাগত উন্নয়ন ভাতা। &nbsp; &nbsp; &nbsp; &nbsp; </span></p>\r\n\r\n<p><span style=\"font-size:14px\">&nbsp; তাছাড়াও যুক্তরাষ্ট্রে ফুলব্রাইট টিইএ কার্যক্রমের আওতায় আমন্ত্রক বিশ্ববিদ্যালয়ের আয়োজনে সমাপনী সেমিনার, দুই সপ্তাহের জন্য যুক্তরাষ্ট্রের কোনো শিক্ষককে আতিথেয়তা দান এবং বিভিন্ন অনুদানের জন্য আবেদনের সুযোগ।</span></p>\r\n\r\n<p><strong><span style=\"font-size:14px\">আবেদনের যোগ্যতা</span></strong></p>\r\n\r\n<p><span style=\"font-size:14px\">১ ইংরেজিতে ভাষায় পারদর্শী হতে হবে। (আইইএলটিএস পরীক্ষার স্কোর ৬.০ থাকতে হবে) ২ বাংলাদেশি বৈধ পাসপোর্ট থাকতে হবে।৩ স্নাতক ডিগ্রি &nbsp;থাকতে হবে।৪ স্নাতকোত্তর স্তরের কোর্সওয়ার্কের জন্য ইংরেজি ভাষায় বিশেষ দক্ষতা থাকতে হবে।৫সংশ্লিষ্ট বিষয়গুলোতে শিক্ষাদানে ন্যূনতম পাঁচ বছরের অভিজ্ঞতা থাকতে হবে।৬মাইক্রোসফট ওয়ার্ড এবং এক্সেলসহ মাইক্রোসফট অফিস স্যুইট ব্যবহার জানা থাকতে হবে।৭মাধ্যমিক স্তরের শিক্ষকদের জন্য ইংরেজি, বিদেশি ভাষা হিসেবে ইংরেজি, গণিত, বিজ্ঞান, সোশ্যাল স্টাডিজ, সাংবাদিকতা ও যোগাযোগ এবং এর সঙ্গে বিশেষ শিক্ষার শিক্ষক।</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>আবেদন প্রক্রিয়া</strong><br />\r\nফেলোশিপের জন্য রেজিস্ট্রেশন করতে ভিজিট করুন বাংলাদেশের মার্কিন দূতাবাসের ওয়েবসাইটে&nbsp;</span></p>', NULL, 4, 'slug-27-nals5lsqhf-1-aNvyupejta', '2024-03-28 06:48:42', '2024-06-16 23:00:47'),
(29, 1, 'অপর্যাপ্ত ঘুম যেভাবে আপনার মস্তিষ্কের ১২ টা বাজাচ্ছে।', '1717188517-jhX6Wj7rHMOcvnihVBMaJKjH6ZsTeCEH.png', NULL, '<p><span style=\"font-size:14px\">আমাদের মস্তিষ্কের সবচেয়ে বেশি ক্ষতি হয় অপর্যাপ্ত ঘুমের কারণে।ঠিক এমনই একটি তথ্য উঠে আসে,যুক্তরাষ্ট্রের প্রিমিয়ার নিউরোলজি অ্যান্ড ওয়েলনেস সেন্টারের তথ্য অনুযায়ী।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">প্রাপ্তবয়স্কদের ক্ষেত্রে পর্যাপ্ত ঘুম বলতে ২৪ ঘণ্টায় ৭ থেকে ৮ ঘণ্টা ঘুমকে বোঝানো হয়। এক্ষেত্রে রাতে নিরবচ্ছিন্ন ঘুম সবচেয়ে বেশি কার্যকর।&nbsp;যদি আপনি আপনার মস্তিষ্ককে রক্ষা করতে চান তাহলে সমাধান একটাই- প্রতি রাতে কমপক্ষে সাত ঘণ্টা ঘুমানো। আট ঘণ্টা হলে বেশি ভালো।</span></p>\r\n\r\n<p dir=\"ltr\"><span style=\"font-size:14px\">ঘুমানোর সময় মস্তিষ্ক বিশ্রাম নেয়ার পাশাপাশি, বিষাক্ত পদার্থ পরিষ্কার করে এবং নতুন কোষ তৈরি করে। কিন্তু ৭ ঘণ্টার কম ঘুমালে নতুন কোষ গঠন হয় না। এর ফলে আপনি কিছু মনে রাখতে পারেন না, মনোযোগ দিতে কষ্ট হয়, মেজাজ খিটখিটে হয়ে যায়, সিদ্ধান্ত নিতে সমস্যা হয়। ঘুমের অভাবে ডিমেনশিয়া অ্যালঝেইমার্সের ঝুঁকিও বেড়ে যায়।</span></p>\r\n\r\n<p dir=\"ltr\"><span style=\"font-size:14px\">এজন্য যেটা করতে পারেন ঘুমের সময়ের অন্তত এক ঘণ্টা আগে বিছানায় যান,আর ঘুমের পরিবেশ তৈরি করতে আগেই শোবার ঘর পরিষ্কার করে নিন, ঘরের আলো কমিয়ে দিন, আপনার বিছানা, পোশাক, ঘরের তাপমাত্রা সবকিছু যেন আরামদায়ক হয়।এসময় কোনো ডিভাইস ব্যবহার করবেন না।</span></p>\r\n\r\n<p dir=\"ltr\"><span style=\"font-size:14px\">আরেকটা বিষয়- কখনও মাথা ঢেকে ঘুমাবেন না। কারণ মাথা ঢাকলে আপনার মাথার চারপাশে অক্সিজেনের পাশাপাশি প্রশ্বাসের সাথে বেরিয়ে আসা কার্বন ডাই অক্সাইড গ্যাস জমে থাকে।এই গ্যাসের মিশ্রণ নিশ্বাসের সাথে গ্রহণ করলে মস্তিষ্কে অক্সিজেনের ঘাটতি দেখা দেয়</span></p>', NULL, 2, 'slug-29-y9mhafdssx-1-gutqQsIcc3', '2024-04-02 06:54:40', '2024-06-01 06:48:37'),
(30, 1, 'জীবনে ব্যর্থতা কমিয়ে সফলতার হার বাড়ানোর উপায়।', '1717188589-n0zOLVSfbUTclM9375WTfnVu0NSyFSrB.png', NULL, '<p><span style=\"font-size:14px\">আপনি যখন আপনার ব্রেন কে জিজ্ঞাসা করেন আমার গার্লফ্রেন্ড আমাকে ছেরে দিয়েছে আমার কি মরে যাওয়া &nbsp;উচিত? &nbsp;আপনার ব্রেন এক ধাপ এগিয়ে বলবেন yes ! &nbsp;বস আপনার আত্মহত্যা করা উচিত এই জীবন রাখার কোন মানে হয় না। &nbsp; অথবা আমার কি চাকরি হবে না? &nbsp;ব্রেন থেকে signal &nbsp;আসবে, সারা বাংলাদেশে যে পরিমাণ ক্যান্ডিডেট আপনার চাকরি হওয়ার কোন সম্ভাবনা নাই। মানে হচ্ছে মানুষের শরীরের সবচেয়ে আনুগত্যশীল অঙ্গ হচ্ছে ব্রেন।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">আপনি ভাল বা খারাপ যেটাই চিন্তা করছেন ব্রেন আপনাকে একধাপ এগিয়ে উত্তরটা দিবে, ব্রেনের অ্যালগরিদম এভাবেই সাজানো। সেই সাথে &nbsp;আপনার পারিপার্শ্বিক পরিবেশ , প্রতিবেশী, বন্বুমহল &nbsp;কিংবা আপনি যেই শ্রেণীর লোকের সাথে চলাফেরা করেন তাদের নিতিবাচক &nbsp;চিন্তাভাবনা, দৃষ্টিভঙ্গি আপনাকে প্রভাবিত করছে বা &nbsp;আপনি চোখ দিয়ে যা দেখছেন যাদের সাথে কথা বলছেন তাদের নেতিবাচক চিন্তাগুলো আপনার ব্রেনকে প্রভাবিত করছে যে কারনে &nbsp;ব্রেইন আপনার যুক্তির পক্ষে আরও কয়েকটি শক্তিশালী নীতিবাচক &nbsp;উত্তর দিচ্ছে ।ফলাফল, আপনি সবসময় নেতিবাচক চিন্তা করতেই থাকেন যে আমাকে দিয়ে হবে না এটা করতে পারব না ঔটা করা যাবে না ইত্যাদি। এই চিন্তা নিজের মধ্যে থাকার কারণে কোন কাজ আপনি শুরুই করছেন না বা সেটার জন্য আপনি কোনো কাজ করছেন না আপনি শুধু সময় নষ্ট করছেন।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">সুতরাং স্বাভাবিকভাবেই আপনার মধ্যে কোন কাজে সফল হওয়ার হার কমে যাবে এটার জন্য কিন্তু আপনার অক্ষমতা দায়ী না, আপনি কাজ শুরু করছেন না বা চেষ্টা করছেন না মূলত এটাই ছিল এখানে দায়ী। উল্টাদিকে যারা &nbsp;বিশ্বাস করতে থাকে আমি এ কাজটা পারি বা পারবো বা এই কাজটা অমুক ব্যক্তি কিভাবে করেছে দিনের পর দিন আপনি ব্রেন কে প্রশ্ন করতে থাকেন মানি &nbsp;চেষ্টা করতে থাকেন একটা সময় ব্রেন আপনাকে ঠিকই সমাধান খুজে দিবে অথবা আপনার পারিপার্শ্বিক যে মানুষগুলোর সাথে আপনি চলাফেরা করছেন তাদের কাছ থেকে কোনো না কোনো সমাধান পেয়ে যাবেন।সুতরাং আমাদের উচিত নিজের চিন্তা ভাবনা এবং লক্ষ্যের সাথে মিলে এরকম বন্ধু তৈরি করা ও পারিপার্শ্বিকে অবস্থান করা &nbsp;সেই সাথে সব সময় নিজের মধ্যে আত্মবিশ্বাস বাড়ানো যে আমি এটা পারবো এবং চেষ্টা চালিয়ে যাওয়া।</span></p>\r\n\r\n<p><span style=\"font-size:14px\">তখন &nbsp;ব্রেন একটা সমাধান খুঁজে দেবে এবং পারিপার্শ্বিকতা থেকে আমরা অনেক কিছু শেখবো। আমাদের মধ্যে তৈরি হবে কাজ করার আগ্রহ &nbsp;যখন আমরা আগ্রহ &nbsp;নিয়ে কাজ করতে থাকবো একটা সময় সফলতা &nbsp;ধরা দিবে অথবা কোনো কাজে যখন একবার দুইবার বা তিনবার ব্যর্থ হবো কিন্তু &nbsp;চতুর্থবার বা পঞ্চবার ঠিকই &nbsp;সফলতা চলে আসবে। আসলে সফলতা বেশির &nbsp;বাগের জীবনে এভাবেই আসে ।প্রথমবার অথবা &nbsp;দ্বিতীয়বারই সব মানুষের জীবনের সফলতা &nbsp;ধরা দেয়না।&nbsp;</span></p>\r\n\r\n<p>(মোঃ নুরুজ্জামান)</p>', NULL, 13, 'slug-30-ojkyuj82ih-1-S5ROTi1Chv', '2024-04-03 01:49:18', '2024-06-01 06:49:49'),
(34, 1, 'ফ্রেডরিখ ইবার্ট স্টিফটাং“ স্কলারশিপে (scholarship) বিনামূল্যে ডক্টরাল করুন জার্মানিতে, মাসে থাকছে ১ লাখ টাকা।', '1717188638-1bqBQz3E9lwgMfekEOO6VYw9uap9jUFR.png', 'ফ্রেডরিখ ইবার্ট স্টিফটাং“ স্কলারশিপে ( scholarship)। আন্তর্জাতিক শিক্ষার্থীরা সম্পূর্ণ বিনামূল্যে ডক্টরাল স্টাডিজ প্রোগ্রামে অধ্যায়নের সুযোগ  দিচ্ছে জার্মানি। সাথে থাকছে মাসে থাকছে ১ লাখ টাকা,', '<p><span style=\"font-size:14px\">ফ্রেডরিখ ইবার্ট স্টিফটাং&ldquo; স্কলারশিপে&nbsp;( scholarship)। আন্তর্জাতিক শিক্ষার্থীরা সম্পূর্ণ বিনামূল্যে ডক্টরাল স্টাডিজ প্রোগ্রামে অধ্যায়নের সুযোগ&nbsp;&nbsp;দিচ্ছে জার্মানি।&nbsp;সাথে থাকছে&nbsp;মাসে থাকছে ১ লাখ টাকা,বর্তমানে উচ্চশিক্ষার জন্য&nbsp; ইউরোপের দেশগুলোর মধ্যে শিক্ষার্থীদের পছন্দের বিবেচনায় এগিয়ে থাকে জার্মানি।স্বনামধন্য বিশ্ববিদ্যালয়, বিশ্ব মানের শিক্ষাব্যবস্থা, সময়োপযোগী বিষয়, ইতিহাস ও ঐতিহ্য মিলিয়ে কেবল বাংলাদেশ নয়; পৃথিবীব্যাপী শিক্ষার্থীদের কাছেই কাঙ্ক্ষিত গন্তব্য জার্মানি।উন্নত এবং বিশ্বের ধনী দেশগুলোর মধ্যে জার্মানি অন্যতম।এর মূল কারণ হচ্ছে জার্মানির &nbsp;বিশ্ববিদ্যালয়গুলোতে পড়ার জন্য রয়েছে না ধরনের নজরকাড়া সব স্কলারশিপ।&nbsp;বাংলাদেশ সহ অন্যান্য সকল দেশের শিক্ষার্থীরা আবেদন করতে পারবেন। এই স্কলারশিপের জন্য যেকোন সময় আবেদন জমা দেওয়া যায়।বাংলাদেশ সহ অন্যান্য সকল দেশের শিক্ষার্থীরা আবেদন করতে পারবেন। এই স্কলারশিপের জন্য যেকোন সময় আবেদন জমা দেওয়া যায়।</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>সুযোগ-সুবিধা&nbsp;</strong><br />\r\n* সম্পূর্ণ টিউশন ফি প্রদান করবে ।&nbsp;<br />\r\n* উপবৃত্তি হিসেবে প্রতি মাসে ১২০০ ইউরো (বাংলাদেশী টাকায় ১ লক্ষ ৪২ হাজার ৬৯১ টাকা) &nbsp;প্রদান করবে।&nbsp;<br />\r\n* স্বাস্থ্যবিমা প্রদান করবে।&nbsp;<br />\r\n* মেডিকেল ব্যতীত অন্য সকল বিষয়ের শিক্ষার্থীরা আবেদন করতে পারবে।&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>আবেদন প্রক্রিয়া</strong><br />\r\nঅনলাইনের আবেদন করতে এবং&nbsp;<a href=\"https://www2.daad.de/deutschland/stipendium/datenbank/en/21148-scholarship-database/?status=&amp;origin=&amp;subjectGrps=&amp;daad=&amp;intention=&amp;q=friedrich&amp;page=1&amp;detail=10000126\" rel=\"noopener\" target=\"_blank\"><strong>বিস্তারিত জানতে ক্লিক করুন</strong></a></span></p>\r\n\r\n<p><span style=\"font-size:14px\"><strong>যোগ্যতাসমূহ</strong><br />\r\n* আন্তর্জাতিক শিক্ষার্থী হতে হবে।<br />\r\n* একাডেমিক ফলাফল ভালো হতে হবে।&nbsp;<br />\r\n* জার্মান ভাষায় দক্ষ হতে হবে।&nbsp;<br />\r\n* এশিয়া, আফ্রিকা ও লাতিন আমেরিকা, সোভিয়েত&ndash;পরবর্তী প্রজাতন্ত্রগুলোর এবং দক্ষিণ-পূর্ব ইউরোপের (ইউরোপীয় ইউনিয়নভুক্ত) দেশগুলোর নাগরিক হতে হবে।&nbsp;</span></p>', 'scholarship', 19, 'slug-34-ughx78eayn-1-1y3Bq2RWny', '2024-04-25 20:06:54', '2024-06-01 06:50:38'),
(35, 1, 'মাস্টার্সের শিক্ষার্থীদের জন্য  UEA Colfuturo Partner Award scholarship  সাথে  রয়েছে ৬ লাখ টাকা', '1717188671-xcd7CrgZFyMqmijgeZvPXS3XN4L1kw4p.png', '৬ লাখ টাকাসহ শুধুমাত্র বাংলাদেশের শিক্ষার্থীদের জন্য UEA Colfuturo Partner Award scholarship', '<pre>\r\n<span style=\"font-size:14px\">UEA-তে স্নাতকোত্তর কোর্সে আবেদন করা সমস্ত বাংলাদেশী শিক্ষার্থী স্বয়ংক্রিয়ভাবে এই বৃত্তি প্রদান করবে।</span></pre>\r\n\r\n<pre>\r\n<span style=\"font-size:14px\"><strong>যোগ্যতা</strong>\r\n1.সকল বাংলাদেশী ছাত্র যোগ্য।\r\n2.স্নাতকোত্তর কোর্সে আবেদন করতে হবে।</span></pre>\r\n\r\n<pre>\r\n<span style=\"font-size:14px\">সুবিধা এবং পুরস্কার মূল্য:\r\n&pound;4,000 - যদি আপনি UEA প্রবেশের প্রয়োজনীয়তা পূরণ করেন\r\n&pound;5,000 - যদি আপনার চূড়ান্ত স্নাতক GPA 3.2+ হয়\r\nশর্তাবলী অনুযায়ী আপনার টিউশন ফি থেকে পরিমাণ কেটে নেওয়া হবে* শুধুমাত্র সেপ্টেম্বর 2023 থেকে শুরু হওয়া কোর্সগুলি</span></pre>\r\n\r\n<pre>\r\n<span style=\"font-size:14px\"><strong>আবেদন</strong>\r\nএই স্কলারশিপটি আপনার অফার লেটার হাতে পাওয়ার পরপরই স্বয়ংক্রিয়ভাবে নিশ্চিত হয়ে যাবে ।স্বাস্থ্য বিজ্ঞানের শিক্ষার্থীদের জন্য দুই বৎসরের প্রোগ্রামে অধ্যায়ন করতে হবে । স্কলারশিপ টি শুধুমাত্র প্রথম বছরের জন্য প্রযোজ্য হবে।</span>\r\n</pre>\r\n\r\n<p><span style=\"font-size:14px\">আবেদন করতে বিস্তারিত জানতে <a href=\"https://www.uea.ac.uk/study/fees-and-funding/scholarships/uea-bangladesh-award\">এই লিঙ্কে ক্লিক করুন</a></span></p>', 'education news, daily education news, scholarship', 15, 'slug-35-mpna57p31j-1-mVlTz10rZ3', '2024-04-27 00:41:58', '2024-06-01 06:51:11'),
(36, 1, '২০২৪-২৫ শিক্ষাবর্ষের শিক্ষার্থীরা যুক্তরাজ্যে scholarship নিয়ে স্নাতকোত্তর করুন। সাথে ১০ হাজার পাউন্ড', '1717188715-3EoAe9n4Rkw7YyxuUlP7GprYFcNkXVZ4.jpg', 'বাংলাদেশি শিক্ষার্থীদের স্নাতকোত্তর করার ক্ষেত্রে ১৫টি গ্রেট স্কলারশিপের সুযোগ দেওয়া হচ্ছে, এ বছর যুক্তরাজ্যের ৭১টি বিশ্ববিদ্যালয়ে সাথে ১৩ লাখ টাকা', '<p><span style=\"font-size:16px\">গ্রেট স্কলারশিপের আওতায় এ বছর যুক্তরাজ্যের ৭১ টি বিশ্ববিদ্যালয়ে এক বৎসর মেয়াদে স্নাতকোত্তরের ক্ষেত্রে&nbsp;&nbsp;আন্তর্জাতিক&nbsp;শিক্ষার্থীদের জন্য &nbsp;১৫ টি গ্রেট স্কলারশিপ এর সুযোগ দেওয়া হয়েছে।ব্রিটিশ কাউন্সিলের পক্ষ থেকে এক বিজ্ঞপ্তিতে জানানো হয়েছে যে বিষয়ে স্কলারশিপের জন্য আবেদন করা যাবে বিষয়গুলো হচ্ছে&nbsp;ফাইন্যান্স, মার্কেটিং, বিজনেস, সাইকোলজি, ডান্স,সাইকোলজি ডিজাইন, হিউম্যানিটিজ।&nbsp;</span></p>\r\n\r\n<p><span style=\"font-size:16px\">এই বৃত্তির আওতায় ২০২৪-২৫ বাংলাদেশি শিক্ষার্থীরাও আবেদন করতে পারবেন।&nbsp;&nbsp;যুক্তরাজ্য সরকারের গ্রেট ব্রিটেন ক্যাম্পেইন ও ব্রিটিশ কাউন্সিলের সঙ্গে যৌথভাবে নির্দিষ্ট বিশ্ববিদ্যালয়ের অনুদানে এই গ্রেট স্কলারশিপ দেওয়া হয়।&nbsp;বিশ্ববিদ্যালয় ভেদে আবেদনের সময়ের ভিন্নতা রয়েছে।</span></p>\r\n\r\n<p><span style=\"font-size:16px\">যোগ্যতা:&nbsp;<br />\r\n* স্নাতক ডিগ্রিসম্পন্ন হতে হবে। প্রস্তাবিত বিষয়ে আগ্রহ থাকতে হবে।<br />\r\n* যুক্তরাজ্যের হায়ার এডুকেশন ইন্সটিটিউশনের ইংরেজি ভাষায় দক্ষতা থাকতে হবে।<br />\r\n* ব্যক্তিগত ও শিক্ষাগত যোগ্যতার মাধ্যমে যুক্তরাজ্যের সঙ্গে একজন শিক্ষার্থী হিসেবে সম্পর্ক স্থাপন করতে হবে।<br />\r\n* যুক্তরাজ্যভিত্তিক গ্রেট স্কলারদের নেটওয়ার্কে যোগ দিয়ে অভিজ্ঞতা শেয়ারের মানসিকতা থাকতে হবে।<br />\r\n* গ্রেট স্কলারশিপের একজন অ্যালামনাই হিসেবে কাজ করতে হবে।</span></p>\r\n\r\n<p><span style=\"font-size:16px\">সুযোগ-সুবিধাসমূহঃ-<br />\r\n২০২৪-২৫ শিক্ষাবর্ষে&nbsp;&nbsp;স্নাতকোত্তর কোর্সে অধ্যয়নের ক্ষেত্রে টিউশন ফি হিসেবে প্রতিটি গ্রেট স্কলারশিপের জন্য ১০ হাজার পাউন্ড অনুদান দেওয়া হবে। বাংলাদেশি টাকায় প্রায় ১৩ লাখ ৭২ হাজার ৮৪১ টাকা।</span></p>\r\n\r\n<p><span style=\"font-size:16px\">আবেদন প্রক্রিয়া:&nbsp;<br />\r\nআনলাইনে আবেদন করা যাবে। আবেদনকারীকে গ্রেট স্কলারশিপ&ndash;সংক্রান্ত বিস্তারিত তথ্য অফিসিয়াল ওয়েবসাইট থেকে জেনে নিতে হবে।&nbsp;অফিসিয়াল ওয়েবসাইট এর লিংক</span></p>', 'scholarship', 19, 'slug-36-o2nid1dbuj-1-iBafxnQL9U', '2024-05-01 02:14:13', '2024-06-01 06:51:55'),
(37, 1, 'কানাডায় ব্যান্টিং পোস্টডক্টরাল ফেলোশিপ, বছরে পাবেন ৫৬ লাখ টাকা পোস্ট ডক্টরের সুযোগ।', '1717188781-kKFqZH87daYoK2nhizZp0q8rCnawzlBg.jpg', 'বছরে পাবেন ৫৬ লাখ টাকা কানাডায় ( scholarship) পোস্ট ডক্টরের সুযোগ।', '<p><sup><span style=\"font-size:16px\">ব্যান্টিং পোস্টডক্টরাল ফেলোশিপ&rsquo; প্রোগ্রামের আওতায়&nbsp;বাংলাদেশসহ যে কোনো দেশের&nbsp; নির্বাচিত শিক্ষার্থীদের&nbsp;এ ফেলোশিপ&nbsp;দিচ্ছে কানাডা।&nbsp;ব্যান্টিং পোস্টডক্টরাল ফেলোশিপ প্রোগ্রামটি সেরা পোস্টডক্টরাল প্রার্থীদের জন্য তহবিল সরবরাহ করে থাকে।এ প্রোগ্রামের উদ্দেশ্য হল শীর্ষ-স্তরের পোস্টডক্টরাল প্রতিভাকে আকৃষ্ট করা&nbsp;&nbsp;বিশেষ করে যারা দেশের অর্থনৈতিক, সামাজিক এবং গবেষণা-ভিত্তিক বৃদ্ধিকে ইতিবাচকভাবে প্রভাবিত করবে।</span></sup></p>\r\n\r\n<p><sup><span style=\"font-size:16px\"><strong>সুযোগ সুবিধাসমূহ:</strong><br />\r\n* নির্বাচিত শিক্ষার্থীদের প্রতিবছর ৭০ হাজার কানাডিয়ান ডলার (বাংলাদেশি টাকায় প্রায় ৫৬ লাখ ৩ হাজার ৭১২ টাকা) প্রদান করা হবে।<br />\r\n* সেরা কানাডিয়ান সুপারভাইজারদের অধীনে তাদের গবেষণা প্রোগ্রামে কাজ করার সুযোগ পাবেন।<br />\r\n* শিক্ষার্থীরা ফেলোশিপের মাধ্যমে কানাডার বিভিন্ন প্রতিষ্ঠানে আবেদন করতে পারবেন।</span></sup></p>\r\n\r\n<p><sup><span style=\"font-size:16px\"><strong>আবেদনের যোগ্যতা</strong><br />\r\n* আবেদনকারীকে পিএইচডি ডিগ্রী সম্পন্ন হতে হবে।<br />\r\n* কানাডার স্থায়ী বাসিন্দা নন এমন শিক্ষার্থীরা এ ফেলোশিপ পাবেন।<br />\r\n* শুধুমাত্র কানাডিয়ান ইন্সটিটিউটে আবেদনকারীরা এ ফেলোশিপের জন্য আবেদন করতে পারবেন।<br />\r\n* আবেদনকারীদের অবশ্যই কাঙ্ক্ষিত সুপারভাইজারের সাথে যোগাযোগ করতে হবে এবং ব্যান্টিং ফেলোশিপের জন্য ইনস্টিটিউটের যোগ্যতা নিশ্চিত করতে হবে।</span></sup></p>\r\n\r\n<p><sup><span style=\"font-size:16px\"><strong>আবেদন পদ্ধতি</strong><br />\r\nঅনলাইনে আবেদন করা যাবে।</span></sup></p>\r\n\r\n<p><sup><span style=\"font-size:16px\">আবেদন প্রক্রিয়া জানতে&nbsp;<a href=\"https://banting.fellowships-bourses.gc.ca/en/app-dem_guide.html\" rel=\"noopener\" target=\"_blank\"><strong>অফিসিয়াল লিংকে ক্লিক করুন</strong></a>।</span></sup></p>', 'বছরে পাবেন ৫৬ লাখ টাকা কানাডায় পোস্ট ডক্টরের সুযোগ।', 11, 'slug-37-pf035qeufk-1-7mCAxY3NiZ', '2024-05-06 01:36:14', '2024-06-01 06:53:01');
INSERT INTO `blogs` (`id`, `user_id`, `name`, `image_path`, `short_description`, `description`, `keyword`, `pageview`, `slug`, `created_at`, `updated_at`) VALUES
(39, 1, 'ঘুমের প্রয়োজনীয়তা : ঘুম একটি প্রয়োজনীয়তা, বিলাসিতা নয়।', '1717188819-7AOs7CBCoKYqJXFFOp4tZtuyjx2425OM.jpg', 'হাফিংটন পর্যবেক্ষণ করেন যে আমাদের সাফল্যের জন্য ঘুম ত্যাগ করতে শেখানো হয়েছে। তিনি আরও উল্লেখ করেছেন যে ভাল বিশ্রামরত কর্মচারীরা আরও সৃজনশীল, দক্ষ এবং কার্যকর।', '<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:11pt\"><span style=\"font-family:Calibri,sans-serif\"><span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">হাফিংটন</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">পোষ্টের</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">প্রতিষ্ঠাতা</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">আরিয়ানা</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">হাফিংটন</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">সামগ্রিক</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">স্বাস্থ্যের</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">জন্য</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">ঘুমের</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">গুরুত্বের</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">উপর</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">জোর</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">দিয়েছেন</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">তার</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">২০২৩</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">সালের</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">বক্তৃতায়</span> &quot;<span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">ঘুমের</span> <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">শক্তি</span>&quot; <span style=\"font-family:&quot;Nirmala UI&quot;,sans-serif\">শীর্ষক</span> <span style=\"font-family:&quot;Nirmala UI&quot;,