		<tr>\r\n			<td style=\"height:153.85pt; vertical-align:top; width:91.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">PAST</span></span></span></p>\r\n			</td>\r\n			<td style=\"height:153.85pt; vertical-align:top; width:88.65pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16px\">NO Auxiliary verb, direct V2&nbsp;&nbsp;&nbsp;&nbsp;</span>&nbsp; &nbsp;&nbsp;</span></span></p>\r\n			</td>\r\n			<td style=\"height:153.85pt; vertical-align:top; width:99.75pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">was= I /Rahim/she/he/</span></span><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">your father</span></span></span></p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">were=you/they/Rahim &amp; Karim / Rahim &amp; Karim</span></span></span></p>\r\n			</td>\r\n			<td style=\"height:153.85pt; vertical-align:top; width:95.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">Had= I/you/they/she/he/Rahim/</span></span><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">Rahim &amp; Karim /my father</span></span></span></p>\r\n			</td>\r\n			<td style=\"height:153.85pt; vertical-align:top; width:102.8pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\">Had been = I/you/they/she/he/ Rahim/my father/Rahim &amp; Karim</span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"height:105.6pt; vertical-align:top; width:91.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">FUTURE</span></span></p>\r\n			</td>\r\n			<td style=\"height:105.6pt; vertical-align:top; width:88.65pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">Will = I/you/they/she/he/Rahim /my father/Rahim &amp; Karim /my father</span></span></span></p>\r\n			</td>\r\n			<td style=\"height:105.6pt; vertical-align:top; width:99.75pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">Will be= I/you/they /she/he/Rahim/my father /Rahim &amp; Karim/my father</span></span></span></p>\r\n			</td>\r\n			<td style=\"height:105.6pt; vertical-align:top; width:95.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">Will have= I/you/they/she/he/Rahim /</span></span></span></p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">Rahim &amp; Karim/my father</span></span></span></p>\r\n			</td>\r\n			<td style=\"height:105.6pt; vertical-align:top; width:102.8pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">Will have been = I /you/they/she/he/Rahim/my father / Rahim &amp; Karim</span></span></span></p>\r\n\r\n			<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">#&nbsp; টিকা</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">1.</span> <span style=\"font-size:14.0pt\">you have to pay </span><span style=\"font-size:18px\">তোমাকে খেলতে হবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;2.</span> <span style=\"font-size:14.0pt\">he has to eat </span><span style=\"font-size:18px\">তাকে খেতে হবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">3.</span> <span style=\"font-size:14.0pt\">they have to walk <span style=\"font-size:18px\">তাদের হাঁটতে হবে</span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">4.</span> <span style=\"font-size:14.0pt\">Rahim has to go <span style=\"font-size:18px\">রহিমকে যেতে হবে</span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">5.</span> <span style=\"font-size:14.0pt\">I have to come </span><span style=\"font-size:18px\">আমাকে আসতেই হবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p>&nbsp;</p>', NULL, 'auxiliary verb', 'vinn-vinn-verb-er-sathe-vinn-vinn-auxiliary-verb-er-bzbhar', 1, 24, '1', '2024-06-01 21:34:47', '2024-06-21 19:31:23'),
(102, 12, 'Affirmative  কিভাবে না বোধক অর্থাৎ negative এবং প্রশ্নবোধক অর্থাৎ interrogative বাক্যে পরিবর্তন করব', NULL, 'audio', 'Affirmative  / হ্যা বোধক বাক্যকে কিভাবে না বোধক অর্থাৎ negative এবং প্রশ্নবোধক অর্থাৎ interrogative বাক্যে পরিবর্তন করব', '<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">আমরা এতক্ষণ পর্যন্ত যতটুকু ইংরেজি শিখেছি সবগুলোই ছিল হ্যাঁ বোধক বাক্য অর্থাৎ আমি ঘুমিয়েছি সে খেয়েছে , না বোধক কোন বাক্য ছিল না এখন আমরা বিভিন্ন </span><span style=\"font-size:18px\">tense </span><span style=\"font-size:16px\">দিয়ে গঠিত</span><span style=\"font-size:18px\"> Affirmative &nbsp;/ </span><span style=\"font-size:16px\">হ্যা বোধক বাক্যকে কিভাবে না বোধক অর্থাৎ </span><span style=\"font-size:18px\">negative</span><span style=\"font-size:16px\"> এবং প্রশ্নবোধক অর্থাৎ </span><span style=\"font-size:18px\">interrogative </span><span style=\"font-size:16px\">বাক্যে পরিবর্তন করব এই নিয়মটি খুব সহজ পদ্ধতিতে শিখবো।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\"><strong>1.</strong> &nbsp;সাধারণত সকল </span><span style=\"font-size:18px\">tense </span><span style=\"font-size:16px\">এ </span><span style=\"font-size:18px\">auxiliary verb</span><span style=\"font-size:16px\"> এর পরের </span><span style=\"font-size:18px\">not </span><span style=\"font-size:16px\">যু্ক্ত&nbsp; করে</span><span style=\"font-size:18px\"> negative</span><span style=\"font-size:16px\"> বা না&zwnj; বোধক&nbsp; বাক্য গঠন করা হয় এবং</span><span style=\"font-size:18px\"> Auxiliary verb</span><span style=\"font-size:16px\"> কে বাক্যের&nbsp; সামনে নিয়ে এসে</span><span style=\"font-size:18px\"> Interrogative </span><span style=\"font-size:16px\">বা প্রশ্নবোধক&nbsp; গঠন করা হয়।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\"><strong>2.</strong> যেহেতু </span><span style=\"font-size:18px\">present &amp; past simple tense </span><span style=\"font-size:16px\">এ</span><span style=\"font-size:18px\"> Auxiliary verb</span><span style=\"font-size:16px\"> নাই, তাই </span><span style=\"font-size:18px\">present simple</span><span style=\"font-size:16px\"> এ </span><span style=\"font-size:18px\">Do/does </span><span style=\"font-size:16px\">এবং</span><span style=\"font-size:18px\"> past simple did Auxiliary</span><span style=\"font-size:16px\"> হিসেবে ব্যবহার হয়।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">(তবে মনে রাখতে হবে </span><span style=\"font-size:18px\">present simple tense </span><span style=\"font-size:16px\">এর </span><span style=\"font-size:18px\">subjec</span><span style=\"font-size:16px\">t যদি </span><span style=\"font-size:18px\">third person</span><span style=\"font-size:16px\"> এবং</span><span style=\"font-size:18px\"> singular </span><span style=\"font-size:16px\">নাম্বার হয় তাহলে </span><span style=\"font-size:18px\">does</span><span style=\"font-size:16px\"> হবে আর তাছাড়া </span><span style=\"font-size:18px\">present simple tense </span><span style=\"font-size:16px\">এর অন্য যে কোন সাবজেক্ট এর ক্ষেত্রেই do বসবে )</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"><strong>Present indefinite tens</strong></span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">&nbsp; </span><span style=\"font-size:18px\"># I chat with you </span><span style=\"font-size:16px\">আমি খুশ গল্প করি তুমার সাথে। </span><span style=\"font-size:18px\">(Affirmative)&nbsp;</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">&nbsp;&nbsp;&nbsp;</span><span style=\"font-size:18px\"> I don&#39;t chat with you </span><span style=\"font-size:16px\">আমি খুশ গল্প করিনা&nbsp; তুমার সাথে। </span><span style=\"font-size:18px\">(Affirmative এর Negative)</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">&nbsp;&nbsp;&nbsp; D0, I chat with you</span><span style=\"font-size:16px\"> আমি কি খুশ গল্প করি তুমার সাথে?&nbsp;&nbsp; </span><span style=\"font-size:18px\">(Interrogative)</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">&nbsp;&nbsp;&nbsp; </span><span style=\"font-size:18px\">Don&#39;t I chat with you </span><span style=\"font-size:16px\">আমি কী খুশ গল্প করি না তুমার সাথে? </span><span style=\"font-size:18px\">(Interrogative এর negative)</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"># Affirmative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She helps me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করে।</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She doesn&#39;t help me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করে না।</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Interrogative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Does she help me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করে?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative Interrogative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Doesn&#39;t she help me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করে না?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"># My father butchers this cow</span><span style=\"font-size:16px\"> আমার বাবা এই গরুটী&nbsp; জবাই&nbsp; করে</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">&nbsp;&nbsp; </span><span style=\"font-size:18px\">My father doesn&rsquo;t butcher this cow</span><span style=\"font-size:16px\"> আমার বাবা এই গরুটী&nbsp; জবাই&nbsp; করেনা</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">&nbsp;&nbsp;</span><span style=\"font-size:18px\"> Does My father butcher this cow</span><span style=\"font-size:16px\"> আমার বাবা&nbsp; কি&nbsp; এই গরুটি জবাই&nbsp; করে ?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">&nbsp;&nbsp; </span><span style=\"font-size:18px\">Doesn&rsquo;t my father butcher this cow? </span><span style=\"font-size:16px\">আমার বাবা&nbsp; কি&nbsp; এই গরুটি জবাই&nbsp; করে না</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"><strong>Present <a name=\"_Hlk168237717\">continuous tens</a></strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Affirmative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She is helping me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করছে।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She is not helping me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করছে না।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Interrogative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Is she helping me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করছে?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative Interrogative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Isn&#39;t she helping me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করছে না?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"><strong>Present perfect tense tens</strong></span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Affirmative</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She has helped me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করেছে।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She hasn&#39;t helped me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করে নি।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Interrogative</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Has she helped me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করেছে?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative Interrogative</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Hasn&#39;t she helped me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করে নি?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"><strong>Present perfect continuous tens</strong></span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"><a name=\"_Hlk168237968\">Affirmative</a></span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She has been helping me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করে আসছে।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She hasn&#39;t been helping me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করে আসছে না।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Interrogative</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Has she been helping me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করে আসছে?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative Interrogative</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Hasn&#39;t she been helping me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করে আসছে না? সে কি আমাকে সাহায্য করছিল না?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\"><strong>PAST INDEFINITE</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"># I chatted with you</span><span style=\"font-size:16px\"> আমি খুশ গল্প করতাম&nbsp; তুমার সাথে</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">&nbsp;I didn&rsquo;t chat with you </span><span style=\"font-size:16px\">আমি খুশ গল্প&nbsp;&nbsp; করতাম না তুমার সাথে</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">&nbsp;Did I chat with you?</span><span style=\"font-size:16px\"> আমি কি খুশ গল্প করতাম তুমার সাথে?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Didn&#39;t I chat with you </span><span style=\"font-size:16px\">আমি কি খুশ গল্প করতাম না তুমার সাথে?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\"><strong>Past continuous tense</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\"><strong>&nbsp;&nbsp;</strong></span><span style=\"font-size:18px\">Affirmative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She was helping me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করছিল।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">She wasn&#39;t helping me.</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে আমাকে সাহায্য করছিল না।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Interrogative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Was she helping me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">সে কি আমাকে সাহায্য করছিল?</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Negative Interrogative:</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:18px\">Wasn&#39;t she helping me?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\"><strong>সে কি আমাকে সাহায্য করছিল না?</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">একই&nbsp; পদ্ধতিতে বাকি </span><span style=\"font-size:18px\">tense </span><span style=\"font-size:16px\">গুলো </span><span style=\"font-size:18px\">Affirmative</span><span style=\"font-size:16px\"> থেকে </span><span style=\"font-size:18px\">negative </span><span style=\"font-size:16px\">ও </span><span style=\"font-size:18px\">interrogative </span><span style=\"font-size:16px\">এ পরিবর্তন করা যাবে আপনারা বাকি tense গুলো নিজে নিজে</span><span style=\"font-size:18px\"> practice&nbsp;</span><span style=\"font-size:16px\"> করে নিবেন</span></span></p>', NULL, 'Affirmative sentence , interrogative sentence, negatives sentence', 'affirmative-kivabe-na-bodhk-orthatt-negative-ebng-prsnbodhk-orthatt-interrogative-bakze-pribrtn-krb', 1, 30, '1', '2024-06-02 21:44:54', '2024-06-21 06:19:32'),
(103, 12, 'সকল tense , affirmative , negative and interrogative  শিক্ষার উপর অনুশীলন করি', NULL, 'normal', 'আসুন আমাদের সকল tense , affirmative , negative and interrogative  শিক্ষার উপর অনুশীলন করি', '<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:15.0pt\">you are learning English slowly from Red-Rose Academy/you aren&#39;t learning English properly/Aren&rsquo;t you learning English from your teacher? /You have completed your lesson for next class/You haven&rsquo;t finished your tomorrow&#39;s lesson /Haven&#39;t you finished your lesson? /You have been learning English for 3 hours/You haven&rsquo;t been practicing English for 2 hours/ Haven&#39;t you been practicing English for 2 hours?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">তুমি ধীরে ধীরে রেড-রোজ একাডেমি থেকে ইংরেজি শিখতেছো/তুমি যথাযথভাবে ইংরেজি শিখতেছো না/তুমি কি তোমার শিক্ষকের কাছ থেকে ইংরেজি শিখতেছো না?/তুমি তোমার পরবর্তী ক্লাসের পাঠ শেষ করেছো/তুমি তোমার আগামীকালের পাঠ শেষ করো নাই/তুমি কি তোমার পাঠ শেষ করো নাই?/তুমি তিন ঘন্টা ধরে ইংরেজি শিখতেছো/তুমি দুই ঘন্টা ধরে ইংরেজি চর্চা করতেছো না/তুমি কি দুই ঘন্টা ধরে ইংরেজি চর্চা করতেছো না?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong>&nbsp;&nbsp;<span style=\"font-size:14.0pt\">Usage of all Past Tenses</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\">&nbsp;<span style=\"font-size:14.0pt\">He was playing cricket in the afternoon / He wasn&#39;t playing football with his friend/ Wasn&#39;t he playing cricket with his friends in the field? /He had done his Work before going there/He hadn&#39;t done his work before going there/Hadn&#39;t he done his work before going there? /He had been playing for 2hours /He hadn&#39;t been playing for 2 hours/ Hadn&#39;t he been playing for 2 hours?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">সে বিকালে ক্রিকেট খেলতেছিলো/সে তার বন্ধুদের সাথে ফুটবল খেলতেছিলো না/সে কি মাঠে তার বন্ধুদের সাথে ক্রিকেট খেলতেছিলো না?সে সেখানে যাওয়ার আগে কাজ শেষ করেছিলো/ সে সেখানে যাওয়ার আগে কাজ শেষ করেছিলো না/সে কি সেখানে যাওয়ার আগে কাজ শেষ করেছিলো না?সে দুই ঘন্টা ধরে খেলতেছিলো /সে দুই ঘন্টা ধরে খেলতেছিলো না/সে কি দুই ঘন্টা ধরে খেলতেছিলো না?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong>&nbsp;<span style=\"font-size:14.0pt\">Usage of all Future Tenses</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">I will learn English from red rose academy/ I will not learn English from other academy/ Won&#39;t I learn English from red rose academy? /I will be playing cricket /I won&#39;t be playing football /won&#39;t I be playing cricket? I will have finished this work before you come/I won&#39;t have finished this work before you come/ Won&#39;t I have finished this work before you come? I will have been playing cricket for 2 hours/ I won&#39;t have been playing football for 2 hours/Won&#39;t I have been playing cricket for 2 hours?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">আমি রেড-রোজ একাডেমি থেকে ইংরেজি শিখবো/আমি অন্য কোন একাডেমি থেকে ইংরেজি শিখবো না/আমি কি রেড-রোজ একাডেমি থেকে ইংরেজি শিখবো না?/আমি ক্রিকেট খেলতে থাকবো/আমি ফুটবল খেলতে থাকবো না/আমি কি ক্রিকেট খেলতে থাকবো না?/তুমি আসার আগে আমি এই কাজটি শেষ করে থাকবো/তুমি আসার আগে আমি এই কাজটি শেষ করে থাকবো না/তুমি আসার আগে আমি কি এই কাজটি শেষ করে থাকবো না?/আমি দুই ঘন্টা ধরে ক্রিকেট খেলতে থাকবো/আমি দুই ঘন্টা ধরে ফুটবল খেলতে থাকবো না/আমি কি দুই ঘন্টা ধরে ক্রিকেট খেলতে থাকবো না?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\">PRESENT CONTINUOUS</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;&nbsp; I am clamping with your speech </span><span style=\"font-size:12.0pt\">তোমার</span> <span style=\"font-size:12.0pt\">বক্তৃতায়</span> <span style=\"font-size:12.0pt\">আমি</span> <span style=\"font-size:12.0pt\">হাততালি</span> <span style=\"font-size:12.0pt\">দিচ্ছি</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp; I am not clamping with your speech </span><span style=\"font-size:12.0pt\">তোমার</span> <span style=\"font-size:12.0pt\">বক্তৃতায়</span> <span style=\"font-size:12.0pt\">আমি</span> <span style=\"font-size:12.0pt\">হাততালি</span> <span style=\"font-size:12.0pt\">দিচ্ছি</span> <span style=\"font-size:12.0pt\">না</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;Am I clamping with your speech </span><span style=\"font-size:12.0pt\">আমি</span> <span style=\"font-size:12.0pt\">কি</span> <span style=\"font-size:12.0pt\">তোমার</span> <span style=\"font-size:12.0pt\">বক্তৃতায়</span>&nbsp; <span style=\"font-size:12.0pt\">হাততালি</span> <span style=\"font-size:12.0pt\">দিচ্ছি?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:justify\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;Am not I clamping with your speech </span><span style=\"font-size:12.0pt\">আমি</span> <span style=\"font-size:12.0pt\">কি</span> <span style=\"font-size:12.0pt\">তোমার</span> <span style=\"font-size:12.0pt\">বক্তৃতায়</span>&nbsp; <span style=\"font-size:12.0pt\">হাততালি দিচ্ছিনা?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">একইভাবে বাকি সকল tense গুলো দিয়ে আমরা Affirmative/ negative বাক্য&nbsp;&nbsp; গঠন করতে পারব।</span></span></span></p>', NULL, NULL, 'skl-tense-affirmative-negative-and-interrogative-sikshar-upr-onuseeln-kri', 1, 23, '1', '2024-06-02 22:11:25', '2024-06-21 17:38:58');
INSERT INTO `book_items` (`id`, `chapter_id`, `title`, `sub_title`, `type`, `short_details`, `details`, `audio_text`, `keyword`, `slug`, `status`, `pageview`, `added_by`, `created_at`, `updated_at`) VALUES
(104, 12, 'Long forms, contracted forms (short forms) of auxiliaries এর শর্ট ফর্ম লং ফ্রম', NULL, 'audio', 'Long forms, contracted forms (short forms) of auxiliaries verb এর শর্ট ফর্ম লং ফ্রম', '<div style=\"border-bottom:solid #dcaa1e 4.5pt; padding:0in 0in 6.0pt 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><strong><span style=\"font-size:18.0pt\"><span style=\"color:black\">1.&nbsp;<em>To be (am, are, is)</em></span></span></strong></span></span></span></p>\r\n</div>\r\n\r\n<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:-9.0pt; width:612px\">\r\n	<thead>\r\n		<tr>\r\n			<td colspan=\"2\" style=\"background-color:#f9f6eb; width:181.85pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Affirmative</span></span></strong></span></span></p>\r\n			</td>\r\n			<td colspan=\"2\" style=\"background-color:#f9f6eb; width:277.15pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Negative</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f9f6eb; width:75.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Long form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Contracted form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:80.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Long form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:196.9pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Contracted form</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:75.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">I&nbsp;<strong><span style=\"color:#129b50\">am</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">I<strong><span style=\"color:#129b50\">&#39;m</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:80.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">I&nbsp;<strong><span style=\"color:#129b50\">am&nbsp;</span><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:196.9pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">I<strong><span style=\"color:#129b50\">&#39;m&nbsp;</span><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td rowspan=\"2\" style=\"width:75.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">you&nbsp;<strong><span style=\"color:#129b50\">are</span></strong></span></span></span></p>\r\n			</td>\r\n			<td rowspan=\"2\" style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">you<strong><span style=\"color:#129b50\">&#39;re</span></strong></span></span></span></p>\r\n			</td>\r\n			<td rowspan=\"2\" style=\"width:80.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">you&nbsp;<strong><span style=\"color:#129b50\">are&nbsp;</span><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:196.9pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">you<strong><span style=\"color:#129b50\">&#39;re</span></strong>&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:196.9pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">you&nbsp;<strong><span style=\"color:#129b50\">are</span><span style=\"color:#cd4b3c\">n&#39;t</span></strong></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td rowspan=\"2\" style=\"width:75.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">he&nbsp;<strong><span style=\"color:#129b50\">is</span></strong></span></span></span></p>\r\n			</td>\r\n			<td rowspan=\"2\" style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">he<strong><span style=\"color:#129b50\">&#39;s</span></strong></span></span></span></p>\r\n			</td>\r\n			<td rowspan=\"2\" style=\"width:80.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">he is&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:196.9pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">he<strong><span style=\"color:#129b50\">&#39;s</span></strong>&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:196.9pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">he&nbsp;<strong><span style=\"color:#129b50\">is</span><span style=\"color:#cd4b3c\">n&#39;t</span></strong></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td rowspan=\"2\" style=\"width:75.25pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">she&nbsp;<stron