<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:-9.0pt; width:632px\">\r\n	<thead>\r\n		<tr>\r\n			<td style=\"background-color:#f9f6eb; width:127.75pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong>&nbsp;</strong></span></span></p>\r\n			</td>\r\n			<td colspan=\"2\" style=\"background-color:#f9f6eb; width:169.95pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Affirmative</span></span></strong></span></span></p>\r\n			</td>\r\n			<td colspan=\"2\" style=\"background-color:#f9f6eb; width:176.15pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Negative</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f9f6eb; width:127.75pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Pronoun</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:70.15pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Long form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:99.8pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Contracted form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:74.85pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Long form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:101.3pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Contracted form</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:127.75pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">I, he, she, it, we, you, they</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:70.15pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">we&nbsp;<strong><span style=\"color:#129b50\">did</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:99.8pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">---</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:74.85pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">we&nbsp;<strong><span style=\"color:#129b50\">did</span></strong>&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:101.3pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">we&nbsp;<strong><span style=\"color:#129b50\">did</span><span style=\"color:#cd4b3c\">n&#39;t</span></strong></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<h2 style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:13pt\"><span style=\"background-color:white\"><span style=\"color:#2f5496\"><strong><span style=\"font-size:18.0pt\"><span style=\"color:black\">7. Modals&nbsp;<em>(can, could, must, might, will, would, shall, should, ought to)</em></span></span></strong></span></span></span></span></h2>\r\n\r\n<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:-9.0pt; width:636px\">\r\n	<thead>\r\n		<tr>\r\n			<td colspan=\"2\" style=\"background-color:#f9f6eb; width:181.8pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Affirmative</span></span></strong></span></span></p>\r\n			</td>\r\n			<td colspan=\"2\" style=\"background-color:#f9f6eb; width:4.1in\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Negative</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f9f6eb; width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Long form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Contracted form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Long form</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f9f6eb; width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#5f490d\">Contracted form</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">can</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">-</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">Can</span><span style=\"color:#cd4b3c\">not</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">can</span><span style=\"color:#cd4b3c\">&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">could</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">-</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">could</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">could</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">must</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">-</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">must</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">must</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">might</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">-</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">might</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">--</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">need</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">-</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">need</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">need</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">will</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">&#39;ll</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">will</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">wo</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">would</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">&#39;d</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">would</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">would</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">shall</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">-</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">shall</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">sha</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">should</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">&#39;d</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">should</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">should</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:75.2pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">ought</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;to</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:106.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">-</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:81.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">ought</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;<strong><span style=\"color:#cd4b3c\">not</span></strong>&nbsp;to</span></span></span></p>\r\n			</td>\r\n			<td style=\"width:213.6pt\">\r\n			<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">ought</span><span style=\"color:#cd4b3c\">n&#39;t</span></span></strong><span style=\"font-size:12.0pt\">&nbsp;to</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">The short/contracted forms&rsquo;&nbsp;and&rsquo;s&nbsp;have<strong> two different long forms</strong>:</span></span></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">he</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">&#39;s</span></span></strong><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;= he&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">is</span></span></strong>&nbsp;<em><span style=\"font-size:12.0pt\"><span style=\"color:#666666\">or</span></span></em><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;he&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">has</span></span></strong></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">he</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">&#39;d</span></span></strong><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;= he&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">would</span></span></strong>&nbsp;<em><span style=\"font-size:12.0pt\"><span style=\"color:#666666\">or</span></span></em><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;he&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">had</span></span></strong></span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">We seldom use short/contracted forms after names and nouns.</span></span></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">Peter&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">has</span></span></strong>&nbsp;<strong><span style=\"font-size:12.0pt\"><span style=\"color:#6d6fc0\">got</span></span></strong><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;a book. = Peter</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">&#39;s</span></span></strong>&nbsp;<strong><span style=\"font-size:12.0pt\"><span style=\"color:#6d6fc0\">got</span></span></strong><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;a book.</span></span></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">The children&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#129b50\">have</span></span></strong>&nbsp;<strong><span style=\"font-size:12.0pt\"><span style=\"color:#55a5d2\">visit</span></span></strong><strong><span style=\"font-size:12.0pt\"><span style=\"color:#dd961e\">ed</span></span></strong><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;London. = The children&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#55a5d2\">visit</span></span></strong><strong><span style=\"font-size:12.0pt\"><span style=\"color:#dd961e\">ed</span></span></strong><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;London.</span></span></span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">If have is a full verb, we do not use the short form.</span></span></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"color:black\">They&nbsp;</span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#55a5d2\">have</span></span></strong><span style=\"font-size:12.0pt\"><span style=\"color:black\">&nbsp;breakfast at 6 o&#39;clock.</span></span></span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>', NULL, 'Long forms, contracted forms (short forms) of auxiliaries', 'long-forms-contracted-forms-short-forms-of-auxiliaries', 1, 28, '1', '2024-06-02 22:49:22', '2024-06-21 11:26:58');
INSERT INTO `book_items` (`id`, `chapter_id`, `title`, `sub_title`, `type`, `short_details`, `details`, `audio_text`, `keyword`, `slug`, `status`, `pageview`, `added_by`, `created_at`, `updated_at`) VALUES
(105, 12, 'WH word দিয়ে কিভাবে wH questions? বানাবো', NULL, 'audio', 'সাধারণত auxiliary interrogative/ questions   এর পূর্বে W.H. word যোগ করে W.H interrogative / question বাক্য গঠন করা হয় ।', '<p style=\"margin-left:0in; margin-right:0in; text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">1. </span><span style=\"font-size:16.0pt\">interrogative / questions</span> <span style=\"font-size:13.0pt\">বা</span> &nbsp;<span style=\"font-size:13.0pt\">প্রশ্নবোধক</span> <span style=\"font-size:13.0pt\">বাক্য</span> <span style=\"font-size:13.0pt\">দুই</span> <span style=\"font-size:13.0pt\">প্রকার</span> <span style=\"font-size:16.0pt\">auxiliary interrogative </span><span style=\"font-size:13.0pt\">এবং</span> &nbsp;<span style=\"font-size:16.0pt\">&nbsp;WH word interrogative </span><span style=\"font-size:13.0pt\">অর্থাৎ</span> <span style=\"font-size:13.0pt\">যেই</span> <span style=\"font-size:13.0pt\">প্রশ্নের</span> <span style=\"font-size:13.0pt\">প্রথমে</span> <span style=\"font-size:14.0pt\">w.h </span><span style=\"font-size:13.0pt\">ওয়ার্ডের</span> <span style=\"font-size:13.0pt\">নয়টি</span> <span style=\"font-size:13.0pt\">থেকে</span> <span style=\"font-size:13.0pt\">যেকোনো</span> <span style=\"font-size:13.0pt\">একটি</span> <span style=\"font-size:13.0pt\">দিয়ে</span> <span style=\"font-size:13.0pt\">প্রশ্ন</span> <span style=\"font-size:13.0pt\">করা</span> <span style=\"font-size:13.0pt\">হয়</span> <span style=\"font-size:13.0pt\">তাকে</span> <span style=\"font-size:16.0pt\">WH </span><span style=\"font-size:13.0pt\">interrogative </span><span style=\"font-size:13.0pt\">বা</span> <span style=\"font-size:13.0pt\">প্রশ্নবোধক</span> <span style=\"font-size:13.0pt\">বাক্য</span> <span style=\"font-size:13.0pt\">এবং</span> <span style=\"font-size:13.0pt\">যেই</span> <span style=\"font-size:16.0pt\">interrogative </span><span style=\"font-size:13.0pt\">এর</span> <span style=\"font-size:13.0pt\">পূর্বে</span> <span style=\"font-size:16.0pt\">auxiliary verb </span><span style=\"font-size:13.0pt\">দিয়ে</span> <span style=\"font-size:13.0pt\">প্রশ্নবোধক</span> <span style=\"font-size:13.0pt\">বাক্য</span> <span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">করা</span> <span style=\"font-size:13.0pt\">হয়</span> <span style=\"font-size:13.0pt\">তাকে</span> <span style=\"font-size:16.0pt\">auxiliary interrogative </span><span style=\"font-size:14.0pt\">বলে|</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">যেমন</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Auxiliary questions - Do you smile? </span><span style=\"font-size:13.0pt\">তুমি</span> <span style=\"font-size:13.0pt\">কি</span> <span style=\"font-size:13.0pt\">হাসো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">WH questions- why do you smile?</span><span style=\"font-size:13.0pt\"> তুমি</span> <span style=\"font-size:13.0pt\">কী হাসো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">2 নিম্নে 9</span><span style=\"font-size:13.0pt\">টি</span><span style=\"font-size:13.0pt\"> WH word </span><span style=\"font-size:13.0pt\">এবং</span> <span style=\"font-size:13.0pt\">তাদের</span> <span style=\"font-size:13.0pt\">একাধিক</span> <span style=\"font-size:13.0pt\">অর্থ</span> <span style=\"font-size:13.0pt\">দেওয়া</span> <span style=\"font-size:13.0pt\">হলো</span> <span style=\"font-size:13.0pt\">তবে</span> <span style=\"font-size:13.0pt\">মনে</span> <span style=\"font-size:13.0pt\">রাখতে</span> <span style=\"font-size:13.0pt\">হবে</span><span style=\"font-size:13.0pt\"> WH word </span><span style=\"font-size:13.0pt\">বাক্যের</span> <span style=\"font-size:13.0pt\">প্রথমে</span> <span style=\"font-size:13.0pt\">বসে</span> <span style=\"font-size:13.0pt\">তাহলে</span> <span style=\"font-size:13.0pt\">বাংলা</span> <span style=\"font-size:13.0pt\">অর্থ</span> <span style=\"font-size:13.0pt\">প্রথমটি</span> <span style=\"font-size:13.0pt\">ব্যবহার</span> <span style=\"font-size:13.0pt\">হবে</span> <span style=\"font-size:13.0pt\">আর</span> <span style=\"font-size:13.0pt\">যদি</span><span style=\"font-size:13.0pt\"> WH word </span><span style=\"font-size:13.0pt\">টি</span> <span style=\"font-size:13.0pt\">বাক্যের</span> <span style=\"font-size:13.0pt\">ভিতরে</span> <span style=\"font-size:13.0pt\">বসে</span> <span style=\"font-size:13.0pt\">তাহলে</span> <span style=\"font-size:13.0pt\">বাংলা</span> <span style=\"font-size:13.0pt\">অর্থ</span> <span style=\"font-size:13.0pt\">দ্বিতীয়</span> <span style=\"font-size:13.0pt\">বা</span> <span style=\"font-size:13.0pt\">তৃতীয়</span> <span style=\"font-size:13.0pt\">নম্বরটি</span> <span style=\"font-size:13.0pt\">ব্যবহৃত</span> <span style=\"font-size:13.0pt\">হবে.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\"><span style=\"color:#44546a\">নিম্নে</span></span> <span style=\"font-size:12.0pt\"><span style=\"color:#44546a\">৯টি</span></span><span style=\"font-size:14.0pt\"><span style=\"color:#44546a\"> Wh words </span></span><span style=\"font-size:14.0pt\"><span style=\"color:#44546a\">এবং</span></span> <span style=\"font-size:14.0pt\"><span style=\"color:#44546a\">অর্থ</span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">What কি</span><span style=\"font-size:14.0pt\">,যা</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Who কে</span><span style=\"font-size:14.0pt\"> , যে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Where কোথায়</span><span style=\"font-size:14.0pt\">, যেথায়</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">When কখন</span><span style=\"font-size:14.0pt\">, </span><span style=\"font-size:14.0pt\">যখন,</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">How কেমন</span><span style=\"font-size:14.0pt\"> , </span><span style=\"font-size:14.0pt\">কত</span><span style=\"font-size:14.0pt\"> , </span><span style=\"font-size:14.0pt\">কিভাবে,</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Why কেনো</span><span style=\"font-size:14.0pt\">, যেনো</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Whom কাকে</span><span style=\"font-size:14.0pt\"> , </span><span style=\"font-size:14.0pt\">কাদেরকে,</span> <span style=\"font-size:14.0pt\">যাকে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Which কোনটি</span><span style=\"font-size:14.0pt\">,</span><span style=\"font-size:14.0pt\">যেটি </span><span style=\"font-size:14.0pt\">&nbsp;(Which pen </span><span style=\"font-size:14.0pt\">কোন</span> <span style=\"font-size:14.0pt\">কলমটি)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Whose কারটি</span><span style=\"font-size:14.0pt\"> ,</span><span style=\"font-size:14.0pt\">যারটি&nbsp; </span><span style=\"font-size:14.0pt\">(Whose pen </span><span style=\"font-size:14.0pt\">কার</span> <span style=\"font-size:14.0pt\">কলমটি)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">3. auxiliary interrogatives </span><span style=\"font-size:12.0pt\">এর</span> <span style=\"font-size:12.0pt\">ক্ষেত্রে</span> <span style=\"font-size:12.0pt\">বাক্যের</span> <span style=\"font-size:12.0pt\">প্রথমে</span> <span style=\"font-size:12.0pt\">নিম্নের</span><span style=\"font-size:14.0pt\"> verbs </span><span style=\"font-size:12.0pt\">গুলো</span> <span style=\"font-size:12.0pt\">ব্যবহৃত</span> <span style=\"font-size:12.0pt\">হবে</span> </span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">(do/does-am/is/are-have/has/have been/has been- was/were-had-had been-will-will be- will have -will have been)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">তবে</span> <span style=\"font-size:13.0pt\">একটি</span> <span style=\"font-size:13.0pt\">বিষয়</span> <span style=\"font-size:13.0pt\">খেয়াল</span> <span style=\"font-size:13.0pt\">রাখতে</span> <span style=\"font-size:13.0pt\">হবে</span><span style=\"font-size:14.0pt\"> tense </span><span style=\"font-size:13.0pt\">এর</span> <span style=\"font-size:13.0pt\">সাথে</span> <span style=\"font-size:13.0pt\">যখন</span> <span style=\"font-size:13.0pt\">কোন</span><span style=\"font-size:14.0pt\"> auxiliary </span><span style=\"font-size:13.0pt\">বা</span> <span style=\"font-size:13.0pt\">সাহায্যকারী</span> <span style=\"font-size:14.0pt\">verb</span> <span style=\"font-size:13.0pt\">বসে</span> <span style=\"font-size:13.0pt\">তখন</span> <span style=\"font-size:14.0pt\">auxiliary verb </span><span style=\"font-size:13.0pt\">এর</span> <span style=\"font-size:13.0pt\">নিজস্ব</span> <span style=\"font-size:13.0pt\">কোন</span> <span style=\"font-size:13.0pt\">অর্থ</span> <span style=\"font-size:13.0pt\">থাকে</span> <span style=\"font-size:13.0pt\">না</span> <span style=\"font-size:13.0pt\">।কিন্তু</span> <span style=\"font-size:13.0pt\">যদি</span> <span style=\"font-size:13.0pt\">কোন</span> <span style=\"font-size:13.0pt\">বাক্যে</span> <span style=\"font-size:14.0pt\">auxiliary verb </span><span style=\"font-size:13.0pt\">ছাড়া</span> <span style=\"font-size:13.0pt\">অন্য</span> <span style=\"font-size:13.0pt\">কোন</span> <span style=\"font-size:13.0pt\">মূলভাব</span> <span style=\"font-size:13.0pt\">না</span> <span style=\"font-size:13.0pt\">থাকে</span> <span style=\"font-size:13.0pt\">তাহলে</span> <span style=\"font-size:13.0pt\">প্রত্যেকটি</span> <span style=\"font-size:14.0pt\">auxiliary verb </span><span style=\"font-size:13.0pt\">এর</span> <span style=\"font-size:13.0pt\">নিজস্ব</span> <span style=\"font-size:13.0pt\">একটি</span> <span style=\"font-size:13.0pt\">অর্থ</span> <span style=\"font-size:13.0pt\">রয়েছে</span> <span style=\"font-size:13.0pt\">তবে</span> <span style=\"font-size:13.0pt\">এ</span> <span style=\"font-size:13.0pt\">বিষয়টি</span> <span style=\"font-size:13.0pt\">পরবর্তী</span> <span style=\"font-size:13.0pt\">অধ্যায়</span> <span style=\"font-size:13.0pt\">বিস্তারিত</span> <span style=\"font-size:13.0pt\">আলোচনা</span> <span style=\"font-size:13.0pt\">করা</span> <span style=\"font-size:13.0pt\">হবে।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Formula-1</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">সাধারণত </span><span style=\"font-size:16.0pt\">auxiliary interrogative/ questions&nbsp;&nbsp; </span><span style=\"font-size:14.0pt\">এর পূর্বে W.H. word যোগ করে </span><span style=\"font-size:16.0pt\">W.H interrogative / question </span><span style=\"font-size:14.0pt\">বাক্য গঠন করা হয় ।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What does he do/what is he doing / when will he come / why did you go there? /How have you done it? /Whom has he given it / where do they live?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in; text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">সে কি করে</span><span style=\"font-size:14.0pt\">? /সে কি </span><span style=\"font-size:14.0pt\">করতেছে</span><span style=\"font-size:14.0pt\">? /সে কখন </span><span style=\"font-size:14.0pt\">আসবে</span><span style=\"font-size:14.0pt\">? /তুমি সেখানে কেন </span><span style=\"font-size:14.0pt\">গিয়েছিলে</span><span style=\"font-size:14.0pt\">? /তুমি কিভাবে এটা </span><span style=\"font-size:14.0pt\">করেছো? /সে কাকে এটা দিয়েছে?তারা কোথায় থাকে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">আরো কিছু নিয়মে </span><span style=\"font-size:16.0pt\">W.H question </span><span style=\"font-size:14.0pt\">করা&nbsp; যায়</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Formula-2</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Who/what + principal verb+...ext.?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">[Who /what subject </span><span style=\"font-size:14.0pt\">হিসাবে ব্যবহার হলে তাদের পর সরাসরি </span><span style=\"font-size:16.0pt\">principal verb </span><span style=\"font-size:14.0pt\">বসানো যায়,</span><span style=\"font-size:16.0pt\">auxiliary verb (am,is,are,was,were etc.) </span><span style=\"font-size:14.0pt\">এর দরকার হয় না]</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Who went (principal verb) there?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">সেখানে কে গিয়েছিলো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Who knows?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কে জানে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What works better?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কোনটা ভালো কাজ করে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Formula-3</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Which/whose + Noun/noun phrase + auxiliary verb+ sub+ ext&hellip;.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">উদাহরণ-</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Which +pen (noun/noun phrase) +do (auxiliary verb) +you(sub) +want (principal verb)?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তুমি কোন কলমটি চাও?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Which one is better?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কোনটি ভালো হয়?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Whose name have you forgotten?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তুমি কার নাম ভুলে গিয়েছো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Whose pen is this?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">এটি কার কলম?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Formula-4</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">WH- word </span><span style=\"font-size:14.0pt\">সমন্বিত </span><span style=\"font-size:16.0pt\">question এ preposition </span><span style=\"font-size:14.0pt\">থাকলে তা আলাদাভাবেও ব্যবহার করা যায়</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">উদাহরণ</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">1.I live with my brother</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">আমি আমার ভাইয়ের সাথে থাকি</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Q1. whom do you live with? (</span><span style=\"font-size:14.0pt\">এটা </span><span style=\"font-size:16.0pt\">formal &amp; standard?or</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">With whom do you live?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তুমি কার সাথে থাকো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">2.He killed it with a knife</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">সে ছুরি দিয়ে এটাকে হত্যা করেছিলো</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Q-2 What did he kill it with?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">সে কি দিয়ে এটাকে হত্যা করেছিল?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">3.I have come here for some information</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">আমি এখানে কিছু তথ্যের জন্য এসেছি</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Q-3. what have you come here for?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তুমি এখানে কিসের জন্য এসেছো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Formula-5</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">How+many(গণনা করা যায় এমন কিছুর ক্ষেত্রে)/much(অগণনাযোগ্য বস্তুর ক্ষেত্রে</span><span style=\"font-size:16.0pt\">)/often/long/far/Adjective noun/ noun phrase auxiliary verb +sub+ extn,,,,,</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\">উদাহরণ-</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How many mangoes did he buy?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কতগুলো আম সে কিনেছিল?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How long will it take for us to finish?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">এটা শেষ করতে আমাদের কতক্ষণ লাগবে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How much water is there in the bucket?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কতটুকু পানি হয় বালতিতে আছে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How long ago did it happen?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কতক্ষণ আগে এটি ঘটেছে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How far have they walked?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কতদূর তারা হেটেছে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How big is the bag?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">ব্যাগটা হয় কত বড়?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How large was the river?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">নদীটা কত বড় হয়েছিল?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How often do you go there?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কতবার তুমি সেখানে যাও?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Formula-6</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What if= what will happen if</span><span style=\"font-size:14.0pt\">. (কি হবে যদি)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">what if+ sub +verb+ extn&hellip;.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">উদাহরণ</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What if it rains?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">যদি বৃষ্টি হয়</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What if he doesn&#39;t come?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কি হবে যদি সে না আসে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What if he dies?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কি হবে যদি সে মারা যায়?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Formula-7</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কোন </span><span style=\"font-size:16.0pt\">invitation</span><span style=\"font-size:14.0pt\"> বা </span><span style=\"font-size:16.0pt\">suggestion </span><span style=\"font-size:14.0pt\">বুঝাতে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How/ what about +verb+ing extn&hellip; </span><span style=\"font-size:14.0pt\">(এটা/ওটা করলে কেমন হয়)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">উদাহরণ</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How about taking a walk?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">একটু হাটলে কেমন হয়?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What about drinking some tea?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">চা খেলে কেমন হয়?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How about enjoying the party?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">পার্টিটা উপভোগ করলে কেমন হয়?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\">উদাহরণ-</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp; What do you do?</span>&nbsp; <span style=\"font-size:14.0pt\">তুমি</span> <span style=\"font-size:14.0pt\">কী</span> <span style=\"font-size:14.0pt\">কর?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Where do you do this work </span><span style=\"font-size:14.0pt\">কোথায়</span> <span style=\"font-size:14.0pt\">তুমি</span>&nbsp;&nbsp; <span style=\"font-size:14.0pt\">এই</span> <span style=\"font-size:14.0pt\">কাজটি</span> <span style=\"font-size:14.0pt\">করো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How do you do this work? </span><span style=\"font-size:14.0pt\">কীভাবে</span> <span style=\"font-size:14.0pt\">এই</span> <span style=\"font-size:14.0pt\">কাজটি</span>&nbsp;&nbsp; <span style=\"font-size:14.0pt\">করো?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\">&nbsp;<span style=\"font-size:14.0pt\">কোন</span> <span style=\"font-size:14.0pt\">ধরনের</span><span style=\"font-size:14.0pt\">/ </span><span style=\"font-size:14.0pt\">কোন</span> <span style=\"font-size:14.0pt\">প্রকারের</span><span style=\"font-size:14.0pt\">/ </span><span style=\"font-size:14.0pt\">কী</span> <span style=\"font-size:14.0pt\">রকম</span><span style=\"font-size:14.0pt\"> -</span><span style=\"font-size:14.0pt\">বুঝালে</span> <span style=\"font-size:14.0pt\">এমন</span> <span style=\"font-size:14.0pt\">হবে ,</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What kind of/what kinds of </span><span style=\"font-size:14.0pt\">(</span><span style=\"font-size:14.0pt\">বহু</span> <span style=\"font-size:14.0pt\">বচনের</span> <span style=\"font-size:14.0pt\">সময়)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What kind of animal&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><span style=\"font-size:14.0pt\">কী</span> <span style=\"font-size:14.0pt\">ধরনের</span> <span style=\"font-size:14.0pt\">প্রাণী</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What kinds of animals&nbsp;&nbsp; </span><span style=\"font-size:14.0pt\">কোন</span> <span style=\"font-size:14.0pt\">ধরনের</span> <span style=\"font-size:14.0pt\">প্রণী গুলো</span> <span style=\"font-size:14.0pt\">কী</span> <span style=\"font-size:14.0pt\">রকম</span> <span style=\"font-size:14.0pt\">বুঝতে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What kind of food item&nbsp;&nbsp;</span><span style=\"font-size:14.0pt\">কি</span> <span style=\"font-size:14.0pt\">রকমের</span> <span style=\"font-size:14.0pt\">খাবার</span> <span style=\"font-size:14.0pt\">আইটেম</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What kinds of food items&nbsp;&nbsp;</span><span style=\"font-size:14.0pt\">কোন</span> <span style=\"font-size:14.0pt\">ধরনের</span> <span style=\"font-size:14.0pt\">খাবার</span> <span style=\"font-size:14.0pt\">আইটেম গুলো</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What kind of food do you like? </span><span style=\"font-size:14.0pt\">কি</span> <span style=\"font-size:14.0pt\">ধরনের</span> <span style=\"font-size:14.0pt\">খাবার</span> <span style=\"font-size:14.0pt\">তুমি</span> <span style=\"font-size:14.0pt\">পছন্দ</span> <span style=\"font-size:14.0pt\">কর?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">What types of food items do you want?&nbsp;&nbsp; কো</span> <span style=\"font-size:14.0pt\">প্রকার</span> <span style=\"font-size:14.0pt\">খাবার</span> <span style=\"font-size:14.0pt\">গুলো</span> <span style=\"font-size:14.0pt\">তুমি</span> <span style=\"font-size:14.0pt\">চাও?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">What ব্যবহার</span> <span style=\"font-size:14.0pt\">করে</span> <span style=\"font-size:14.0pt\">প্রশ্ন</span> <span style=\"font-size:14.0pt\">করার</span> <span style=\"font-size:14.0pt\">কিছু</span> <span style=\"font-size:14.0pt\">ধরন</span> <span style=\"font-size:14.0pt\">।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">What your relationship</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">আপনার</span> <span style=\"font-size:14.0pt\">সম্পর্ক</span> <span style=\"font-size:14.0pt\">কি?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">What your relationship is with this person</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">এই</span> <span style=\"font-size:14.0pt\">ব্যক্তির</span> <span style=\"font-size:14.0pt\">সাথে</span> <span style=\"font-size:14.0pt\">আপনার</span> <span style=\"font-size:14.0pt\">সম্পর্ক</span> <span style=\"font-size:14.0pt\">কি?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">What people think</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">মানুষ</span> <span style=\"font-size:14.0pt\">কি</span> <span style=\"font-size:14.0pt\">মনে</span> <span style=\"font-size:14.0pt\">করেন?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">What do people think about this person?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">মানুষ</span> <span style=\"font-size:14.0pt\">এই</span> <span style=\"font-size:14.0pt\">ব্যক্তি</span> <span style=\"font-size:14.0pt\">সম্পর্কে</span> <span style=\"font-size:14.0pt\">কি</span> <span style=\"font-size:14.0pt\">মনে</span> <span style=\"font-size:14.0pt\">করে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What job </span><span style=\"font-size:14.0pt\">কী</span> <span style=\"font-size:14.0pt\">চাকরি?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What job do you like </span><span style=\"font-size:14.0pt\">আপনি</span> <span style=\"font-size:14.0pt\">কি</span> <span style=\"font-size:14.0pt\">কাজ</span> <span style=\"font-size:14.0pt\">পছন্দ</span> <span style=\"font-size:14.0pt\">করেন</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">(বাক্যের</span> <span style=\"font-size:14.0pt\">প্রথমে</span> <span style=\"font-size:14.0pt\">প্রশ্ন</span><span style=\"font-size:14.0pt\">? </span><span style=\"font-size:14.0pt\">হিসেবে</span> <span style=\"font-size:14.0pt\">ব্যবহার</span> <span style=\"font-size:14.0pt\">করা</span> <span style=\"font-size:14.0pt\">হয়)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">What job you like </span><span style=\"font-size:14.0pt\">আপনি</span> <span style=\"font-size:14.0pt\">কি</span> <span style=\"font-size:14.0pt\">কাজ</span> <span style=\"font-size:14.0pt\">পছন্দ</span> <span style=\"font-size:14.0pt\">করেন</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How often </span><span style=\"font-size:14.0pt\">কত</span> <span style=\"font-size:14.0pt\">বার?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How often do you see them?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কতবার</span> <span style=\"font-size:14.0pt\">আপনি</span> <span style=\"font-size:14.0pt\">দেখেন</span> <span style=\"font-size:14.0pt\">তাদের</span> <span style=\"font-size:14.0pt\">কে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">(বাক্যের</span> <span style=\"font-size:14.0pt\">প্রথমে</span> <span style=\"font-size:14.0pt\">প্রশ্ন</span><span style=\"font-size:14.0pt\">? </span><span style=\"font-size:14.0pt\">হিসেবে</span> <span style=\"font-size:14.0pt\">ব্যবহার</span> <span style=\"font-size:14.0pt\">করা</span> <span style=\"font-size:14.0pt\">হয়)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">How often you see them</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কতবার</span> <span style=\"font-size:14.0pt\">আপনি</span> <span style=\"font-size:14.0pt\">দেখেন</span> <span style=\"font-size:14.0pt\">তাদের</span> <span style=\"font-size:14.0pt\">কে?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Why do you like them?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কেন</span> <span style=\"font-size:14.0pt\">আপনি</span> <span style=\"font-size:14.0pt\">তাদের</span> <span style=\"font-size:14.0pt\">পছন্দ</span> <span style=\"font-size:14.0pt\">করেন</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">(বাক্যের</span> <span style=\"font-size:14.0pt\">প্রথমে</span> <span style=\"font-size:14.0pt\">প্রশ্ন</span><span style=\"font-size:14.0pt\">? </span><span style=\"font-size:14.0pt\">হিসেবে</span> <span style=\"font-size:14.0pt\">ব্যবহার</span> <span style=\"font-size:14.0pt\">করা</span> <span style=\"font-size:14.0pt\">হয়)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;Why you like them</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">কেন</span> <span style=\"font-size:14.0pt\">আপনি</span> <span style=\"font-size:14.0pt\">তাদের</span> <span style=\"font-size:14.0pt\">পছন্দ</span> <span style=\"font-size:14.0pt\">করেন</span></span></span></p>', NULL, 'WH word ,WH questions.', 'wh-word-dize-kivabe-wh-questions-banabo', 1, 28, '1', '2024-06-03 21:00:08', '2024-06-21 20:22:58');
INSERT INTO `book_items` (`id`, `chapter_id`, `title`, `sub_title`, `type`, `short_details`, `details`, `audio_text`, `keyword`, `slug`, `status`, `pageview`, `added_by`, `created_at`, `updated_at`) VALUES
(107, 13, 'Transformation of Degree এবং degree change exercise মোট ৩ প্রকার degrees রয়েছে', NULL, 'audio', 'adjectives এবং adverbs এর ক্ষেত্রে মোট ৩ প্রকার degrees রয়েছে, degree change exercise, Strong	  Stronger	 Strongest.No other + প্রদত্ত Superlative এর পরের অংশ + verb + so/as + Superlative Degree এর Positive form +as+ মূল sentence এর subject', '<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Adjective শব্দ বা Adverb শব্দের মাঝে তুলনা করাকে Degree change বা Comparison of Degree বলা হয়ে থাকে ইংরেজি ব্যাকারনে। এটি Transformation of Sentences এর উপরে একটি গুরুত্বপূর্ণ অধ্যায়। এখানে আমাদেরকে একটি বাক্যকে Positive থেকে Comparative বা Superlative এ পরিবর্তন করতে হয় adjective বা adverb শব্দের পরিবর্তনের নিয়ম অনুসরন করে। আমি Changing Degree এর উপরে ৫ টি নিয়ম আলোচনা করতে যাচ্ছি এই অধ্যায়ে।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\"><strong>adjectives</strong><strong> </strong><strong>এবং</strong><strong> </strong><strong>adverbs </strong><strong>এর</strong><strong> </strong><strong>ক্ষেত্রে</strong><strong> </strong><strong>মোট</strong><strong> </strong><strong>৩</strong><strong> </strong><strong>প্রকার</strong><strong> </strong><strong>degrees</strong><strong> </strong><strong>রয়েছেঃ</strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive Degree&ndash; (no comparison -কোন তুলনা হবেনা)</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative Degree&ndash; (comparison between two persons or objects-দুইজনের বা দুটি বিষয়ের মধ্যে তুলনা হবে)</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative Degree&ndash; (comparison among several persons or objects-অনেক ব্যক্তি বা বস্তুর মধ্যে তুলনা হবে)</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive Degree&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Comparative Degree&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Superlative Degree</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Strong&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Stronger&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Strongest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Great&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Greater&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Greatest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Old&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Older/elder&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Oldest/eldest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Small&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Smaller&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Smallest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Few&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;Fewer&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Fewest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Weak&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Weaker&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Weakest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Hot&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Hotter&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;Hottest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Big&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Bigger&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Biggest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Large&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Larger&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Largest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Wise&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Wiser &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Wisest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Easy&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Easier&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Easiest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Beautiful&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; More beautiful&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Most beautiful</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Intelligent&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;More Intelligent&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Most</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Good/well&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Better&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Best</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Bad/badly/&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; evil/ill&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Worse/Worst</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Many/much&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;More&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Most</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Fore&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Former&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Foremost/first</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Little&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Less&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Least</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Late&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Later/latter&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Latest/last</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Far&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Farther&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Farthest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Fore&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Further&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Furthest</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Out&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Outer/utter&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Outmost/outermost</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Up&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Upper &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Uppermost</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">কিছু বিষয় যা তোমাকে মনে রাখতে হবেঃ</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Degrees পরিবর্তনের সময় কিছু নির্দিষ্ট বিষয় তোমাকে মনে রাখতে হবে।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">&nbsp;নিম্নে সেগুলো দেওয়া হলঃ</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 01:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">(Positive Degree এর চিহ্ন হল &ldquo;as&hellip;.as/so&hellip;.as&rdquo;)</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 02:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">(Comparative Degree এর চিহ্ন হল &ldquo;than&rdquo;)</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 03:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">(Superlative Degree এর চিহ্ন হল &ldquo;the&rdquo;)</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 04:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">(Adjective বা Adverb যে শব্দটি দেওয়া আছে তা Degree এর বিভিন্ন রূপ যেমনঃ (Positive- Strong)/ (Comparative- Stronger) / (Superlative-Strongest) অনুযায়ী পরিবর্তন করতে হবে।</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 05:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">(Degree পরিবর্তনের সময় মূল বাক্যের অর্থের কোন পরিবর্তন হওয়া যাবেনা)</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 06:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">(Degree পরিবর্তনের সময় মূল বাক্যের subject এবং object এর স্থান পরিবর্তন করতে হবে। অর্থাৎ, Positive Degree তে object টিকে Comparative Degree / Superlative Degree তে subject হিসেবে বসাতে হবে)</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative Degree কে Positive Degree তে রুপান্তর করার নিয়ম:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 1:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No other + প্রদত্ত Superlative এর পরের অংশ + verb + so/as + Superlative Degree এর Positive form +as+ মূল sentence এর subject.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Rony is the smallest player in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other player in the team is as small as Rony.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Sima is the best housewife.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other housewife is as good as Sima.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 2:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">all other, most other, many other, few other, very few, one of the Superlative Degree (Positive Degree তে রুপান্তর করার নিয়মঃ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">প্রথমে very few + Superlative এর পরের অংশ +verb এর plural form + so/as + Superlative Degree এর Positive form + as + মূল sentence এর subject.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: He is one of the best players in the team. mam</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: Very few players in the team are as good as he.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Iron is one of the most useful metals.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: Very few metals are as useful as Iron.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative into positive</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 1:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Then any other/all other যুক্ত Comparative Degree কে Positive Degree তে রুপান্তরের নিয়মঃ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No other + any other/all other এর পরের অংশ + verb + so/as + Comparative Degree এর Positive form + as + প্রদত্ত sentence এর subject.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: kibria is greater than any other boy in the class.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other boy in the class is as great as Kibria.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Dhaka is larger than all other cities in Bangladesh.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other cities in Bangladesh are as large as Dhaka.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 2:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Then যুক্ত Comparative Degree কে Positive Degree তে রুপান্তর করার নিয়মঃ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Then এর পরের অংশ + verb + not + so/as + Comparative এর Positive form +as+ প্রদত্ত sentence এর subject</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Rony is bigger than Bony. Positive: Bony is not as big as Rony. Comparative: He is stronger than I.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: I am not as strong as he.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 3:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Then most other/ than few other যুক্ত Comparative Degree কে Positive Degree করার নিয়মঃ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Very few + most other/few other + verb এর plural form + so/as + Comparative এর Positive form +as+ প্রদত্ত sentence এর subject.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: The gold is most useful than most other metals.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: very few metals are as/so useful as gold.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: A. K. Fazlul Haque was greater than most other politicians in Bangladesh.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: very few politicians in Bangladesh were as/so great as A. K. Fazlul Haque.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 4:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No less/not less.........than যুক্ত Comparative Degree কে Positive Degree করার নিয়মঃ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No less/not less এর পরিবর্তে উক্ত যায়গায় as বসে এবং than এর পরিবর্তে উক্ত যায়গায় as বসে। আর কোন পরিবর্তন হয় না।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: He is no less intelligent than you.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: He is as intelligent as you.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Kripa is not less clever than shipa.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: Kripa is as clever as shipa.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 5:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No sooner had.... than যুক্ত Comparative Degree কে Positive Degree করার নিয়মঃ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No sooner had এর পরিবর্তে as soon as + subject + verb এর past form(v2) +than এর পূর্বের অংশ +than এর পরিবর্তে কমা বসে + বাকী অংশ।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: No sooner had he seen me than he ran away.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: As soon as he saw me, he ran away.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative into comparative</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 1:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Subject + verb + Superlative এর comparative form + than any other +প্রদত্ত sentence এর বাকী অংশ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: He is the best player in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: He is better than any other player in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Note: All of /of all থাকলে All of এর পরিবর্তে than all other বসে।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: He is the best of all men.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: He is better than all other man.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 2:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">One of the যুক্ত Superlative Degree কে Comparative Degree তে রুপান্তর করার নিয়ম:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Subject + verb + Superlative এর comparative form + than most other + প্রদত্ত sentence এর বাকী অংশ।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Kibria is one of the best players in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Kibria is better than most other players in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Canada is one of the coldest countries in the world.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Canada is colder than most other countries in the world.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive into comparative</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 1:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No other যুক্ত positive Degree কে Comparative Degree করা</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">প্রদত্ত sentence এর subject + verb + positive degree এর comparative form + than any other + no other এর পর থেকে verb এর পূর্ব পর্যন্ত।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other player in the team is as good as him.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: He is better than any other player in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other country in the world is so/as cold as Canada.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Canada is colder than any other country in the world.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 2:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Very few যুক্ত positive Degree কে Comparative Degree করা</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">প্রদত্ত sentence এর subject + verb + positive degree এর comparative form + than most other + no other এর পর থেকে verb এর পূর্ব পর্যন্ত।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: Very few students are so good as Lablu.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Lablu is better than most other students.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 3:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">As.....as যুক্ত positive Degree কে Comparative Degree তে রুপান্তর করার নিয়ম:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">প্রদত্ত sentence এর শেষের subject + verb + not + positive degree এর comparative form +than+ প্রদত্ত sentence এর প্রথম subject</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Positive: He is as good as his brother</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: His brother is not better than him.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative into superlative</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 1:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Subject + verb + the + Comparative এর superlative form + other এর পরের অংশ।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: He is better than any other player in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: He is the best player in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Note- other এর পর plural noun থাকলে superlative এর পরে of all বসে।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: He is bigger than of all boys.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: He is the tallest of all boys.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 2:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Then most other/than few other যুক্ত Comparative কে Superlative করা</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Subject + verb + one of the + Comparative degree এর superlative form + most other/few other এর পরের অংশ।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Vatican City is smaller than most other countries in the world.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Vatican City is one of the smallest countries in the world.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Comparative: Dhaka is bigger than most other cities in Bangladesh.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Dhaka is one of the biggest cities in Bangladesh.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive into superlative:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 1:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">No other যুক্ত positive degree কে superlative degree করা</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">প্রদত্ত sentence এর শেষের Subject + verb + the + positive এর superlative form + no other এর পর থেকে verb এর আগের অংশ।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other player in the team is as good as Raju.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Raju is the best player in the team.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: No other man man in the society is as good as him.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: He is the best man in the society.</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Rule 2:</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Very few যুক্ত positive degree কে superlative degree তে রুপান্তর করার নিয়মঃ</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">প্রদত্ত sentence এর শেষের Subject + verb + one of the + positive এর superlative form + very few এর পর থেকে verb এর আগের অংশ।</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: Very few men in the village are as tall as Kabir.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">&nbsp;Superlative: Kabir is one of the tallest men in the village.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Positive: Very few people in the country are as good as Rakib.</span></span></p>\r\n\r\n<p><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\">Superlative: Rakib is one of the best people in the country.</span></span></p>', NULL, 'degree change exercise, Transformation of Degree', 'transformation-of-degree-ebng-degree-change-exercise-mot-3-prkar-degrees-ryeche-1-MQ9Zpils3C', 1, 19, '1', '2024-06-05 03:15:28', '2024-06-21 18:36:57'),
(108, 14, 'Passive voice: active to passive voice converter', NULL, 'normal', 'Indefinite tense:  a) Present indefinite – am, is, are. b) Past indefinite – was, were. c) Future indefinite – shall be, will be.', '<h3 style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">Rule 1:</span></span></span></span></span></h3>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">a)&nbsp;Active voice এর subject </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">টি</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> passive voice </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">এর</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> object </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">হয়ে</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">যায়।</span></span><br />\r\n<span style=\"font-size:13.5pt\"><span style=\"background-color:null\">b)&nbsp;Active voice </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">এর</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> object </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">টি</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> passive voice </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">এর</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> subject </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">এ</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">রুপান্তর</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">হয়।</span></span><br />\r\n<span style=\"font-size:13.5pt\"><span style=\"background-color:null\">c)&nbsp;</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">মূল</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> verb </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">এর</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> past participle </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">হয়</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">এবং</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> subject </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">ও</span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\"> tense </span></span><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">অনুসারে auxiliary verb/be verb হয়।</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">Rule 2:</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">Indefinite tense:</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">a)&nbsp;Present indefinite &ndash; am, is, are.</span><br />\r\n<span style=\"background-color:null\">b)&nbsp;Past indefinite &ndash; was, were.</span><br />\r\n<span style=\"background-color:null\">c)&nbsp;Future indefinite &ndash; shall be, will be.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">Continuous tense:</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">a)&nbsp;Present Continuous- am being, is being, are being.</span><br />\r\n<span style=\"background-color:null\">b)&nbsp;Past Continuous &ndash; was being, were being</span><br />\r\n<span style=\"background-color:null\">c)&nbsp;Future Continuous - shall be being, will be being.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">Perfect tense:</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"color:null\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\"><span style=\"background-color:null\">a)&nbsp;Present Perfect &ndash; has been, have been.</span><br />\r\n<span style=\"background-color:null\">b)&nbsp;Past Perfect- had been.</span><br />\r\n<span style=\"background-color:null\">c)&nbsp;Future Perfect- shall have been, will have been.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>', NULL, 'active to passive voice converter', 'passive-voice-active-to-passive-voice-converter', 1, 10, '1', '2024-06-12 01:10:14', '2024-06-22 05:13:59');
INSERT INTO `book_items` (`id`, `chapter_id`, `title`, `sub_title`, `type`, `short_details`, `details`, `audio_text`, `keyword`, `slug`, `status`, `pageview`, `added_by`, `created_at`, `updated_at`) VALUES
(109, 14, 'Passive voice: কাকে বলে?  who will help your passive voice', NULL, 'normal', 'Voice এর সংজ্ঞা : Voice অর্থ বাচ্য , ক্রিয়া প্রকাশের ভঙ্গিমাকেই Voice বা বাচ্য বলে । নিচের বাক্য দুটি পড়  I eat a mango (আমি একটি আম খাই) । A mango is eaten by me (আমার দ্বারা একটা  আম খাওয়া হয়)।', '<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:13.5pt\"><span style=\"color:green\">Voice এর</span></span></strong><strong> </strong><strong><span style=\"font-size:13.5pt\"><span style=\"color:green\">সংজ্ঞা</span></span></strong><strong><span style=\"font-size:13.5pt\"><span style=\"color:green\"> :</span></span></strong>&nbsp;<strong><span style=\"font-size:13.5pt\">Voice</span></strong>&nbsp;<span style=\"font-size:13.5pt\">অর্থ</span> <span style=\"font-size:13.5pt\">বাচ্য</span><span style=\"font-size:13.5pt\"> , </span><span style=\"font-size:13.5pt\">ক্রিয়া</span> <span style=\"font-size:13.5pt\">প্রকাশের</span> <span style=\"font-size:13.5pt\">ভঙ্গিমাকেই</span><span style=\"font-size:13.5pt\">&nbsp;<strong>Voice</strong>&nbsp;</span><span style=\"font-size:13.5pt\">বা</span> <span style=\"font-size:13.5pt\">বাচ্য</span> <span style=\"font-size:13.5pt\">বলে</span> <span style=\"font-size:13.5pt\">।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">নিচের</span> <span style=\"font-size:13.5pt\">বাক্য</span> <span style=\"font-size:13.5pt\">দুটি</span> <span style=\"font-size:13.5pt\">পড়</span>&nbsp;</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">I eat a mango (আমি</span> <span style=\"font-size:13.5pt\">একটি</span> <span style=\"font-size:13.5pt\">আম</span> <span style=\"font-size:13.5pt\">খাই</span><span style=\"font-size:13.5pt\">) ।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">A mango is eaten by me (আমার</span> <span style=\"font-size:13.5pt\">দ্বারা</span> <span style=\"font-size:13.5pt\">একটা</span>&nbsp; <span style=\"font-size:13.5pt\">আম</span> <span style=\"font-size:13.5pt\">খাওয়া</span> <span style=\"font-size:13.5pt\">হয়</span><span style=\"font-size:13.5pt\">)।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">প্রথম</span> <span style=\"font-size:13.5pt\">বাক্যে</span><span style=\"font-size:13.5pt\">&nbsp; &nbsp;subject </span><span style=\"font-size:13.5pt\">হল I&nbsp;</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">2য়</span> <span style=\"font-size:13.5pt\">বাক্যে</span><span style=\"font-size:13.5pt\"> subject </span><span style=\"font-size:13.5pt\">হল&nbsp; &nbsp; A mango&nbsp;</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">প্রথম</span> <span style=\"font-size:13.5pt\">বাক্যে</span><span style=\"font-size:13.5pt\"> objects </span><span style=\"font-size:13.5pt\">হল a mango</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">2য়</span> <span style=\"font-size:13.5pt\">বাক্যে</span><span style=\"font-size:13.5pt\"> objects </span><span style=\"font-size:13.5pt\">হল</span><span style=\"font-size:13.5pt\"> me ( I </span><span style=\"font-size:13.5pt\">এর objective case).</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">প্রথম</span> <span style=\"font-size:13.5pt\">বাক্যে</span><span style=\"font-size:13.5pt\"> verb &#39;eat&#39; </span><span style=\"font-size:13.5pt\">হল</span><span style=\"font-size:13.5pt\"> active(</span><span style=\"font-size:13.5pt\">সক্রিয়</span><span style=\"font-size:13.5pt\">) </span><span style=\"font-size:13.5pt\">এখানে</span> <span style=\"font-size:13.5pt\">করতা</span> <span style=\"font-size:13.5pt\">নিজেই</span> <span style=\"font-size:13.5pt\">কাজ</span> <span style=\"font-size:13.5pt\">করছে।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">২য়</span> <span style=\"font-size:13.5pt\">বাক্যে</span><span style=\"font-size:13.5pt\"> verb &#39;is eaten&#39; </span><span style=\"font-size:13.5pt\">হল</span> <span style=\"font-size:13.5pt\">নিস্ক্রিয়</span><span style=\"font-size:13.5pt\"> (</span><span style=\"font-size:13.5pt\">করতার</span> <span style=\"font-size:13.5pt\">উপরে</span> <span style=\"font-size:13.5pt\">চাপানো</span> <span style=\"font-size:13.5pt\">হরছে)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.5pt\">এবার</span> <span style=\"font-size:13.5pt\">বুঝতে</span> <span style=\"font-size:13.5pt\">পারছ</span> <span style=\"font-size:13.5pt\">বাক্য</span> <span style=\"font-size:13.5pt\">দুটির</span> <span style=\"font-size:13.5pt\">গঠনগত</span> <span style=\"font-size:13.5pt\">পাথক্য?&nbsp;</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:20px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"background-color:#f9f9f9\"><span style=\"color:black\">There are two types of voice:</span></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:20px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"background-color:#f9f9f9\"><span style=\"color:black\">Active voice.</span></span></span></span></li>\r\n	<li><span style=\"font-size:20px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"background-color:#f9f9f9\"><span style=\"color:black\">Passive voice.</span></span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\"><span style=\"background-color:#f9f9f9\"><strong><span style=\"color:#032d4c\">Active voice:</span></strong></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:#f9f9f9\"><span style=\"font-size:13.5pt\"><span style=\"color:black\">যে sentence </span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">এ</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> subject </span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">নিজে</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">সক্রিয়</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">বা</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> active </span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">হয়ে</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">কাজ</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">সম্পন্ন</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">করে</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">সে</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> sentence </span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">এ</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> verb </span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">এর</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> Active voice হয়।</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:#f9f9f9\"><strong><span style=\"font-size:13.5pt\"><span style=\"color:black\">Structure:</span></span></strong><br />\r\n<span style=\"font-size:13.5pt\"><span style=\"color:black\"><strong>Subject + verb + object.</strong></span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:#f9f9f9\"><span style=\"font-size:13.5pt\"><span style=\"color:black\">Example: I do the work.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\"><span style=\"background-color:#f9f9f9\"><strong><span style=\"color:#032d4c\">Passive voice:</span></strong></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:#f9f9f9\"><span style=\"font-size:13.5pt\"><span style=\"color:black\">যে<span style=\"font-size:20px\"> sentence </span></span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">এ</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> <span style=\"font-size:20px\">subject </span></span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">নিজে</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">কাজটি</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">করে</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">না</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">বরং</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> object </span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">এর</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">কাজটি</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">তার</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">ওপর</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">এসে</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">পড়ে</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">তখন</span></span> <span style=\"font-size:13.5pt\"><span style=\"color:black\">সে</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> <span style=\"font-size:20px\">sentence </span></span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">এ</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> <span style=\"font-size:20px\">verb </span></span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\">এর</span></span><span style=\"font-size:13.5pt\"><span style=\"color:black\"> <span style=\"font-size:20px\">passive voice</span> হয়।</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:#f9f9f9\"><strong><span style=\"font-size:13.5pt\"><span style=\"color:black\">Structure:</span></span></strong><br />\r\n<span style=\"font-size:13.5pt\"><span style=\"color:black\"><strong>Object + be verb + verb </strong></span></span><strong><span style=\"font-size:13.5pt\"><span style=\"color:black\">এর past participle+ by+ subject.</span></span></strong></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:#f9f9f9\"><span style=\"font-size:13.5pt\"><span style=\"color:black\">Example: The work is done by me.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">প্রতিটি</span> <span style=\"font-size:13.0pt\">আবার</span> <span style=\"font-size:13.0pt\">১২</span> <span style=\"font-size:13.0pt\">প্রকার</span> <span style=\"font-size:13.0pt\">করে</span> <span style=\"font-size:13.0pt\">আমরা</span> <span style=\"font-size:13.0pt\">পূর্বে</span><span style=\"font-size:13.0pt\"> active&nbsp;&nbsp; voice </span><span style=\"font-size:13.0pt\">এর</span><span style=\"font-size:13.0pt\"> 12 </span><span style=\"font-size:13.0pt\">টি</span> <span style=\"font-size:13.0pt\">নিয়ম</span> <span style=\"font-size:13.0pt\">শিখে</span> <span style=\"font-size:13.0pt\">এসেছি</span> <span style=\"font-size:13.0pt\">এখন</span><span style=\"font-size:13.0pt\"> passive voice </span><span style=\"font-size:13.0pt\">এর</span><span style=\"font-size:13.0pt\"> 12 </span><span style=\"font-size:13.0pt\">টি</span> <span style=\"font-size:13.0pt\">নিয়ম</span> <span style=\"font-size:13.0pt\">শেখবো</span> <span style=\"font-size:13.0pt\">।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">প্রতিটি</span> <span style=\"font-size:16.0pt\">active voice</span> <span style=\"font-size:13.0pt\">চেনার</span> <span style=\"font-size:13.0pt\">জন্য</span> <span style=\"font-size:13.0pt\">বাংলা</span> <span style=\"font-size:13.0pt\">বাক্যের</span> <span style=\"font-size:13.0pt\">ক্রিয়ার</span> <span style=\"font-size:13.0pt\">শেষে</span> <span style=\"font-size:13.0pt\">যেই</span>&nbsp; <span style=\"font-size:13.0pt\">শব্দ</span>&nbsp; <span style=\"font-size:13.0pt\">বা</span> <span style=\"font-size:13.0pt\">বর্ণগুলো</span> <span style=\"font-size:13.0pt\">আমরা</span> <span style=\"font-size:13.0pt\">শিখে</span> <span style=\"font-size:13.0pt\">এসেছি</span> <span style=\"font-size:16.0pt\">passive voice </span><span style=\"font-size:13.0pt\">এ</span> <span style=\"font-size:13.0pt\">বাংলা</span> <span style=\"font-size:13.0pt\">বাক্যের</span> <span style=\"font-size:13.0pt\">শেষে</span> <span style=\"font-size:13.0pt\">ঠিক</span> <span style=\"font-size:13.0pt\">একই</span> <span style=\"font-size:13.0pt\">বর্ণ</span> <span style=\"font-size:13.0pt\">বা</span> <span style=\"font-size:13.0pt\">শব্দগুলো</span> <span style=\"font-size:13.0pt\">বসবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:18.0pt\">* <strong>Present</strong></span><strong> </strong><strong><span style=\"font-size:18.0pt\">simple</span></strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">গঠন</span> <span style=\"font-size:12.0pt\">প্রনালী</span><span style=\"font-size:12.0pt\">: </span><span style=\"font-size:14.0pt\">subject + am/is/are </span><sub><span style=\"font-size:18.0pt\">+ </span></sub><span style=\"font-size:14.0pt\">V3</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Such as: Chairman is censured</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">চেয়ারম্যানকে / </span><span style=\"font-size:12.0pt\">চেয়ারম্যানের</span> <span style=\"font-size:12.0pt\">সমালোচনা</span> <span style=\"font-size:12.0pt\">করা</span> <span style=\"font-size:12.0pt\">হয়।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">House is built</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">বাড়ি নির্মাণ করা হয়</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Apple is eaten</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">&nbsp; আপেল খাওয়া হয়</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:18.0pt\">* <strong>Present </strong></span><strong><span style=\"font-size:16.0pt\">continuous&nbsp;</span></strong><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\">&nbsp;<span style=\"font-size:16.0pt\">subject + am/is/are + being v3</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Such as: Chairman is being censured</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">চেয়ারম্যানকে / </span><span style=\"font-size:12.0pt\">চেয়ারম্যানের</span> <span style=\"font-size:12.0pt\">সমালোচনা</span> <span style=\"font-size:12.0pt\">করা</span> <span style=\"font-size:12.0pt\">হচ্ছে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">House is being built </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">বাড়ি নির্মাণ করা হচ্ছে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Rice is being eaten</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">ভাত খাওয়া হচ্ছে</span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">* <strong>Present perfect&nbsp;</strong></span><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;<span style=\"font-size:16.0pt\"><strong> </strong></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:20px\"><span style=\"font-family:Times New Roman,Times,serif\">subject + have/has been V3</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:20px\"><span style=\"font-family:Times New Roman,Times,serif\">&nbsp;Such as: Chairman has been&nbsp;&nbsp; censured</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\">&nbsp;<span style=\"font-size:12.0pt\">চেয়ারম্যানকে</span><span style=\"font-size:12.0pt\"> / </span><span style=\"font-size:12.0pt\">চেয়ারম্যানের</span> <span style=\"font-size:12.0pt\">সমালোচনা</span> <span style=\"font-size:12.0pt\">করা</span> <span style=\"font-size:12.0pt\">হয়েছে।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">He has been beaten </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তাকে প্রহার করা হয়েছে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">House has been built</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">বাড়ি নির্মাণ হয়েছে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:18.0pt\">* </span><span style=\"font-size:16.0pt\">Present perfect continuous&nbsp;</span></strong><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:20px\"><span style=\"font-family:Times New Roman,Times,serif\">&nbsp;subject + have/has been + being + V3 + object</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Such as:&nbsp;&nbsp;Chairman has been being censured for ten minutes </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\">&nbsp;&nbsp;&nbsp;<span style=\"font-size:12.0pt\">চেয়ারম্যানকে</span><span style=\"font-size:12.0pt\"> / </span><span style=\"font-size:12.0pt\">চেয়ারম্যানের</span> <span style=\"font-size:12.0pt\">সমালোচনা</span> <span style=\"font-size:12.0pt\">করা</span> <span style=\"font-size:12.0pt\">হচ্ছে</span> <span style=\"font-size:12.0pt\">১০</span> <span style=\"font-size:12.0pt\">মিনিট</span> <span style=\"font-size:12.0pt\">ধরে।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp;He has been being searched for 30 minutes</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তাকে ৩০ মিনিট ধরে খোজা হচ্ছে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">* <strong>Past indefinite</strong></span><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;<span style=\"font-size:16.0pt\"><strong> </strong></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">subject +&nbsp;&nbsp;&nbsp; was/ were V3&nbsp;&nbsp;&nbsp;&nbsp; +&nbsp;&nbsp;&nbsp;&nbsp; object</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">উদাহরণ:</span>&nbsp;&nbsp;&nbsp; <span style=\"font-size:14.0pt\">Chairman was censured</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">&nbsp;চেয়ারম্যানকে / চেয়ারম্যানের সমালোচনা করল</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;&nbsp;&nbsp; The work was done</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">&nbsp;&nbsp;&nbsp; কাজটি করা হলো/হয়েছিলো</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Rice was cooked </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">ভাত রান্না করা হলো/হয়েছিলো</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">* <strong>Past continuous</strong></span><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;<span style=\"font-size:16.0pt\"> </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">ubject + was/were being V3 + object</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">উদাহরণ: </span><span style=\"font-size:14.0pt\">Chairman was being censured</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">&nbsp;চেয়ারম্যানকে / চেয়ারম্যানের সমালোচনা করা হচ্ছিল</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Tea was being made by her</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">তার দ্বারা চা তেরি হচ্ছিল</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Fish was being caught in the river</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">নদীতে মাছ ধরা হচ্ছিল</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">* <strong>Past perfect</strong></span><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;<span style=\"font-size:16.0pt\"><strong> </strong></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"background-color:#f9f9f9\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><strong>subject + had been + verb 3</strong></span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Such as:&nbsp;&nbsp;&nbsp; Mango had been eaten before he came </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">সে আসার আগে আমটি খাওয়া হয়েছিলো</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">The work had been finished before he left office</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">সে অফিস ত্যাগের আগে কাজটি শেষ করা হয়েছিলো</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><br />\r\n<span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:15.0pt\">* Future indefinite</span></strong><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;<strong><span style=\"font-size:15.0pt\"> </span></strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">গঠন</span> <span style=\"font-size:12.0pt\">প্রনালী</span><span style=\"font-size:12.0pt\">:&nbsp; </span><span style=\"font-size:14.0pt\">&nbsp;&nbsp;subject + will be + v3 +&nbsp;&nbsp;&nbsp;&nbsp; object</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">উদাহরণ</span><span style=\"font-size:14.0pt\"> : Chairman will be&nbsp; censured</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">&nbsp;চেয়ারম্যানকে / চেয়ারম্যানের সমালোচনা করা হবে।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">You will not be helped by them</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তুমি তাদের দ্বারা সাহায্যপ্রাপ্ত হবে না</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">It will be done by them</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">তাদের দ্বারা এ কাজ করা হবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">* Future continuous </span></strong><span style=\"font-size:18.0pt\">-&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span><strong>&nbsp;</strong>&nbsp;&nbsp;</span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp; subject + will be being V3 +&nbsp;&nbsp; object</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">উদাহরণ:</span> <span style=\"font-size:14.0pt\">Chairman will be being censured</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">চেয়ারম্যানকে / চেয়ারম্যানের সমালোচনা করা হতে থাকবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">A kite will be being flown by me</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">একটি ঘুড়ি উড়ানো হতে থাকবে আমার দ্বারা</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Rubel will be being taught english </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">রুবেলকে ইংরেজি শিখানো হতে থাকবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:18.0pt\">*Future perfect -&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span> </span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;subject + shall have/will have been + verb 3 + extn</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">উদাহরণ</span>&nbsp;&nbsp; <span style=\"font-size:14.0pt\">mango will have been eaten?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">আমটি</span> <span style=\"font-size:13.0pt\">খাওয়া</span> <span style=\"font-size:13.0pt\">হয়ে</span> <span style=\"font-size:13.0pt\">থাকবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">It will have been heard by him by this time</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">এতক্ষনে</span> <span style=\"font-size:13.0pt\">তার</span> <span style=\"font-size:13.0pt\">দ্বারা</span> <span style=\"font-size:13.0pt\">এটি</span> <span style=\"font-size:13.0pt\">শুনা</span> <span style=\"font-size:13.0pt\">হয়ে</span> <span style=\"font-size:13.0pt\">থাকবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">The problem has been solved before sunset</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">সূর্যাস্তের</span> <span style=\"font-size:13.0pt\">আগে</span> <span style=\"font-size:13.0pt\">সমস্যাটি</span> <span style=\"font-size:13.0pt\">সমাধান</span> <span style=\"font-size:13.0pt\">হয়ে</span> <span style=\"font-size:13.0pt\">থাকবে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">দুইটি </span><span style=\"font-size:16.0pt\">object </span><span style=\"font-size:13.0pt\">যুক্ত বাক্যকে </span><span style=\"font-size:16.0pt\">passive</span><span style=\"font-size:13.0pt\"> করার নিয়ম। নিচের উদাহরণটি দেখলে</span> <span style=\"font-size:16.0pt\">clear</span> <span style=\"font-size:13.0pt\">হওয়া যাবে&nbsp;&nbsp; </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">He teaches us English.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">বাক্যটিতে দুইটি </span><strong><span style=\"font-size:16.0pt\">object:</span></strong><span style=\"font-size:14.0pt\"> (প্রাণীবাচক) হল us এবং (বস্তু বাচক) হল English.বাক্যটিকে আমরা প্রথমে We এবং পরে </span><span style=\"font-size:16.0pt\">English</span><span style=\"font-size:14.0pt\">-কে </span><span style=\"font-size:16.0pt\">subject</span><span style=\"font-size:14.0pt\"> ধ&#39;রে দুইভাবে </span><strong><span style=\"font-size:16.0pt\">passive-</span></strong><span style=\"font-size:14.0pt\">এ রূপান্তরিত করি </span><span style=\"font-size:13.0pt\">:</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Passive: We are taught English by him.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">or. English is taught to us by him.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\">প্রথম</span> <span style=\"font-size:16.0pt\">passive</span> <span style=\"font-size:13.0pt\">বাক্যে </span><span style=\"font-size:14.0pt\">active</span><span style=\"font-size:13.0pt\">-এর </span><strong><span style=\"font-size:14.0pt\">us</span></strong><span style=\"font-size:13.0pt\"> এসে </span><strong><span style=\"font-size:14.0pt\">subject &#39;we</span></strong><span style=\"font-size:13.0pt\">&#39; হয়েছে। কিন্তু </span><span style=\"font-size:14.0pt\">object</span><span style=\"font-size:13.0pt\">তো আরেকটি রয়ে যায়<strong> </strong></span><strong><span style=\"font-size:14.0pt\">(English).</span></strong> <span style=\"font-size:13.0pt\">এটি কিন্তু ঠিক আগের মতই</span> <span style=\"font-size:16.0pt\">verb</span><span style=\"font-size:14.0pt\">-</span><span style=\"font-size:13.0pt\">এর পর রয়ে যাবে। একে বলে<strong> </strong></span><strong><span style=\"font-size:14.0pt\">R</span></strong><strong><span style=\"font-size:16.0pt\">etained object (R.Obj.)</span></strong><span style=\"font-size:14.0pt\">. </span><span style=\"font-size:13.0pt\">এভাবে দ্বিতীয়</span> <span style=\"font-size:16.0pt\">passive </span><span style=\"font-size:13.0pt\">বাক্যে</span> <strong><span style=\"font-size:16.0pt\">us</span></strong><strong> </strong><strong><span style=\"font-size:13.0pt\">হল </span></strong><strong><span style=\"font-size:14.0pt\">R. Obj, </span></strong><span style=\"font-size:13.0pt\">সুতরাং এ ধরনের বাক্য যে </span><span style=\"font-size:16.0pt\">tense-</span><span style=\"font-size:13.0pt\">এ-ই থাক না কেন, আমরা যেসব </span><span style=\"font-size:16.0pt\">structure</span> <span style=\"font-size:13.0pt\">ব্যবহার করেছি ঠিক সেই ভাবেই এগুলোর </span><span style=\"font-size:16.0pt\">passive</span> <span style=\"font-size:13.0pt\">করতে হবে (বিভিন্ন</span> <span style=\"font-size:16.0pt\">tense </span><span style=\"font-size:13.0pt\">এর ক্ষেত্রে বিভিন্ন </span><span style=\"font-size:16.0pt\">structure </span><span style=\"font-size:13.0pt\">প্রযোজ্য</span><span style=\"font-size:13.0pt\">) </span><span style=\"font-size:13.0pt\">।</span><span style=\"font-size:13.0pt\"> শুধু যে </span><span style=\"font-size:14.0pt\">objec</span><span style=\"font-size:13.0pt\">tটিকে </span><span style=\"font-size:14.0pt\">passive</span><span style=\"font-size:13.0pt\">-এ</span><span style=\"font-size:14.0pt\"> subject </span><span style=\"font-size:13.0pt\">হিসেবে নেয়া হবে না (যেমন উপরের উদাহরণে </span><span style=\"font-size:16.0pt\">English </span><span style=\"font-size:13.0pt\">এবং </span><span style=\"font-size:14.0pt\">us</span><span style=\"font-size:13.0pt\">) তাকে</span> <span style=\"font-size:16.0pt\">verb</span> <span style=\"font-size:13.0pt\">এর পর ঠিক যেভাবে ছিল সেইভাবে বসিয়ে দিতে হবে। এবার তাহলে নিচের</span> <span style=\"font-size:16.0pt\">exercise</span> <span style=\"font-size:13.0pt\">টি কর</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp; &nbsp; 1.She gave me a flower</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Ans: A flower was given me by her</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Or:I was given a flower by her</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">2.she will be teaching us english</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Ans: we will be being taught english by her</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Or: English will be being taught us by her</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:22.0pt\">*</span><span style=\"font-size:18.0pt\">Future perfect continuous</span><span style=\"font-size:22.0pt\"> -&nbsp;</span></span><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">গঠন</span> <span style=\"font-size:13.0pt\">প্রনালী</span> </span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">&nbsp;subject + shall have/will have been + being + verb 3 + extn</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">উদাহরণ</span>&nbsp;&nbsp; <span style=\"font-size:14.0pt\">mango will have been being eaten?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">&nbsp;&nbsp;&nbsp; PASSIVE VOICE OF Modal </span><span style=\"font-size:18.0pt\">verbs (Can, may,should,would etc)</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">Verb</span><span style=\"font-size:13.0pt\"> এর আগে </span><span style=\"font-size:14.0pt\">auxiliary verb </span><span style=\"font-size:13.0pt\">হিসাবে</span> <span style=\"font-size:14.0pt\">can, could, should, would, must </span><span style=\"font-size:13.0pt\">ইত্যাদি&nbsp; থাকলে শুধু </span><span style=\"font-size:14.0pt\">verb</span><span style=\"font-size:13.0pt\"> অংশের</span><span style=\"font-size:14.0pt\"> passive </span><span style=\"font-size:13.0pt\">গঠনটি হয় এরূপঃ</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">can/could/should/would/must+be+V(p.p.)</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp;&nbsp;&nbsp;Active: I can do it.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: It can be done by me.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">এবার নিচের </span><span style=\"font-size:16.0pt\">exercise</span><span style=\"font-size:14.0pt\">টি কর, তাহলে দেখবে এই </span><span style=\"font-size:16.0pt\">verb </span><span style=\"font-size:14.0pt\">গুলো তোমার জন্যে আর কোন সমস্যা নয়</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp; 1. You must eat the mango.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass:The mango must be eaten by you</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp;2.She should love her husband. </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass:Her husband should be loved by her</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">3. They may use this tubewell.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass:This tubewell may be used by them</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\">&nbsp;উপরের বাক্য গুলো</span><span style=\"font-size:15.0pt\"> negative হলে can. should, must ইত্যাদির পর not বসত।</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:15.0pt\">যেমনঃ&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span style=\"font-size:16.0pt\">Act: You must not eat the mango. </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">এবং passive-এ &quot;be&quot;-এর আগে not বসত;</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: The mango must not be eaten by you.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">যদি বাক্য গুলো Interrogative হত তাহলে শুধু can, should ইত্যাদি বাক্যের আগে বসত। যেমন :</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Active: Must you eat the mango?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:15.0pt\">তখন </span><span style=\"font-size:16.0pt\">passive</span><span style=\"font-size:15.0pt\"> বাক্যেও must, can, should ইত্যাদি আগে বসত । যেমন :</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: Must the mango be eaten by you?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:15.0pt\">যদি বাক্যগুলো negative-interrogative হত তাহলে বাক্যের প্রথমেই</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Can/should/must--+S+not+ be</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Active: Must you not eat the mango?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: Must the mango not be eaten by you?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">&nbsp;PASSIVE VOICE OF SENTENCES WITH W-H word</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">এগুলো </span><span style=\"font-size:16.0pt\">active </span><span style=\"font-size:14.0pt\">ও</span><span style=\"font-size:16.0pt\"> passive </span><span style=\"font-size:14.0pt\">উভয় বাক্যের প্রথমে থাকে। বাক্যটি হয় interrogative বা প্রশ্নবোধক। </span><span style=\"font-size:16.0pt\">active sentence </span><span style=\"font-size:14.0pt\">এর </span><span style=\"font-size:16.0pt\">subject &quot;who</span><span style=\"font-size:14.0pt\">&quot; হলে </span><span style=\"font-size:16.0pt\">passive</span><span style=\"font-size:14.0pt\">-এর প্রথমেই &quot;</span><span style=\"font-size:16.0pt\">by</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">whom&quot; (কার দ্বারা) বসে।অন্য যেকোন W-H word অপরিবর্তিত থাকে</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp;Active: Who did it?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass:By whom was it done?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp;Active:When will he read the book?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp;Pass: when will the book be read by him?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">&nbsp; Active:How did you do it? </span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: How was it done by you?</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">&nbsp;PASSIVE VOICE OF IMPERATIVE SENTENCES</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Imperative sentence</span><span style=\"font-size:15.0pt\">-</span><span style=\"font-size:13.0pt\"> এ কোন আদেশ, উপদেশ, বা অনুরোধ ব্যক্ত হয়। এই ধরনের</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">sentence </span><span style=\"font-size:13.0pt\">এর প্রথমে </span><span style=\"font-size:16.0pt\">affirmative- </span><span style=\"font-size:13.0pt\">এ (হ্যাঁ-বোধক) </span><span style=\"font-size:16.0pt\">principal verb </span><span style=\"font-size:13.0pt\">(প্রধান ক্রিয়া) এবং</span><span style=\"font-size:14.0pt\">negative</span><span style=\"font-size:13.0pt\">-এ </span><span style=\"font-size:14.0pt\">auxiliary verb </span><span style=\"font-size:13.0pt\">থাকে। এই ধরনের </span><span style=\"font-size:14.0pt\">sentence-</span><span style=\"font-size:13.0pt\">এর </span><span style=\"font-size:14.0pt\">passive</span><span style=\"font-size:13.0pt\"> হয় নিচের নিয়মে:</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:18.0pt\">A</span><span style=\"font-size:16.0pt\">ffirmative: Let+ obj +be+V(p.p.) + (by you)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Negative: Let not+obj+be +v (p.p) + (by +you)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\">যেমন: </span><span style=\"font-size:16.0pt\">Active: Do the sum (Affir.)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: Let the sum be done (by you).</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Active: Do not tease the boy.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: Let not the boy be teased (by you).</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:16.0pt\">Active sentence- </span><span style=\"font-size:14.0pt\">এর </span></strong><strong><span style=\"font-size:14.0pt\">প্রথমে</span></strong><strong><span style=\"font-size:16.0pt\"> let </span></strong><strong><span style=\"font-size:14.0pt\">থাকলে</span></strong><strong><span style=\"font-size:16.0pt\"> passive sentence- </span></strong><strong><span style=\"font-size:14.0pt\">এর </span></strong><strong><span style=\"font-size:14.0pt\">আগে</span></strong><strong> </strong><strong><span style=\"font-size:16.0pt\">Let </span><span style=\"font-size:14.0pt\">বসে।</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Act:Let him do it </span><span style=\"font-size:13.0pt\">(তাকে একাজ করতে দাও)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass:Let it be done by him</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Act:Let her eat rice </span><span style=\"font-size:13.0pt\">(তাকে ভাত খেতে দাও।)</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass: Let rice be eaten by her.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Act:Let them see the picture.</span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:16.0pt\">Pass:Let the picture be seen by them</span></span></span></p>', NULL, 'who will help your passive voice', 'passive-voice-kake-ble-who-will-help-your-passive-voice', 1, 8, '1', '2024-06-12 01:24:46', '2024-06-22 09:24:20');
INSERT INTO `book_items` (`id`, `chapter_id`, `title`, `sub_title`, `type`, `short_details`, `details`, `audio_text`, `keyword`, `slug`, `status`, `pageview`, `added_by`, `created_at`, `updated_at`) VALUES
(110, 14, 'never tell a lie passive voice  এবং who is calling me passive voice.  do it passive voice', NULL, 'normal', 'Active Voice: Never tell a lie. কখনও মিথ্যা বলো না।  Passive Voice: Let a lie never be told. কখনও মিথ্যা বলা হবে না।  Active: Who is calling me? আমাকে কে ডাকছে? Active: Who can do it? এটি কে করতে পারে?  Passive: By whom can it be done? কার্যবাচ্য: এটি কার দ্বারা করা যেতে পারে?', '<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Here are the passive voice forms for some important sentences </span><span style=\"font-size:16px\">এখানে কিছু গুরুত্বপূর্ণ বাক্যের কার্যবাচ্যের রূপগুলি দেওয়া হল:</span></span></p>\r\n\r\n<p><br />\r\n<span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Passive: By whom am I being called?</span><span style=\"font-size:16px\"> আমাকে কাদের দ্বারা ডাকা হচ্ছে?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Active: Whom do you want?</span><span style=\"font-size:16px\"> তুমি কাকে চাও?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Passive: Who is wanted by you? </span><span style=\"font-size:16px\">কার্যবাচ্য: কাকে তুমি চাও?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Active: Who can do it? </span><span style=\"font-size:16px\">এটি কে করতে পারে?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Passive: By whom can it be done? </span><span style=\"font-size:16px\">কার্যবাচ্য: এটি কার দ্বারা করা যেতে পারে?</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">active:Do it.</span><span style=\"font-size:16px\"> এটি করো।</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Passive: Let it be done.</span><span style=\"font-size:16px\"> কার্যবাচ্য: এটি </span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Active Voice:&nbsp;Never tell a lie. </span><span style=\"font-size:16px\">কখনও মিথ্যা বলো না।</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Passive Voice:&nbsp;Let a lie never be told.</span><span style=\"font-size:16px\"> কখনও মিথ্যা বলা হবে না।</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:20px\">Active: Who is calling me? </span><span style=\"font-size:16px\">আমাকে কে ডাকছে?&nbsp;</span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:16px\">করা হোক।</span></span></p>\r\n\r\n<p>&nbsp;</p>', NULL, 'never tell a lie passive voice, who is calling me passive voice, do it passive voice', 'never-tell-a-lie-passive-voice-ebng-who-is-calling-me-passive-voice-do-it-passive-voice', 1, 9, '1', '2024-06-12 01:54:11', '2024-06-22 23:19:02'),
(111, 15, 'In terms of the structure of sentences  গঠনের দিক থেকে বাক্য', NULL, 'audio', 'Structure অনুসারে sentence তিন প্রকার Simple sentence (সরল বাক্য) Complex sentence (জটিল বাক্য) Compound Sentence (যৌগিক বাক্য)', '<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">পূর্বে</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">আমরা</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:16.0pt\"><span style=\"background-color:null\">sentence</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">অধ্যায়ে</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">অর্থের</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">দিক</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">থেকে</span></span><span style=\"font-size:16.0pt\"><span style=\"background-color:null\"> sentence </span></span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">পাঁচ</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">প্রকার</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">এবং</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">এঅংশটুকু</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">আলোচনা</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">করেছিলাম</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">এখন</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">আমরা</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">আলোচনা</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">করব</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">গঠনের</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">দিক</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">থেকে</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:16.0pt\"><span style=\"background-color:null\">sentence </span></span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">তিন</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">প্রকার</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">কি</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">কি</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">ও</span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"background-color:null\">বিস্তারিত!</span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<div style=\"border-bottom:solid #dddddd 1.0pt; border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\"><span style=\"color:#2f5496\"><span style=\"font-size:18.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Structure </span></span></span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">অনুসারে</span></span></span><span style=\"font-size:18.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> </span><a name=\"_Hlk164340777\"><span style=\"background-color:null\">sentence</span></a><span style=\"background-color:null\"> </span></span></span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">তিন</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">প্রকার</span></span></span></span></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:48.0pt; margin-right:0in; padding:7.0pt 7.0pt 7.0pt 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"color:black\"><span style=\"font-size:18px\"><span style=\"background-color:null\">1&nbsp;</span></span><a href=\"https://www.grammarbd.com/en-grammar/sentence#simple\"><span style=\"font-size:14.5pt\"><span style=\"color:black\"><span style=\"background-color:null\">sentence</span><span style=\"font-size:16px\"><span style=\"background-color:null\"> (</span></span></span></span><span style=\"font-size:16px\"><span style=\"color:black\"><span style=\"background-color:null\">সরল</span></span><span style=\"background-color:null\"> </span><span style=\"color:black\"><span style=\"background-color:null\">বাক্য)</span></span></span></a></span></span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"color:black\"><span style=\"font-size:18px\"><span style=\"background-color:null\">2</span></span><span style=\"background-color:null\">&nbsp;</span><a href=\"https://www.grammarbd.com/en-grammar/sentence#complex\"><span style=\"font-size:14.5pt\"><span style=\"color:black\"><span style=\"background-color:null\">sentence </span><span style=\"font-size:16px\"><span style=\"background-color:null\">(</span></span></span></span><span style=\"font-size:16px\"><span style=\"color:black\"><span style=\"background-color:null\">জটিল</span></span><span style=\"background-color:null\"> </span><span style=\"color:black\"><span style=\"background-color:null\">বাক্য)</span></span></span></a></span></span></span></p>\r\n\r\n<p><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"color:black\"><span style=\"font-size:18px\"><span style=\"background-color:null\">3</span></span><span style=\"background-color:null\">&nbsp;</span><a href=\"https://www.grammarbd.com/en-grammar/sentence#compound\"><span style=\"font-size:14.5pt\"><span style=\"color:black\"><span style=\"background-color:null\">Sentence </span><span style=\"font-size:16px\"><span style=\"background-color:null\">(</span></span></span></span><span style=\"font-size:16px\"><span style=\"color:black\"><span style=\"background-color:null\">যৌগিক</span></span><span style=\"background-color:null\"> </span><span style=\"color:black\"><span style=\"background-color:null\">বাক্য)</span></span></span></a></span></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n</div>\r\n\r\n<div style=\"border-bottom:solid #dddddd 1.0pt; border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"color:#2f5496\"><strong><span style=\"font-size:17.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Simple sentence </span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">(</span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সরল</span></span></span></strong><strong><span style=\"background-color:null\"> </span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্য</span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">)</span></span></span></strong></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:12.0pt\"><span style=\"color:black\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">যে</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সকল</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্যে</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">একটি</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">মাত্র</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Subject or object </span></span></span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">এবং</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">একটিমাত্র</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সমাপিকা</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">ক্রিয়া</span></span></span><span style=\"font-size:13.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> (</span></span></span></span></span><span style=\"color:black\"><a href=\"https://www.grammarbd.com/en-grammar/finite-verb-%E0%A6%95%E0%A6%BE%E0%A6%95%E0%A7%87-%E0%A6%AC%E0%A6%B2%E0%A7%87\"><span style=\"font-size:14.0pt\"><span style=\"color:#9b3d0f\"><span style=\"background-color:null\">finite verb</span></span></span></a></span><span style=\"font-size:12.0pt\"><span style=\"color:black\"><span style=\"font-size:13.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">) </span></span></span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">থাকে</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">তাকেই</span></span></span><span style=\"font-size:13.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> Simple sentence </span></span></span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বা</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সরল</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্য</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বলে।</span></span></span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">In a </span><strong><span style=\"background-color:null\">simple sentence</span></strong><span style=\"background-color:null\">, there is only one subject and one finite verb. It has only one </span></span></span><span style=\"color:black\"><a href=\"https://www.grammarbd.com/en-grammar/clause#main\"><span style=\"font-size:14.0pt\"><span style=\"color:#9b3d0f\"><span style=\"background-color:null\">independent clause</span></span></span></a></span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Now the question is what a </span></span></span><span style=\"color:black\"><a href=\"https://www.grammarbd.com/en-grammar/clause\"><span style=\"font-size:14.0pt\"><span style=\"color:#9b3d0f\"><span style=\"background-color:null\">clause</span></span></span></a></span><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> is?</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">A </span><strong><span style=\"background-color:null\">Clause</span></strong><span style=\"background-color:null\"> is a sentence or a part of it, and it may be dependent or independent.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">E.g., &ldquo;He hates me&rdquo; is a sentence, which has only one clause. &ldquo;He hates me, and I hate him too&rdquo; is also a sentence and it has two clauses; one is &ldquo;He hates me,&rdquo; and another is &ldquo;I hate him too.&rdquo; These two clauses are joined together by a conjunction &lsquo;and.&#39;</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"color:#111111\"><span style=\"background-color:null\">You may follow a simple pattern like:</span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Subject + Finite verb + complement</span></span></span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Example:</span></span></span></strong></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:48.0pt; margin-right:0in; padding:3.0pt 0in 3.0pt 0in\">\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Cox&rsquo;s Bazar is the largest sea-beach in the world.</span></span></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">She wrote an application to the principal.</span></span></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Bangladesh is a developing country.</span></span></span></span></span></li>\r\n</ul>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"color:black\"><span style=\"color:#111111\"><span style=\"background-color:null\">প্রত্যেকটি</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">উদাহরণে</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">একটি</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">করে subject এবং</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">একটি</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">করে</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">সমাপিকা</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">ক্রিয়া</span></span><span style=\"background-color:null\"> </span><span style=\"color:#111111\"><span style=\"background-color:null\">আছে।</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n</div>\r\n\r\n<div style=\"border-bottom:solid #dddddd 1.0pt; border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"color:#2f5496\"><strong><span style=\"font-size:17.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Complex sentence</span></span></span></strong><strong><span style=\"font-size:18.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> (</span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">জটিল</span></span></span></strong><strong><span style=\"background-color:null\"> </span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্য</span></span></span></strong><strong><span style=\"font-size:18.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">):</span></span></span></strong></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"color:black\"><span style=\"color:#111111\">যে</span> <span style=\"color:#111111\">সকল</span> <span style=\"color:#111111\">বাক্যে</span> <span style=\"color:#111111\">একটি</span> <span style=\"color:#111111\">প্রধান</span> <span style=\"color:#111111\">খন্ড</span> <span style=\"color:#111111\">বাক্য</span> <span style=\"color:#111111\">থাকে</span> <span style=\"color:#111111\">এবং</span> <span style=\"color:#111111\">তার</span> <span style=\"color:#111111\">উপর</span> <span style=\"color:#111111\">আশ্রয়</span> <span style=\"color:#111111\">বা</span> <span style=\"color:#111111\">অবলম্বন</span> <span style=\"color:#111111\">করে</span> <span style=\"color:#111111\">আরও</span> <span style=\"color:#111111\">এক</span> <span style=\"color:#111111\">বা</span> <span style=\"color:#111111\">একাধিক</span> <span style=\"color:#111111\">খন্ড</span> <span style=\"color:#111111\">বাক্য</span> <span style=\"color:#111111\">থাকে</span> <span style=\"color:#111111\">তাকেই</span> </span></span></span><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\"><strong><span style=\"color:#111111\">Complex sentence</span></strong></span></span><span style=\"font-size:16px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"color:black\"> <span style=\"color:#111111\">জটিল</span> <span style=\"color:#111111\">বাক্য</span> <span style=\"color:#111111\">বা</span> <span style=\"color:#111111\">মিশ্র</span> <span style=\"color:#111111\">বাক্য</span> <span style=\"color:#111111\">বলে।</span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">It consists of one main clause and one or more subordinate clauses or adverbial clauses.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">1.</span></span></span></strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> Adverbial clauses come after the main clause.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">&nbsp;His brother died when he was seven years old.</span></span></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">His Bother died</span></span></span></strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> (Main clause)</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">When</span></span></span></strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\"> (subordinating conjunction)</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">He was two years old</span></span></span></strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">. (Adverbial clause)</span></span></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:48.0pt; margin-right:0in; padding:3.0pt 0in 3.0pt 0in\">\r\n<ul>\r\n	<li><span style=\"font-size:18px\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"color:#111111\">If you read regularly, you will do well in the exam.</span></span></span></li>\r\n</ul>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">Here, &lsquo;if you read regularly&rsquo; is a subordinate clause and &lsquo;you will do well in the exam&rsquo; is the main clause.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">2. The best way to detect </span></span></span><span style=\"color:black\"><a href=\"https://www.grammarbd.com/en-grammar/clause#subordinate\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">Subordinate clause</span></span></span></a></span><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\"> is that it always begins with </span></span></span><span style=\"color:black\"><a href=\"https://www.grammarbd.com/en-grammar/conjunction\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">conjunctions</span></span></span></a></span><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\"> like </span><em><span style=\"background-color:null\">where, what, when, that, while, who, if, whether, because, whenever, whoever, whatever, wherever, though, although, till, until, unless, after, before, so that,</span></em><span style=\"background-color:null\"> etc.</span></span></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:48.0pt; margin-right:0in; padding:3.0pt 0in 3.0pt 0in\">\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">You did not even hear what his name was.</span></span></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">Though he lives in America, he speaks Bengali fluently.</span></span></span></span></span></li>\r\n</ul>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:.25in; margin-right:0in; padding:3.0pt 0in 3.0pt 0in\">\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">Clause Sub-ord clause = I believe that he is honest.</span></span></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:black\"><span style=\"background-color:null\">Sub-ord clause + P. Clause = Although he is poor, he is honest.</span></span></span></span></span></li>\r\n</ul>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:.5in; margin-right:0in; padding:3.0pt 0in 3.0pt 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n</div>\r\n\r\n<div style=\"border-bottom:solid #dddddd 1.0pt; border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:13.0pt\"><span style=\"color:#2f5496\"><strong><span style=\"font-size:19.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Compound Sentence (</span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">যৌগিক</span></span></span></strong><strong><span style=\"background-color:null\"> </span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্য</span></span></span></strong><strong><span style=\"font-size:18.5pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">):</span></span></span></strong></span></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"color:black\"><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">অর্থাৎ</span></span></span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">, </span></span></span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">নিরপেক্ষ</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">দুই</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বা</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">তার</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">অধিক</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সরল</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্য</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">যদি</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">কোন</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সংযোজক</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">অব্যয়</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">দ্বারা</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সংযুক্ত</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">হয়ে</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">একটি</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">সম্পূর্ণ</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্য</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">তৈরী</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">করে</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">তখন</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">তাকে</span></span></span><span style=\"background-color:null\"> </span></span><strong><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Compound sentence</span></span></span></strong><span style=\"color:black\"><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বা</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">যৌগিক</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বাক্য</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">বলা</span></span></span><span style=\"background-color:null\"> </span><span style=\"font-size:12.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">হয়।</span></span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">It incorporates at least two principal clauses. These clauses are linked by one or more coordinating conjunctions, punctuations, or both.</span></span></span></span></span></p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Conjunctions that are used in compound sentences are </span><em><span style=\"background-color:null\">and, or, but, for, not, also, thus, however, moreover, therefore, so, still, else, as well as, otherwise, accordingly, yet, not yet, but also, either or, neither nor, on the contrary,</span></em><span style=\"background-color:null\"> etc.</span></span></span></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:.25in; margin-right:0in; padding:0in 0in 0in 0in\">\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:blue\"><span style=\"background-color:null\">principal clause coordinating conjunction principal clause</span></span></span></span></span></li>\r\n</ul>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:0in 0in 0in 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\"><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Example:</span></span></span></strong></span></span></p>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; margin-left:48.0pt; margin-right:0in; padding:3.0pt 0in 3.0pt 0in\">\r\n<ul>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">He is poor but happy.</span></span></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">We searched for him everywhere but did not find.</span></span></span></span></span></li>\r\n	<li><span style=\"font-family:Times New Roman,Times,serif\"><span style=\"font-size:11pt\"><span style=\"font-size:14.0pt\"><span style=\"color:#111111\"><span style=\"background-color:null\">Mou shouted, and all the people started to clap their hands.</span></span></span></span></span></li>\r\n</ul>\r\n</div>\r\n\r\n<div style=\"border:none #eaecf0 1.0pt; padding:3.0pt 0in 3.0pt 0in\">\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>\r\n</div>\r\n\r\n<p style=\"margin-left:0in; margin-right:0in\">&nbsp;</p>', NULL, 'In terms of the structure of sentences', 'in-terms-of-the-structure-of-sentences-gthner-dik-theke-bakz', 1, 13, '1', '2024-06-12 13:19:42', '2024-06-22 00:39:07');
